function normalizeWorkflowStageList(value) {
  const source = Array.isArray(value) ? value : DEFAULT_WORKFLOW_STAGES;
  const out = [];
  source.forEach((item) => {
    const stage = normalizeWorkflowStudioNode(item);
    if (!stage) return;
    if (!out.includes(stage)) out.push(stage);
  });
  if (!out.length) return ["msa", "design", "soluprot", "af2"];
  return out;
}

function workflowCheckpointCandidates(nodes) {
  const orderedNodes = normalizeWorkflowStageList(nodes);
  if (orderedNodes.length <= 1) return [];
  return orderedNodes.slice(0, -1);
}

function normalizeWorkflowCheckpointList(value, nodes, { ensureDefault = false } = {}) {
  const candidates = workflowCheckpointCandidates(nodes);
  const source = Array.isArray(value) ? value : value ? [value] : [];
  const out = [];
  source.forEach((item) => {
    const stage = String(item || "")
      .trim()
      .toLowerCase();
    if (!candidates.includes(stage)) return;
    if (!out.includes(stage)) out.push(stage);
  });
  if (!out.length && ensureDefault && candidates.length) {
    out.push(candidates[candidates.length - 1]);
  }
  return out;
}

function createWorkflowDesignerState() {
  const nodes = normalizeWorkflowStageList(DEFAULT_WORKFLOW_STAGES);
  return {
    nodes,
    checkpointEnabled: false,
    checkpointStages: [],
    graphEnabled: true,
    mmseqLoopEnabled: true,
    flowPulse: 0,
  };
}

function cloneWorkflowStudioValue(value) {
  if (Array.isArray(value)) {
    return value.map((item) => cloneWorkflowStudioValue(item));
  }
  if (value && typeof value === "object") {
    return Object.fromEntries(
      Object.entries(value).map(([key, item]) => [key, cloneWorkflowStudioValue(item)])
    );
  }
  return value;
}

function loadWorkflowPlansByRunId() {
  const raw = localStorage.getItem(WORKFLOW_PLAN_STORAGE_KEY);
  if (!raw) return {};
  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return {};
    const out = {};
    Object.entries(parsed).forEach(([runId, item]) => {
      const key = String(runId || "").trim();
      if (!key) return;
      const payload = item && typeof item === "object" && !Array.isArray(item) ? item : {};
      const nodes = normalizeWorkflowStageList(payload.nodes);
      const checkpointEnabled = Boolean(payload.checkpointEnabled);
      const legacyCheckpointStage = String(payload.checkpointStage || "")
        .trim()
        .toLowerCase();
      const checkpointStages = checkpointEnabled
        ? normalizeWorkflowCheckpointList(
            [
              ...(Array.isArray(payload.checkpointStages) ? payload.checkpointStages : []),
              legacyCheckpointStage,
            ],
            nodes
          )
        : [];
      let checkpointIndex = Number(payload.checkpointIndex);
      if (!Number.isFinite(checkpointIndex)) {
        if (Object.prototype.hasOwnProperty.call(payload, "checkpointConsumed")) {
          checkpointIndex = payload.checkpointConsumed ? checkpointStages.length : 0;
        } else if (legacyCheckpointStage) {
          const legacyIndex = checkpointStages.indexOf(legacyCheckpointStage);
          checkpointIndex = legacyIndex >= 0 ? legacyIndex : 0;
        } else {
          checkpointIndex = 0;
        }
      }
      checkpointIndex = Math.max(0, Math.min(checkpointStages.length, Math.trunc(checkpointIndex)));
      out[key] = {
        nodes,
        finalStopAfter: String(payload.finalStopAfter || nodes[nodes.length - 1] || "novelty")
          .trim()
          .toLowerCase(),
        checkpointEnabled: checkpointStages.length > 0,
        checkpointStages,
        checkpointIndex,
        graphEnabled: payload.graphEnabled !== false,
        mmseqLoopEnabled: payload.mmseqLoopEnabled !== false,
      };
    });
    return out;
  } catch (_err) {
    return {};
  }
}

function normalizeWorkflowStudioSessionPayload(payload, sessionIdFallback = "") {
  const source = payload && typeof payload === "object" && !Array.isArray(payload) ? payload : {};
  const sessionId = String(source.session_id || source.sessionId || sessionIdFallback || "")
    .trim();
  if (!sessionId) return null;
  const nodes = normalizeWorkflowStageList(source.nodes);
  const activeStage = resolveWorkflowStudioStageForSession(
    nodes,
    source.active_stage || source.activeStage || nodes[0] || "",
    nodes[0] || "msa"
  ) || nodes[0] || "msa";
  const stageDrafts = Object.fromEntries(DEFAULT_WORKFLOW_STAGES.map((stage) => [stage, {}]));
  const stageExplicitEmpty = Object.fromEntries(DEFAULT_WORKFLOW_STAGES.map((stage) => [stage, {}]));
  Object.entries(source.stage_drafts || source.stageDrafts || {}).forEach(([stage, values]) => {
    const normalizedStage = workflowStudioNodeBaseStage(stage, "");
    if (!normalizedStage) return;
    if (!values || typeof values !== "object" || Array.isArray(values)) return;
    stageDrafts[normalizedStage] = cloneWorkflowStudioValue(values);
  });
  Object.entries(source.stage_explicit_empty || source.stageExplicitEmpty || {}).forEach(([stage, values]) => {
    const normalizedStage = workflowStudioNodeBaseStage(stage, "");
    if (!normalizedStage) return;
    if (!values || typeof values !== "object" || Array.isArray(values)) return;
    stageExplicitEmpty[normalizedStage] = Object.fromEntries(
      Object.entries(values).map(([key, value]) => [key, value === true])
    );
  });
  const stageStates = {};
  Object.entries(source.stage_states || source.stageStates || {}).forEach(([stage, value]) => {
    const normalizedStage = normalizeWorkflowStageList([stage])[0];
    const text = String(value || "").trim().toLowerCase();
    if (!normalizedStage || !text) return;
    stageStates[normalizedStage] = text;
  });
  const stageRunIds = {};
  Object.entries(source.stage_run_ids || source.stageRunIds || {}).forEach(([stage, value]) => {
    const normalizedStage = normalizeWorkflowStageList([stage])[0];
    const runId = String(value || "").trim();
    if (!normalizedStage || !runId) return;
    stageRunIds[normalizedStage] = runId;
  });
  const history = Array.isArray(source.history)
    ? source.history
        .filter((item) => item && typeof item === "object")
        .map((item) => ({
          run_id: String(item.run_id || "").trim(),
          start_from: String(item.start_from || "").trim().toLowerCase(),
          stop_after: String(item.stop_after || "").trim().toLowerCase(),
          target_node: workflowStudioNodeId(item.target_node || "", ""),
          created_at: String(item.created_at || "").trim(),
        }))
        .filter((item) => item.run_id)
    : [];
  const pending =
    source.pending && typeof source.pending === "object" && !Array.isArray(source.pending)
      ? {
          run_id: String(source.pending.run_id || "").trim(),
          start_from: String(source.pending.start_from || "").trim().toLowerCase(),
          stop_after: String(source.pending.stop_after || "").trim().toLowerCase(),
          target_node: workflowStudioNodeId(source.pending.target_node || "", ""),
          request_snapshot:
            source.pending.request_snapshot &&
            typeof source.pending.request_snapshot === "object" &&
            !Array.isArray(source.pending.request_snapshot)
              ? cloneWorkflowStudioValue(source.pending.request_snapshot)
              : {},
        }
      : null;
  const residuePickerState =
    source.residue_picker_state &&
    typeof source.residue_picker_state === "object" &&
    !Array.isArray(source.residue_picker_state)
      ? cloneWorkflowStudioValue(source.residue_picker_state)
      : null;
  const uiState =
    source.ui_state && typeof source.ui_state === "object" && !Array.isArray(source.ui_state)
      ? cloneWorkflowStudioValue(source.ui_state)
      : {};
  return {
    session_id: sessionId,
    label: String(source.label || "").trim(),
    prompt: String(source.prompt || "").trim(),
    nodes,
    active_stage: activeStage,
    base_answers:
      source.base_answers && typeof source.base_answers === "object" && !Array.isArray(source.base_answers)
        ? cloneWorkflowStudioValue(source.base_answers)
        : {},
    stage_drafts: stageDrafts,
    stage_explicit_empty: stageExplicitEmpty,
    stage_states: stageStates,
    stage_run_ids: stageRunIds,
    head_run_id: String(source.head_run_id || source.headRunId || "").trim(),
    head_request:
      source.head_request && typeof source.head_request === "object" && !Array.isArray(source.head_request)
        ? cloneWorkflowStudioValue(source.head_request)
        : {},
    source_run_id: String(source.source_run_id || source.sourceRunId || "").trim(),
    created_at: String(source.created_at || source.createdAt || "").trim(),
    updated_at: String(source.updated_at || source.updatedAt || "").trim(),
    pending: pending && pending.run_id ? pending : null,
    history,
    residue_picker_state: residuePickerState,
    ui_state: uiState,
    owner_username: String(source.owner_username || source.ownerUsername || "").trim(),
    owner_run_prefix: String(source.owner_run_prefix || source.ownerRunPrefix || "").trim(),
    owner_role: String(source.owner_role || source.ownerRole || "").trim().toLowerCase(),
  };
}

function workflowStudioLatestSessionId(sessionsById = {}) {
  return Object.values(sessionsById || {})
    .filter((item) => item && typeof item === "object" && String(item.session_id || "").trim())
    .sort((a, b) => {
      const aTime = Date.parse(String(a.updated_at || a.created_at || "")) || 0;
      const bTime = Date.parse(String(b.updated_at || b.created_at || "")) || 0;
      if (aTime !== bTime) return bTime - aTime;
      return String(b.session_id || "").localeCompare(String(a.session_id || ""));
    })[0]?.session_id || "";
}

function loadWorkflowStudioSessionsFromStorageKey(storageKey) {
  const key = String(storageKey || "").trim();
  if (!key) return {};
  const raw = localStorage.getItem(key);
  if (!raw) return {};
  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return {};
    const out = {};
    Object.entries(parsed).forEach(([sessionId, payload]) => {
      const normalized = normalizeWorkflowStudioSessionPayload(payload, sessionId);
      if (!normalized) return;
      out[normalized.session_id] = normalized;
    });
    return out;
  } catch (_err) {
    return {};
  }
}

function loadWorkflowStudioSessionsById(user = null) {
  const owner = workflowStudioOwnerFromUser(user);
  if (!owner.owner_username || !owner.owner_run_prefix) return {};
  const { sessionsKey } = workflowStudioStorageKeysForUser(user);
  const scopedSessions = filterWorkflowStudioSessionsForUser(
    loadWorkflowStudioSessionsFromStorageKey(sessionsKey),
    user
  );
  if (sessionsKey === WORKFLOW_STUDIO_STORAGE_KEY) return scopedSessions;
  const legacySessions = filterWorkflowStudioSessionsForUser(
    loadWorkflowStudioSessionsFromStorageKey(WORKFLOW_STUDIO_STORAGE_KEY),
    user
  );
  return {
    ...legacySessions,
    ...scopedSessions,
  };
}

function loadCurrentWorkflowStudioSessionId(user = null, sessionsById = {}) {
  const owner = workflowStudioOwnerFromUser(user);
  if (!owner.owner_username || !owner.owner_run_prefix) return "";
  const { currentKey } = workflowStudioStorageKeysForUser(user);
  const sessions = sessionsById && typeof sessionsById === "object" && !Array.isArray(sessionsById) ? sessionsById : {};
  const scopedCurrent = String(localStorage.getItem(currentKey) || "").trim();
  if (scopedCurrent && sessions[scopedCurrent]) return scopedCurrent;
  if (currentKey !== WORKFLOW_STUDIO_CURRENT_KEY) {
    const legacyCurrent = String(localStorage.getItem(WORKFLOW_STUDIO_CURRENT_KEY) || "").trim();
    if (legacyCurrent && sessions[legacyCurrent]) return legacyCurrent;
  }
  return workflowStudioLatestSessionId(sessions);
}

