function normalizePipelineStage(value, fallback = "") {
  let raw = String(value || "")
    .trim()
    .toLowerCase();
  raw = raw.replace(/[\s-]+/g, "_");
  if (raw === "wt_diff" || raw === "wtdiff") raw = "novelty";
  if (PIPELINE_STAGE_ORDER.includes(raw)) return raw;
  return fallback;
}

function workflowStudioNodeBaseStage(value, fallback = "") {
  return parseWorkflowStudioNode(value)?.baseStage || normalizePipelineStage(value, fallback);
}

function workflowStudioNodeId(value, fallback = "") {
  return normalizeWorkflowStudioNode(value) || fallback;
}

function workflowStudioStatusStageValue(status, fallback = "") {
  const recoveredStage = String(status?._studio_stage || "").trim();
  if (recoveredStage) return recoveredStage;
  return String(status?.stage || fallback || "").trim();
}

function workflowStudioRequestTargetNode(payload, fallback = "") {
  const stopAfter = normalizePipelineStage(payload?.stop_after, "");
  const selected = Array.isArray(payload?.selected_tiers) ? payload.selected_tiers : [];
  if (!stopAfter || !selected.length) return workflowStudioNodeId(fallback, "");
  const target = workflowStudioExecutionTarget(
    `${stopAfter === "design" ? "proteinmpnn" : stopAfter}_${selected[0]}`
  );
  return target.nodeId || workflowStudioNodeId(fallback, "");
}

function syncStartStopStages() {
  const start = normalizePipelineStage(state.answers.start_from, "");
  const stop = normalizePipelineStage(state.answers.stop_after, "");
  if (!start || !stop) return;
  if (PIPELINE_STAGE_ORDER.indexOf(start) > PIPELINE_STAGE_ORDER.indexOf(stop)) {
    state.answers.stop_after = start;
  }
}

function normalizeWorkflowNodesForState(value) {
  const source = Array.isArray(value) ? value : state.workflowDesigner?.nodes;
  const list = [];
  (source || []).forEach((item) => {
    const stage = workflowStudioNodeBaseStage(item, "");
    if (!stage) return;
    if (!list.includes(stage)) list.push(stage);
  });
  if (!list.length) return ["msa", "design", "soluprot", "af2"];
  return list;
}

function nextPipelineStage(stage) {
  const normalized = normalizePipelineStage(stage, "");
  if (!normalized) return "";
  const idx = PIPELINE_STAGE_ORDER.indexOf(normalized);
  if (idx < 0 || idx + 1 >= PIPELINE_STAGE_ORDER.length) return "";
  return PIPELINE_STAGE_ORDER[idx + 1];
}

function buildWorkflowPlanFromDesigner() {
  const nodes = normalizeWorkflowNodesForState(state.workflowDesigner?.nodes);
  const start = nodes[0] || "msa";
  const finalStop = nodes[nodes.length - 1] || "novelty";
  const checkpointEnabled = Boolean(state.workflowDesigner?.checkpointEnabled);
  const checkpointStages = checkpointEnabled
    ? normalizeWorkflowCheckpointList(state.workflowDesigner?.checkpointStages, nodes)
    : [];
  const nextCheckpointStage = checkpointStages[0] || "";
  const stopAfter = nextCheckpointStage || finalStop;
  const noveltyEnabled = finalStop === "novelty";
  const bioemuUse = nodes.includes("bioemu");
  const continueFrom = nextCheckpointStage ? nextPipelineStage(nextCheckpointStage) : "";
  return {
    nodes,
    start,
    stopAfter,
    finalStop,
    checkpointEnabled: checkpointStages.length > 0,
    checkpointStages,
    checkpointIndex: 0,
    nextCheckpointStage,
    continueFrom,
    noveltyEnabled,
    bioemuUse,
    graphEnabled: state.workflowDesigner?.graphEnabled !== false,
    mmseqLoopEnabled: state.workflowDesigner?.mmseqLoopEnabled !== false,
  };
}

function pipelineStageSlice(start, stop) {
  const normalizedStart = normalizePipelineStage(start, "msa") || "msa";
  const normalizedStop = normalizePipelineStage(stop, normalizedStart) || normalizedStart;
  const startIdx = PIPELINE_STAGE_ORDER.indexOf(normalizedStart);
  const stopIdx = PIPELINE_STAGE_ORDER.indexOf(normalizedStop);
  if (startIdx < 0 || stopIdx < 0) return ["msa", "design", "soluprot", "af2"];
  const from = Math.min(startIdx, stopIdx);
  const to = Math.max(startIdx, stopIdx);
  return PIPELINE_STAGE_ORDER.slice(from, to + 1);
}

function workflowPlanForRunId(runId) {
  const key = String(runId || "").trim();
  if (!key) return null;
  const saved = state.workflowPlansByRunId?.[key];
  if (saved && typeof saved === "object") {
    const nodes = normalizeWorkflowNodesForState(saved.nodes);
    const finalStopAfter = normalizePipelineStage(saved.finalStopAfter, nodes[nodes.length - 1] || "novelty");
    const checkpointEnabled = Boolean(saved.checkpointEnabled);
    const legacyCheckpointStage = normalizePipelineStage(saved.checkpointStage, "");
    const checkpointStages = checkpointEnabled
      ? normalizeWorkflowCheckpointList(
          [
            ...(Array.isArray(saved.checkpointStages) ? saved.checkpointStages : []),
            legacyCheckpointStage,
          ],
          nodes
        )
      : [];
    let checkpointIndex = Number(saved.checkpointIndex);
    if (!Number.isFinite(checkpointIndex)) {
      if (Object.prototype.hasOwnProperty.call(saved, "checkpointConsumed")) {
        checkpointIndex = saved.checkpointConsumed ? checkpointStages.length : 0;
      } else if (legacyCheckpointStage) {
        const legacyIndex = checkpointStages.indexOf(legacyCheckpointStage);
        checkpointIndex = legacyIndex >= 0 ? legacyIndex : 0;
      } else {
        checkpointIndex = 0;
      }
    }
    checkpointIndex = Math.max(0, Math.min(checkpointStages.length, Math.trunc(checkpointIndex)));
    const nextCheckpointStage = checkpointStages[checkpointIndex] || "";
    return {
      nodes,
      finalStopAfter,
      checkpointEnabled: checkpointStages.length > 0,
      checkpointStages,
      checkpointIndex,
      nextCheckpointStage,
      continueFrom: nextCheckpointStage ? nextPipelineStage(nextCheckpointStage) : "",
      graphEnabled: saved.graphEnabled !== false,
      mmseqLoopEnabled: saved.mmseqLoopEnabled !== false,
      checkpointConsumed: checkpointIndex >= checkpointStages.length,
    };
  }
  if (state.runModeById?.[key] !== "workflow") return null;
  const ctx = state.progressContextByRunId?.[key];
  if (!ctx || typeof ctx !== "object") return null;
  const nodes = pipelineStageSlice(ctx.startFrom || "msa", ctx.stopAfter || "novelty");
  const finalStopAfter = normalizePipelineStage(ctx.stopAfter, nodes[nodes.length - 1] || "novelty");
  return {
    nodes,
    finalStopAfter,
    checkpointEnabled: false,
    checkpointStages: [],
    checkpointIndex: 0,
    nextCheckpointStage: "",
    continueFrom: "",
    graphEnabled: true,
    mmseqLoopEnabled: false,
    checkpointConsumed: true,
  };
}

function workflowArtifactCountsForNodes(nodes) {
  const counts = {};
  (nodes || []).forEach((stage) => {
    counts[stage] = 0;
  });
  const artifacts = Array.isArray(state.artifacts) ? state.artifacts : [];
  const backboneSourceIndex = backboneSourceIndexFromManifest(currentBackboneManifest());
  artifacts.forEach((item) => {
    const stage = artifactMetaFromPathForManifest(item?.path || "", backboneSourceIndex).stage;
    if (Object.prototype.hasOwnProperty.call(counts, stage)) {
      counts[stage] += 1;
    }
  });
  return counts;
}

function workflowArtifactGroupsForReview() {
  const artifacts = Array.isArray(state.artifacts) ? state.artifacts : [];
  const files = artifacts.filter((item) => item && item.type === "file" && String(item.path || "").trim());
  const groups = new Map();
  const backboneSourceIndex = backboneSourceIndexFromManifest(currentBackboneManifest());
  files.forEach((item) => {
    const stage = artifactMetaFromPathForManifest(item.path, backboneSourceIndex).stage || "misc";
    if (!groups.has(stage)) groups.set(stage, []);
    groups.get(stage).push(item);
  });
  const orderedStages = ARTIFACT_STAGE_ORDER.filter((stage) => groups.has(stage));
  const extraStages = Array.from(groups.keys())
    .filter((stage) => !orderedStages.includes(stage))
    .sort();
  const stageOrder = [...orderedStages, ...extraStages];
  return stageOrder.map((stage) => ({
    stage,
    items: (groups.get(stage) || []).sort((a, b) => String(a.path || "").localeCompare(String(b.path || ""))),
  }));
}

function workflowStudioSessionForId(sessionId = state.currentWorkflowStudioSessionId) {
  const key = String(sessionId || "").trim();
  if (!key) return null;
  return state.workflowStudioSessionsById?.[key] || null;
}

function workflowStudioSessionsOrdered() {
  return Object.values(state.workflowStudioSessionsById || {})
    .filter((item) => item && typeof item === "object" && String(item.session_id || "").trim())
    .sort((a, b) => {
      const aTime = Date.parse(String(a.updated_at || a.created_at || "")) || 0;
      const bTime = Date.parse(String(b.updated_at || b.created_at || "")) || 0;
      if (aTime !== bTime) return bTime - aTime;
      return String(b.session_id || "").localeCompare(String(a.session_id || ""));
    });
}

function workflowStudioSessionDefaultLabel(session) {
  const nodes = normalizeWorkflowNodesForState(session?.nodes);
  return nodes.join(" -> ");
}

function workflowStudioSessionTimestampLabel(session) {
  const raw = String(session?.updated_at || session?.created_at || "").trim();
  const ts = parseStatusTimestamp(raw);
  if (!Number.isFinite(ts)) return "";
  const date = new Date(ts);
  const pad = (value) => String(value).padStart(2, "0");
  return `${pad(date.getMonth() + 1)}-${pad(date.getDate())} ${pad(date.getHours())}:${pad(date.getMinutes())}`;
}

function workflowStudioSessionLabel(session) {
  if (!session || typeof session !== "object") return "";
  const explicit = String(session.label || "").trim();
  if (explicit && explicit !== workflowStudioSessionDefaultLabel(session)) return explicit;
  const headRunId = String(session.head_run_id || "").trim();
  if (headRunId) return headRunId;
  const sourceRunId = String(session.source_run_id || "").trim();
  if (sourceRunId) return sourceRunId;
  return String(session.session_id || "").trim();
}

function workflowStudioSessionOptionLabel(session) {
  const base = workflowStudioSessionLabel(session);
  const detail = [
    session?.active_stage ? formatStageLabel(session.active_stage) : "",
    workflowStudioSessionTimestampLabel(session),
  ].filter(Boolean);
  return detail.length ? `${base} · ${detail.join(" · ")}` : base;
}

function workflowStudioSessionDetailLabel(session) {
  return [
    session?.active_stage ? formatStageLabel(session.active_stage) : "",
    workflowStudioSessionTimestampLabel(session),
  ]
    .filter(Boolean)
    .join(" · ");
}

function workflowStudioSessionDuplicateCounts(sessions = workflowStudioSessionsOrdered()) {
  const counts = new Map();
  (Array.isArray(sessions) ? sessions : []).forEach((session) => {
    const runKey = workflowStudioSessionRunKey(session);
    if (!runKey) return;
    counts.set(runKey, (counts.get(runKey) || 0) + 1);
  });
  return counts;
}

function workflowStudioDeleteSessionById(sessionId, { chooseFallback = true } = {}) {
  const key = String(sessionId || "").trim();
  if (!key || !state.workflowStudioSessionsById?.[key]) return false;
  delete state.workflowStudioSessionsById[key];
  deleteWorkflowStudioFieldErrorsForSession(key);
  if (state.workflowStudioCheckTimersBySession?.[key]) {
    window.clearTimeout(state.workflowStudioCheckTimersBySession[key]);
    delete state.workflowStudioCheckTimersBySession[key];
  }
  if (state.workflowStudioChecksBySession?.[key]) {
    delete state.workflowStudioChecksBySession[key];
  }
  const nextCurrent = chooseFallback
    ? workflowStudioSessionsOrdered().find((item) => item?.session_id && item.session_id !== key)?.session_id || ""
    : "";
  if (String(state.currentWorkflowStudioSessionId || "").trim() === key) {
    setCurrentWorkflowStudioSessionId(nextCurrent);
  } else {
    persistWorkflowStudioSessions();
  }
  return true;
}

function workflowStudioDeleteOtherSessions(currentSessionId = state.currentWorkflowStudioSessionId) {
  const keepId = String(currentSessionId || "").trim();
  const otherIds = workflowStudioSessionsOrdered()
    .map((session) => String(session?.session_id || "").trim())
    .filter((sessionId) => sessionId && sessionId !== keepId);
  otherIds.forEach((sessionId) => {
    workflowStudioDeleteSessionById(sessionId, { chooseFallback: false });
  });
  if (keepId && state.workflowStudioSessionsById?.[keepId]) {
    setCurrentWorkflowStudioSessionId(keepId);
  } else if (otherIds.length) {
    setCurrentWorkflowStudioSessionId(workflowStudioSessionsOrdered()[0]?.session_id || "");
  }
  return otherIds.length;
}

function workflowStudioDeleteDuplicateSessions(sessionId) {
  const keepId = String(sessionId || "").trim();
  const keepSession = workflowStudioSessionForId(keepId);
  if (!keepId || !keepSession) return 0;
  const runKey = workflowStudioSessionRunKey(keepSession);
  if (!runKey) return 0;
  const duplicateIds = workflowStudioSessionsOrdered()
    .filter((session) => String(session?.session_id || "").trim() !== keepId)
    .filter((session) => workflowStudioSessionRunKey(session) === runKey)
    .map((session) => String(session?.session_id || "").trim())
    .filter(Boolean);
  duplicateIds.forEach((duplicateId) => {
    workflowStudioDeleteSessionById(duplicateId, { chooseFallback: false });
  });
  if (!duplicateIds.length) return 0;
  if (state.workflowStudioSessionsById?.[keepId]) {
    setCurrentWorkflowStudioSessionId(keepId);
  } else {
    setCurrentWorkflowStudioSessionId(workflowStudioSessionsOrdered()[0]?.session_id || "");
  }
  return duplicateIds.length;
}

function workflowStudioDeleteSessionsForRun(runId) {
  const key = String(runId || "").trim();
  if (!key) return 0;
  const matches = workflowStudioSessionsOrdered()
    .filter((session) => {
      if (String(session?.head_run_id || "").trim() === key) return true;
      if (String(session?.source_run_id || "").trim() === key) return true;
      if (String(session?.pending?.run_id || "").trim() === key) return true;
      if (Object.values(session?.stage_run_ids || {}).some((value) => String(value || "").trim() === key)) return true;
      return Array.isArray(session?.history) && session.history.some((item) => String(item?.run_id || "").trim() === key);
    })
    .map((session) => session.session_id);
  matches.forEach((sessionId) => {
    workflowStudioDeleteSessionById(sessionId, { chooseFallback: false });
  });
  if (matches.length) {
    const nextCurrent = workflowStudioSessionsOrdered()[0]?.session_id || "";
    if (!state.workflowStudioSessionsById?.[String(state.currentWorkflowStudioSessionId || "").trim()]) {
      setCurrentWorkflowStudioSessionId(nextCurrent);
    } else {
      persistWorkflowStudioSessions();
    }
  }
  return matches.length;
}

function setCurrentWorkflowStudioSessionId(sessionId) {
  const next = String(sessionId || "").trim();
  const changed = next !== String(state.currentWorkflowStudioSessionId || "").trim();
  state.currentWorkflowStudioSessionId = next;
  if (next) {
    state.studioBuilderOpen = false;
  }
  if (changed) {
    state.studioArtifactPath = "";
    state.studioOpenField = "";
    setFilePreviewPlaceholder("studio");
  }
  persistWorkflowStudioSessions();
}

function upsertWorkflowStudioSession(session) {
  const normalized = normalizeWorkflowStudioSessionPayload(
    {
      ...(session && typeof session === "object" && !Array.isArray(session) ? session : {}),
      ...workflowStudioOwnerFromUser(state.user),
    },
    session?.session_id || ""
  );
  if (!normalized) return null;
  state.workflowStudioSessionsById[normalized.session_id] = normalized;
  setCurrentWorkflowStudioSessionId(normalized.session_id);
  return normalized;
}

function deleteWorkflowStudioFieldErrorsForSession(sessionId) {
  const key = String(sessionId || "").trim();
  if (!key) return;
  if (state.workflowStudioFieldErrorsBySession?.[key]) {
    delete state.workflowStudioFieldErrorsBySession[key];
  }
}

function setWorkflowStudioFieldError(sessionId, fieldId, error) {
  const sessionKey = String(sessionId || "").trim();
  const fieldKey = String(fieldId || "").trim();
  if (!sessionKey || !fieldKey) return;
  if (!state.workflowStudioFieldErrorsBySession[sessionKey]) {
    state.workflowStudioFieldErrorsBySession[sessionKey] = {};
  }
  const message = String(error || "").trim();
  if (!message) {
    delete state.workflowStudioFieldErrorsBySession[sessionKey][fieldKey];
    return;
  }
  state.workflowStudioFieldErrorsBySession[sessionKey][fieldKey] = message;
}

function workflowStudioFieldError(sessionId, fieldId) {
  return String(state.workflowStudioFieldErrorsBySession?.[String(sessionId || "").trim()]?.[String(fieldId || "").trim()] || "");
}

function workflowStudioCheckState(sessionId) {
  return (
    state.workflowStudioChecksBySession?.[String(sessionId || "").trim()] &&
    typeof state.workflowStudioChecksBySession[String(sessionId || "").trim()] === "object"
      ? state.workflowStudioChecksBySession[String(sessionId || "").trim()]
      : null
  );
}

function createWorkflowStudioSession({
  sessionId = "",
  prompt = "",
  nodes = [],
  answers = {},
  headRunId = "",
  headRequest = {},
  sourceRunId = "",
  status = null,
} = {}) {
  const nextSessionId = String(sessionId || "").trim() || createWorkflowSessionId("workflow");
  const normalizedNodes = normalizeWorkflowStageList(nodes);
  const split = splitWorkflowStudioAnswers(answers || {});
  const now = new Date().toISOString();
  const session = normalizeWorkflowStudioSessionPayload(
    {
      session_id: nextSessionId,
      label: normalizeWorkflowNodesForState(normalizedNodes).join(" -> "),
      prompt: String(prompt || "").trim(),
      nodes: normalizedNodes,
      active_stage: normalizedNodes[0] || "msa",
      base_answers: split.baseAnswers,
      stage_drafts: split.stageDrafts,
      head_run_id: String(headRunId || "").trim(),
      head_request: headRequest && typeof headRequest === "object" ? cloneWorkflowStudioValue(headRequest) : {},
      source_run_id: String(sourceRunId || "").trim(),
      created_at: now,
      updated_at: now,
      stage_states: {},
      stage_run_ids: {},
      history: [],
      residue_picker_state: null,
      ...workflowStudioOwnerFromUser(state.user),
    },
    nextSessionId
  );
  if (!session) return null;
  const completedState = String(status?.state || "").trim().toLowerCase();
  const stopAfter = workflowStudioNodeBaseStage(
    session.head_request?.stop_after || workflowStudioStatusStageValue(status, "") || session.active_stage || "",
    ""
  );
  const headTargetNode = workflowStudioRequestTargetNode(session.head_request, session.active_stage);
  if (session.head_run_id && stopAfter && ["completed", "done"].includes(completedState)) {
    if (headTargetNode && session.nodes.includes(headTargetNode)) {
      session.stage_states[headTargetNode] = "completed";
      session.stage_run_ids[headTargetNode] = session.head_run_id;
    } else {
      pipelineStageSlice("msa", stopAfter).forEach((stage) => {
        if (!session.nodes.includes(stage)) return;
        session.stage_states[stage] = "completed";
        session.stage_run_ids[stage] = session.head_run_id;
      });
    }
  }
  return session;
}

function workflowStudioDraftAnswers(session) {
  return buildWorkflowStudioEffectiveAnswers({
    headRequest: session?.head_request || {},
    baseAnswers: session?.base_answers || {},
    stageDrafts: session?.stage_drafts || {},
    nodes: session?.nodes || [],
  });
}

function workflowStudioExecutionSegments(session) {
  const segments = [];
  if (Array.isArray(session?.history)) {
    session.history.forEach((item) => {
      const runId = String(item?.run_id || "").trim();
      const stopAfter = normalizePipelineStage(item?.stop_after || "", "");
      if (!runId || !stopAfter) return;
      const targetNode = workflowStudioNodeId(item?.target_node || "", "");
      segments.push({
        run_id: runId,
        start_from: normalizePipelineStage(item?.start_from || "", stopAfter),
        stop_after: stopAfter,
        target_node: targetNode,
      });
    });
  }
  const headRunId = String(session?.head_run_id || "").trim();
  const headStopAfter = normalizePipelineStage(session?.head_request?.stop_after || "", "");
  if (headRunId && headStopAfter && !session?.pending) {
    const headTargetNode = workflowStudioRequestTargetNode(session?.head_request || {}, "");
    segments.unshift({
      run_id: headRunId,
      start_from: normalizePipelineStage(session?.head_request?.start_from || "", "msa"),
      stop_after: headStopAfter,
      target_node: headTargetNode,
    });
  }
  return segments;
}

function workflowStudioRecoveredStageState(session, stage) {
  const normalizedStage = workflowStudioNodeId(stage, "");
  if (!session || !normalizedStage) return "";
  if (session.pending && String(session.pending.run_id || "").trim()) return "";
  const storedState = String(session.stage_states?.[normalizedStage] || "").trim().toLowerCase();
  if (["failed", "error", "cancelled", "canceled", "stopped"].includes(storedState)) return storedState;
  const stageRunId = String(session.stage_run_ids?.[normalizedStage] || "").trim();
  const stageBase = workflowStudioNodeBaseStage(normalizedStage, "");
  const segments = workflowStudioExecutionSegments(session);
  for (const segment of segments) {
    const segmentRunId = String(segment?.run_id || "").trim();
    if (stageRunId && segmentRunId && stageRunId !== segmentRunId) continue;
    const targetNode = workflowStudioNodeId(segment?.target_node || "", "");
    if (targetNode) {
      if (targetNode === normalizedStage) return "completed";
      continue;
    }
    const executedStages = pipelineStageSlice(segment.start_from || "msa", segment.stop_after || stageBase);
    if (!parseWorkflowStudioNode(normalizedStage)?.isTier && executedStages.includes(stageBase)) {
      return "completed";
    }
  }
  return "";
}

function buildWorkflowStudioPreflightRequest(session, targetStage = session?.active_stage || "", preview = null) {
  const effectivePreview = preview || workflowStudioExecutionPreview(session, targetStage);
  const route = workflowStudioExecutionTarget(targetStage || effectivePreview?.targetStage || "msa");
  const normalizedTarget = route.nodeId || effectivePreview?.targetStage || "msa";
  const args = withProjectRoundContext(
    buildRunArguments({
      prompt: session?.prompt || el.promptInput?.value.trim() || "",
      routed: { stop_after: route.stopAfter || workflowStudioNodeBaseStage(normalizedTarget, "msa") || "msa" },
      answers: {
        ...(effectivePreview?.nextPayload || {}),
        ...(route.selectedTiers ? { selected_tiers: route.selectedTiers } : {}),
      },
      runId: "",
    }),
    currentProjectRoundContext()
  );
  if (effectivePreview?.reuseRun && effectivePreview?.requiredStart !== "msa") {
    args.start_from = effectivePreview.requiredStart;
  } else {
    delete args.start_from;
  }
  args.stop_after = route.stopAfter || workflowStudioNodeBaseStage(normalizedTarget, "msa") || "msa";
  if (route.selectedTiers) {
    args.selected_tiers = [...route.selectedTiers];
  } else {
    delete args.selected_tiers;
  }
  args.auto_recover = true;
  args.force = false;
  if (effectivePreview?.reuseRun && String(session?.head_run_id || "").trim()) {
    args.run_id = String(session.head_run_id || "").trim();
  } else {
    delete args.run_id;
  }
  return {
    stage: normalizedTarget,
    args,
    key: JSON.stringify(args),
  };
}

function workflowStudioDependencyMessageKey(code) {
  if (code === "design_outputs_missing") return "studio.validation.depDesign";
  if (code === "soluprot_passed_missing") return "studio.validation.depSoluProt";
  if (code === "af2_selected_missing") return "studio.validation.depAf2";
  return "";
}

function workflowStudioDependencyState(session, targetStage, preview) {
  const runId = String(workflowStudioActionRunId(session) || "").trim();
  const currentRunId = String(state.currentRunId || "").trim();
  const dependency = workflowStudioDependencyStatus({
    targetStage,
    requiredStart: preview?.requiredStart || targetStage,
    artifacts: runId && currentRunId === runId ? state.artifacts : [],
  });
  const warnings = [];
  const blockingErrors = [];
  const pending = Boolean(dependency.required && runId && runId !== currentRunId);
  if (pending) {
    warnings.push(t("studio.validation.syncRun"));
  } else if (dependency.blocked) {
    const messageKey = workflowStudioDependencyMessageKey(dependency.code);
    blockingErrors.push(messageKey ? t(messageKey) : formatStageLabel(dependency.upstreamStage || ""));
  }
  return {
    pending,
    warnings,
    blockingErrors,
  };
}

function queueWorkflowStudioCheck(session, targetStage, request = null) {
  const sessionId = String(session?.session_id || "").trim();
  if (!sessionId || !session) return;
  const prepared = request || buildWorkflowStudioPreflightRequest(session, targetStage);
  const existing = workflowStudioCheckState(sessionId);
  if (existing && existing.stage === prepared.stage && existing.key === prepared.key && ["loading", "ready"].includes(existing.status)) {
    return;
  }
  if (state.workflowStudioCheckTimersBySession?.[sessionId]) {
    window.clearTimeout(state.workflowStudioCheckTimersBySession[sessionId]);
  }
  state.workflowStudioChecksBySession[sessionId] = {
    status: "loading",
    stage: prepared.stage,
    key: prepared.key,
    ok: null,
    errors: [],
    required_inputs: [],
    warnings: [],
  };
  if (String(state.currentWorkflowStudioSessionId || "").trim() === sessionId) {
    renderWorkflowStudio();
  }
  state.workflowStudioCheckTimersBySession[sessionId] = window.setTimeout(async () => {
    try {
      const result = await apiCall("pipeline.preflight", reconcileUserInputsIntoArgs({ ...prepared.args }));
      const current = workflowStudioCheckState(sessionId);
      if (!current || current.key !== prepared.key || current.stage !== prepared.stage) return;
      state.workflowStudioChecksBySession[sessionId] = {
        status: "ready",
        stage: prepared.stage,
        key: prepared.key,
        ok: result?.ok !== false,
        errors: Array.isArray(result?.errors) ? result.errors : [],
        required_inputs: Array.isArray(result?.required_inputs) ? result.required_inputs : [],
        warnings: Array.isArray(result?.warnings) ? result.warnings : [],
      };
    } catch (err) {
      const current = workflowStudioCheckState(sessionId);
      if (!current || current.key !== prepared.key || current.stage !== prepared.stage) return;
      state.workflowStudioChecksBySession[sessionId] = {
        status: "error",
        stage: prepared.stage,
        key: prepared.key,
        ok: false,
        errors: [String(err?.message || err || "Preflight failed")],
        required_inputs: [],
        warnings: [],
      };
    } finally {
      delete state.workflowStudioCheckTimersBySession[sessionId];
      if (String(state.currentWorkflowStudioSessionId || "").trim() === sessionId) {
        renderWorkflowStudio();
      }
    }
  }, 250);
}

function workflowStudioHasExplicitContigDraft(session) {
  const draftValue = String(session?.stage_drafts?.rfd3?.rfd3_contig || "").trim();
  if (draftValue) return true;
  return session?.stage_explicit_empty?.rfd3?.rfd3_contig === true;
}

function workflowStudioHeadRunStopAfter(session) {
  if (!session || typeof session !== "object") return "";
  const headRunId = String(session.head_run_id || "").trim();
  if (!headRunId) return "";
  const pendingRunId = String(session.pending?.run_id || "").trim();
  const pendingStop = normalizePipelineStage(
    pendingRunId && pendingRunId === headRunId
      ? session.pending?.request_snapshot?.stop_after || session.pending?.stop_after || ""
      : "",
    ""
  );
  if (pendingStop) return pendingStop;
  const historyStop = normalizePipelineStage(
    Array.isArray(session.history)
      ? session.history.find((item) => String(item?.run_id || "").trim() === headRunId)?.stop_after || ""
      : "",
    ""
  );
  if (historyStop) return historyStop;
  const requestStop = normalizePipelineStage(session.head_request?.stop_after || "", "");
  if (requestStop) return requestStop;
  const completedStages = PIPELINE_STAGE_ORDER.filter((stage) => {
    return (
      String(session.stage_states?.[stage] || "").trim().toLowerCase() === "completed" &&
      String(session.stage_run_ids?.[stage] || "").trim() === headRunId
    );
  });
  return completedStages[completedStages.length - 1] || "";
}

function workflowStudioStageSkippedByHeadRun(session, stage) {
  const normalizedStage = workflowStudioNodeId(stage, "");
  if (!session || !normalizedStage) return false;
  if (parseWorkflowStudioNode(normalizedStage)?.isTier) return false;
  const headRunId = String(session.head_run_id || "").trim();
  if (!headRunId) return false;
  const stageRunId = String(session.stage_run_ids?.[normalizedStage] || "").trim();
  const storedState = String(session.stage_states?.[normalizedStage] || "").trim().toLowerCase();
  if (["launching", "running", "completed", "done"].includes(storedState)) {
    return false;
  }
  if (["failed", "error", "cancelled", "canceled", "stopped"].includes(storedState) && stageRunId) {
    return false;
  }
  const stopAfter = workflowStudioHeadRunStopAfter(session);
  if (!stopAfter) return false;
  const executedStages = new Set(pipelineStageSlice("msa", stopAfter));
  if (executedStages.has(normalizedStage)) return false;
  const pending = session.pending;
  if (pending && String(pending.run_id || "").trim() === headRunId) {
    const pendingStages = pipelineStageSlice(pending.start_from || "msa", pending.stop_after || stopAfter);
    if (pendingStages.includes(normalizedStage)) return false;
  }
  return !stageRunId || stageRunId === headRunId;
}

function normalizeWorkflowStudioAnswersForRun(rawAnswers, { nodes = [] } = {}) {
  return normalizeWorkflowStudioPayloadForComparison(rawAnswers, { nodes });
}

function workflowStudioStageState(session, stage) {
  const normalizedStage = resolveWorkflowStudioStageForSession(session?.nodes, stage, workflowStudioNodeId(stage, ""));
  if (!session || !normalizedStage) return "idle";
  const pending = session.pending;
  const storedState = String(session.stage_states?.[normalizedStage] || "").trim().toLowerCase();
  const liveStatus = workflowStudioLiveStatus(session);
  const liveStage = resolveWorkflowStudioStageForSession(
    session?.nodes,
    workflowStudioStatusStageValue(liveStatus, ""),
    workflowStudioNodeId(workflowStudioStatusStageValue(liveStatus, ""), "")
  );
  const liveStateRaw = String(liveStatus?.state || "").trim().toLowerCase();
  const liveState =
    liveStateRaw === "done"
      ? "completed"
      : liveStateRaw === "error"
        ? "failed"
        : liveStateRaw;
  if (liveStage && normalizedStage === liveStage && liveState) {
    return liveState;
  }
  const pendingRunId = String(pending?.run_id || "").trim();
  const pendingStatusState =
    pendingRunId && String(state.lastRunStatus?.run_id || "").trim() === pendingRunId
      ? String(state.lastRunStatus?.state || "").trim().toLowerCase()
      : "";
  const pendingTargetNode = resolveWorkflowStudioStageForSession(
    session?.nodes,
    pending?.target_node || "",
    workflowStudioNodeId(pending?.target_node || "", "")
  );
  const pendingStages =
    pending && pending.run_id && !pendingTargetNode
      ? pipelineStageSlice(
          pending.start_from || "msa",
          pending.stop_after || workflowStudioNodeBaseStage(normalizedStage, "msa")
        )
      : [];
  if (
    pending &&
    pending.run_id &&
    (pendingTargetNode
      ? pendingTargetNode === normalizedStage
      : pendingStages.includes(workflowStudioNodeBaseStage(normalizedStage, "")))
  ) {
    if (pendingStatusState === "running") {
      return "running";
    }
    if (
      String(state.currentRunId || "").trim() === String(pending.run_id || "").trim() &&
      currentRunStateText() === "running"
    ) {
      return "running";
    }
    if (storedState === "running") return "running";
    if (storedState === "launching") return "launching";
    return "launching";
  }
  const recoveredState = workflowStudioRecoveredStageState(session, normalizedStage);
  if (recoveredState) {
    return recoveredState === "error" ? "failed" : recoveredState;
  }
  if (workflowStudioStageSkippedByHeadRun(session, normalizedStage)) {
    return "skipped";
  }
  return storedState || "idle";
}

function workflowStudioStageCompleted(session, stage) {
  return workflowStudioStageState(session, stage) === "completed";
}

function workflowStudioFormatRequestedRange(start, stop) {
  const normalizedStart = workflowStudioNodeId(start, normalizePipelineStage(start, ""));
  const normalizedStop = workflowStudioNodeId(stop, normalizePipelineStage(stop, normalizedStart || ""));
  if (!normalizedStop) return "-";
  const startLabel = formatStageLabel(normalizedStart || normalizedStop);
  const stopLabel = formatStageLabel(normalizedStop);
  return normalizedStart && normalizedStart !== normalizedStop ? `${startLabel} -> ${stopLabel}` : stopLabel;
}

function workflowStudioStatusSnapshot(session = workflowStudioSessionForId()) {
  if (!session) {
    return {
      runId: "-",
      stage: "-",
      state: "",
      stateLabel: "-",
      requested: "-",
      updated: "-",
      line: t("studio.runStatus.empty"),
    };
  }
  const pending = session.pending && String(session.pending.run_id || "").trim() ? session.pending : null;
  const currentRunId = String(state.currentRunId || "").trim();
  const runId = String(pending?.run_id || session.head_run_id || currentRunId || "").trim();
  const rawStatus = workflowStudioLiveStatus(session);
  const status =
    pending && rawStatus && String(rawStatus.state || "").trim().toLowerCase() !== "running" ? null : rawStatus;
  const statusStage = resolveWorkflowStudioStageForSession(
    session?.nodes,
    workflowStudioStatusStageValue(status, ""),
    workflowStudioNodeId(workflowStudioStatusStageValue(status, ""), "")
  );
  const pendingTargetNode = resolveWorkflowStudioStageForSession(
    session?.nodes,
    pending?.target_node || "",
    workflowStudioNodeId(pending?.target_node || "", "")
  );
  const currentRunState = currentRunId === runId ? currentRunStateText() : "";
  const fallbackState = pending
    ? currentRunState === "running"
      ? currentRunState
      : "launching"
    : currentRunState
      ? currentRunState
      : workflowStudioStageState(session, session.active_stage);
  const stateText = String(status?.state || fallbackState || "").trim().toLowerCase();
  const stateLabel = stateText ? t(`studio.status.${stateText}`) : "-";
  const stage = formatStatusStage(
    statusStage ||
      pendingTargetNode ||
      pending?.start_from ||
      workflowStudioRequestTargetNode(session?.head_request || {}, "") ||
      workflowStudioHeadRunStopAfter(session) ||
      session.active_stage ||
      ""
  );
  const updated = String(status?.updated_at || "").trim() || (pending ? t("studio.runStatus.awaiting") : "-");
  const headTargetNode = resolveWorkflowStudioStageForSession(
    session?.nodes,
    workflowStudioRequestTargetNode(session?.head_request || {}, ""),
    workflowStudioRequestTargetNode(session?.head_request || {}, "")
  );
  const requested = pending?.stop_after
    ? workflowStudioFormatRequestedRange(
        pendingTargetNode || pending.start_from || pending.stop_after,
        pendingTargetNode || pending.stop_after
      )
    : headTargetNode
      ? workflowStudioFormatRequestedRange(headTargetNode, headTargetNode)
      : workflowStudioHeadRunStopAfter(session)
        ? workflowStudioFormatRequestedRange("msa", workflowStudioHeadRunStopAfter(session))
      : "-";
  const line = runId
    ? t("studio.runStatus.line", {
        id: runId,
        stage: stage || "-",
        state: stateLabel || "-",
        updated,
      })
    : t("studio.runStatus.empty");
  return {
    runId: runId || "-",
    stage: stage || "-",
    state: stateText,
    stateLabel: stateLabel || "-",
    requested,
    updated,
    line,
  };
}

function updateWorkflowStudioRunStatus(session = workflowStudioSessionForId()) {
  const snapshot = workflowStudioStatusSnapshot(session);
  if (el.studioRunInlineStatus) {
    el.studioRunInlineStatus.textContent = snapshot.line;
    el.studioRunInlineStatus.dataset.state = snapshot.state || "";
  }
  if (el.studioRunIdValue) el.studioRunIdValue.textContent = snapshot.runId || "-";
  if (el.studioRunStageValue) el.studioRunStageValue.textContent = snapshot.stage || "-";
  if (el.studioRunRequestedValue) el.studioRunRequestedValue.textContent = snapshot.requested || "-";
  if (el.studioRunUpdatedValue) el.studioRunUpdatedValue.textContent = snapshot.updated || "-";
  if (el.studioRunStateValue) {
    el.studioRunStateValue.textContent = snapshot.stateLabel || "-";
    setStateBadge(el.studioRunStateValue, snapshot.state || "");
  }
  if (el.studioRunPanel) {
    el.studioRunPanel.dataset.state = snapshot.state || "";
  }
}

function workflowStudioStageArtifacts(stage) {
  const meta = parseWorkflowStudioNode(stage);
  const baseStage = meta?.baseStage || normalizePipelineStage(stage, "");
  const tierKey = meta?.tierKey || "";
  const artifacts = Array.isArray(state.artifacts) ? state.artifacts : [];
  const matchesStage = (path) => {
    const normalized = String(path || "")
      .trim()
      .replace(/\\/g, "/")
      .replace(/\/+/g, "/")
      .toLowerCase();
    if (!normalized) return false;
    if (tierKey) {
      const tierMatch = normalized.match(/(?:^|\/)tiers\/([^/]+)/);
      if (!tierMatch || normalizeTierKeyValue(tierMatch[1]) !== tierKey) return false;
    }
    if (baseStage === "design") {
      return (
        /(?:^|\/)tiers\/[^/]+\/(proteinmpnn\.json|designs(?:_pi_filtered)?\.fasta|fixed_positions(?:_check)?\.json|mutation_report\.json|mutations_by_(?:position|sequence)\.(?:tsv|svg)|proteinmpnn_backbones\.json)$/i.test(
          normalized
        ) ||
        (tierKey ? new RegExp(`(?:^|/)backbones/[^/]+/tiers/${tierKey}/`, "i").test(normalized) : false)
      );
    }
    if (baseStage === "soluprot") {
      return /(?:^|\/)tiers\/[^/]+\/(soluprot\.json|designs_filtered\.fasta)$/i.test(normalized);
    }
    if (baseStage === "af2") {
      return (
        /(?:^|\/)tiers\/[^/]+\/(af2_scores\.json|af2_selected\.fasta)$/i.test(normalized) ||
        /(?:^|\/)tiers\/[^/]+\/af2\//i.test(normalized)
      );
    }
    if (baseStage === "novelty") {
      return /(?:^|\/)tiers\/[^/]+\/novelty\.(?:json|tsv)$/i.test(normalized);
    }
    return artifactMetaForPath(path).stage === baseStage;
  };
  return artifacts.filter((item) => {
    if (!item || item.type !== "file" || !String(item.path || "").trim()) return false;
    return matchesStage(item.path);
  }).sort((a, b) => String(a.path || "").localeCompare(String(b.path || "")));
}

function workflowStudioChainRangesForAnswers(answers = {}) {
  const rfd3Text = getRfd3InputPdbTextFromAnswers(answers);
  if (rfd3Text) {
    return parsePdbChainRanges(rfd3Text);
  }
  const targetPdbText = getTargetInputPdbTextFromAnswers(answers);
  if (targetPdbText) {
    return parsePdbChainRanges(targetPdbText);
  }
  return null;
}

function workflowStudioDesignChainOptionsForAnswers(answers = {}, currentValue = []) {
  const ranges = workflowStudioChainRangesForAnswers(answers) || {};
  const selected = Array.isArray(currentValue)
    ? currentValue.map((item) => String(item || "").trim()).filter(Boolean)
    : [];
  return Array.from(new Set([...Object.keys(ranges), ...selected])).sort((a, b) => a.localeCompare(b));
}

function workflowStudioContigOptionsForAnswers(answers = {}, currentValue = "") {
  const ranges = workflowStudioChainRangesForAnswers(answers) || {};
  const options = Object.entries(ranges)
    .sort(([a], [b]) => a.localeCompare(b))
    .map(([chain, range]) => ({
      value: `${chain}${range.min}-${range.max}`,
      label: `${denormalizeChainId(chain) || "_"}${range.min}-${range.max}`,
    }));
  const current = String(currentValue || "").trim();
  if (current && !options.some((item) => item.value === current)) {
    options.unshift({ value: current, label: current });
  }
  return options;
}

const WORKFLOW_STUDIO_REPRESENTATIVE_PATTERNS = Object.freeze({
  msa: Object.freeze([/coverage|conservation/i, /\.a3m$/i, /\.fasta?$/i, /\.json$/i]),
  rfd3: Object.freeze([/ranked_0\.pdb$/i, /target\.pdb$/i, /backbones?\//i, /\.pdb$/i]),
  bioemu: Object.freeze([/ranked_0\.pdb$/i, /topology/i, /target\.pdb$/i, /\.pdb$/i]),
  design: Object.freeze([/summary/i, /\.fa(sta)?$/i, /\.jsonl?$/i, /design/i]),
  soluprot: Object.freeze([/soluprot/i, /summary/i, /\.json$/i, /\.(tsv|csv)$/i]),
  af2: Object.freeze([/ranked_0\.pdb$/i, /ranking/i, /scores?/i, /\.pdb$/i]),
  novelty: Object.freeze([/novelty|wt[_-]?diff/i, /summary/i, /\.json$/i, /\.(tsv|csv)$/i]),
});

function workflowStudioArtifactPreviewScore(stage, path) {
  const text = String(path || "");
  let score = 80;
  if (isStructurePath(text)) {
    score = 0;
  } else if (isImagePath(text)) {
    score = 12;
  } else if (/\.jsonl?$/i.test(text)) {
    score = 24;
  } else if (/\.(tsv|csv)$/i.test(text)) {
    score = 34;
  } else if (/\.(txt|log|md)$/i.test(text)) {
    score = 44;
  } else if (/\.(fa|fasta|a3m)$/i.test(text)) {
    score = 54;
  } else if (isBinaryPath(text)) {
    score = 150;
  }
  const patterns = WORKFLOW_STUDIO_REPRESENTATIVE_PATTERNS[workflowStudioNodeBaseStage(stage, "")] || [];
  patterns.forEach((pattern, idx) => {
    if (pattern.test(text)) {
      score -= 30 - idx * 4;
    }
  });
  if (/ranked_0|summary|report|top|best/i.test(text)) {
    score -= 6;
  }
  if (/target\.pdb$/i.test(text)) {
    score -= 8;
  }
  return score;
}

function workflowStudioRepresentativeArtifact(stage, items = []) {
  const files = (Array.isArray(items) ? items : []).filter((item) => item && item.type === "file" && String(item.path || "").trim());
  if (!files.length) return null;
  return [...files].sort((a, b) => {
    const scoreDiff =
      workflowStudioArtifactPreviewScore(stage, a.path) - workflowStudioArtifactPreviewScore(stage, b.path);
    if (scoreDiff !== 0) return scoreDiff;
    return String(a.path || "").localeCompare(String(b.path || ""));
  })[0];
}

function workflowStudioActionRunId(session = workflowStudioSessionForId()) {
  return workflowStudioActionRunIdForSession(session, state.currentRunId);
}

function workflowStudioLiveStatus(session = workflowStudioSessionForId()) {
  const runId = workflowStudioActionRunId(session);
  if (!runId) return null;
  if (String(state.lastRunStatus?.run_id || "").trim() !== runId) return null;
  return state.lastRunStatus;
}

function workflowStudioRunActive(session = workflowStudioSessionForId()) {
  if (!session) return false;
  const liveStatus = workflowStudioLiveStatus(session);
  if (String(liveStatus?.state || "").trim().toLowerCase() === "running") {
    return true;
  }
  const pendingRunId = String(session?.pending?.run_id || "").trim();
  if (pendingRunId) {
    if (
      String(state.lastRunStatus?.run_id || "").trim() === pendingRunId &&
      String(state.lastRunStatus?.state || "").trim().toLowerCase() === "running"
    ) {
      return true;
    }
    return true;
  }
  const runId = workflowStudioActionRunId(session);
  if (!runId) return false;
  return String(state.currentRunId || "").trim() === runId && currentRunStateText() === "running";
}

function workflowStudioExecutionPreview(session, targetStage = session?.active_stage || "") {
  const route = workflowStudioExecutionTarget(targetStage || session?.nodes?.[0] || "msa");
  const normalizedTarget = route.nodeId || session?.nodes?.[0] || "msa";
  const nextPayload = normalizeWorkflowStudioAnswersForRun(workflowStudioDraftAnswers(session), {
    nodes: session?.nodes || [],
  });
  const hasExplicitContig = workflowStudioHasExplicitContigDraft(session);
  const previewRfd3Mode = effectiveRfd3Mode(nextPayload) || "local_diversify";
  if (
    route.baseStage === "rfd3" &&
    rfd3ModeUsesContig(previewRfd3Mode) &&
    !hasExplicitContig &&
    !String(nextPayload.rfd3_contig || "").trim()
  ) {
    const contigOptions = workflowStudioContigOptionsForAnswers(nextPayload, "");
    if (contigOptions.length) {
      nextPayload.rfd3_contig = contigOptions[0].value;
    }
  }
  const previousPayloadRaw =
    session?.pending?.request_snapshot && typeof session.pending.request_snapshot === "object"
      ? session.pending.request_snapshot
      : session?.head_request && typeof session.head_request === "object"
        ? session.head_request
        : {};
  const previousPayload = normalizeWorkflowStudioPayloadForComparison(previousPayloadRaw, {
    nodes: session?.nodes || [],
  });
  const changedFields = workflowStudioChangedFields(previousPayload, nextPayload);
  const requiredStart = minimumWorkflowStudioStartStage({
    previousPayload,
    nextPayload,
    targetStage: route.baseStage || normalizedTarget,
  });
  const sameRunCandidate = Boolean(String(session?.head_run_id || "").trim()) && requiredStart !== "msa";
  return {
    targetStage: normalizedTarget,
    targetBaseStage: route.baseStage || normalizedTarget,
    selectedTiers: route.selectedTiers ? [...route.selectedTiers] : undefined,
    nextPayload,
    previousPayload,
    changedFields,
    requiredStart,
    reuseRun: sameRunCandidate,
  };
}

function workflowStudioExecutionNoteKey(preview, activeStage) {
  const activeBaseStage = workflowStudioNodeBaseStage(activeStage, "");
  if (preview.requiredStart === activeBaseStage) {
    return preview.reuseRun ? "studio.note.continue" : "studio.note.newRun";
  }
  if (preview.requiredStart === "msa") {
    return "studio.note.fork";
  }
  return "studio.note.restartFrom";
}

function ensureWorkflowPlanForSessionRun(runId, session) {
  const key = String(runId || "").trim();
  if (!key || !session) return;
  const baseNodes = normalizeWorkflowNodesForState(session.nodes);
  state.runModeById[key] = "workflow";
  state.workflowPlansByRunId[key] = {
    nodes: baseNodes,
    finalStopAfter: baseNodes[baseNodes.length - 1] || "novelty",
    checkpointEnabled: false,
    checkpointStages: [],
    checkpointIndex: 0,
    graphEnabled: true,
    mmseqLoopEnabled: false,
  };
  const initialProgressContext = buildWorkflowProgressContext({
    nodes: baseNodes,
    tierKeys:
      Array.isArray(session?.head_request?.selected_tiers) && session.head_request.selected_tiers.length
        ? session.head_request.selected_tiers
        : Array.isArray(session?.head_request?.conservation_tiers) && session.head_request.conservation_tiers.length
          ? session.head_request.conservation_tiers
          : undefined,
    wtCompare: Boolean(session?.head_request?.wt_compare),
  });
  if (initialProgressContext) {
    state.progressContextByRunId[key] = initialProgressContext;
  }
  persistWorkflowPlans();
}

async function saveWorkflowStudioSessionToRun(session, runId = session?.head_run_id || "") {
  const key = String(runId || "").trim();
  if (!key || !session) return;
  try {
    await apiCall("pipeline.save_workflow_session", {
      run_id: key,
      session,
    });
  } catch (_err) {
    // Keep local persistence even if backend sync fails.
  }
}

async function loadWorkflowStudioSessionFromRun(runId) {
  const key = String(runId || "").trim();
  if (!key) return null;
  try {
    const result = await apiCall("pipeline.get_workflow_session", { run_id: key });
    if (result?.found && result?.session && typeof result.session === "object") {
      const normalized = normalizeWorkflowStudioSessionPayload(result.session, result.session.session_id || key);
      if (normalized) return normalized;
    }
  } catch (_err) {
    try {
      const artifact = await apiCall("pipeline.read_artifact", {
        run_id: key,
        path: WORKFLOW_STUDIO_SESSION_PATH,
        max_bytes: 2_000_000,
      });
      const text = String(artifact?.text || "").trim();
      if (!text) return null;
      const normalized = normalizeWorkflowStudioSessionPayload(JSON.parse(text), key);
      if (normalized) return normalized;
    } catch (_err2) {
      return null;
    }
  }
  return null;
}

function workflowStudioSessionIdForRun(runId) {
  return workflowStudioSessionIdForLinkedRun(workflowStudioSessionsOrdered(), runId);
}

async function adoptWorkflowStudioSessionFromRun(runId, { activate = true } = {}) {
  const key = String(runId || "").trim();
  if (!key) return null;
  const existingId = workflowStudioSessionIdForRun(key);
  if (existingId) {
    if (activate) setCurrentWorkflowStudioSessionId(existingId);
    return workflowStudioSessionForId(existingId);
  }
  const saved = await loadWorkflowStudioSessionFromRun(key);
  if (saved) {
    const normalized = upsertWorkflowStudioSession(saved);
    if (normalized) {
      ensureWorkflowPlanForSessionRun(key, normalized);
      return normalized;
    }
  }
  try {
    const payload = await readRunRequestPayload(key);
    const draft = buildSetupDraftFromRequest(payload);
    const plan = workflowPlanForRunId(key);
    const laneTiers =
      Array.isArray(payload?.selected_tiers) && payload.selected_tiers.length
        ? payload.selected_tiers
        : Array.isArray(payload?.conservation_tiers) && payload.conservation_tiers.length
          ? payload.conservation_tiers
          : [0.3, 0.5, 0.7];
    const baseNodes =
      Array.isArray(plan?.nodes) && plan.nodes.length
        ? plan.nodes
        : buildWorkflowStudioNodesFromRequest(payload);
    const session = createWorkflowStudioSession({
      sessionId: createWorkflowSessionId(key),
      prompt: "",
      nodes: expandWorkflowStudioNodes(baseNodes, laneTiers),
      answers: draft.answers,
      headRunId: key,
      headRequest: payload,
      sourceRunId: key,
      status: state.lastRunStatus,
    });
    if (!session) return null;
    const normalized = upsertWorkflowStudioSession(session);
    if (normalized) {
      ensureWorkflowPlanForSessionRun(key, normalized);
      await saveWorkflowStudioSessionToRun(normalized, key);
      if (activate) setCurrentWorkflowStudioSessionId(normalized.session_id);
      return normalized;
    }
  } catch (_err) {
    return null;
  }
  return null;
}

async function openWorkflowStudioFromSetup({ prompt = "", workflowPlan = null, selectedRunId = "" } = {}) {
  const prefix = state.user?.run_prefix || buildUserPrefix({ name: state.user?.username || "user" });
  const sessionId = createWorkflowSessionId(prefix);
  const selected = String(selectedRunId || "").trim();
  let headRequest = {};
  let sourceRunId = "";
  let headRunId = "";
  if (selected) {
    try {
      headRequest = await readRunRequestPayload(selected);
      sourceRunId = selected;
      headRunId = selected;
    } catch (_err) {
      headRequest = {};
    }
  }
  const baseNodes =
    Array.isArray(workflowPlan?.nodes) && workflowPlan.nodes.length
      ? workflowPlan.nodes
      : normalizeWorkflowNodesForState(state.workflowDesigner?.nodes);
  const laneTiers = workflowStudioLaneTiersFromSources({
    answers: state.answers,
    headRequest,
  });
  const nodes = expandWorkflowStudioNodes(baseNodes, laneTiers);
  const session = createWorkflowStudioSession({
    sessionId,
    prompt,
    nodes,
    answers: state.answers,
    headRunId,
    headRequest,
    sourceRunId,
    status: state.lastRunStatus,
  });
  if (!session) return null;
  const normalized = upsertWorkflowStudioSession(session);
  if (!normalized) return null;
  if (headRunId) {
    ensureWorkflowPlanForSessionRun(headRunId, normalized);
    await saveWorkflowStudioSessionToRun(normalized, headRunId);
  }
  setMessage(t("studio.createdSession", { id: workflowStudioSessionLabel(normalized) }), "ai");
  setActiveTab("studio");
  renderWorkflowStudio();
  return normalized;
}

function syncWorkflowStudioSessionFromStatus(status = state.lastRunStatus) {
  const runId = String(status?.run_id || state.currentRunId || "").trim();
  if (!runId) return;
  const runState = String(status?.state || state.currentRunState || "").trim().toLowerCase();
  let touched = false;
  workflowStudioSessionsOrdered().forEach((session) => {
    const pending = session.pending;
    if (!pending || String(pending.run_id || "").trim() !== runId) return;
    const targetNode = workflowStudioNodeId(pending.target_node || "", "");
    let sessionTouched = false;
    if (runState === "running") {
      if (targetNode && session.nodes.includes(targetNode)) {
        sessionTouched =
          upsertWorkflowStudioStageStatus(session.stage_states, session.stage_run_ids, targetNode, "running", runId) ||
          sessionTouched;
      } else {
        pipelineStageSlice(pending.start_from || "msa", pending.stop_after || session.active_stage || "msa").forEach((stage) => {
          if (!session.nodes.includes(stage)) return;
          sessionTouched =
            upsertWorkflowStudioStageStatus(session.stage_states, session.stage_run_ids, stage, "running", runId) ||
            sessionTouched;
        });
      }
      if (String(session.head_run_id || "").trim() !== runId) {
        session.head_run_id = runId;
        sessionTouched = true;
      }
      if (sessionTouched) {
        session.updated_at = new Date().toISOString();
        touched = true;
      }
      return;
    }
    if (!["completed", "done", "failed", "error", "cancelled", "canceled", "stopped"].includes(runState)) {
      return;
    }
    if (["completed", "done"].includes(runState)) {
      if (targetNode && session.nodes.includes(targetNode)) {
        sessionTouched =
          upsertWorkflowStudioStageStatus(session.stage_states, session.stage_run_ids, targetNode, "completed", runId) ||
          sessionTouched;
      } else {
        pipelineStageSlice(pending.start_from || "msa", pending.stop_after || session.active_stage || "msa").forEach((stage) => {
          if (!session.nodes.includes(stage)) return;
          sessionTouched =
            upsertWorkflowStudioStageStatus(session.stage_states, session.stage_run_ids, stage, "completed", runId) ||
            sessionTouched;
        });
      }
      if (String(session.head_run_id || "").trim() !== runId) {
        session.head_run_id = runId;
        sessionTouched = true;
      }
      session.head_request =
        pending.request_snapshot && typeof pending.request_snapshot === "object"
          ? cloneWorkflowStudioValue(pending.request_snapshot)
          : session.head_request;
      session.history = [
        {
          run_id: runId,
          start_from: pending.start_from || "msa",
          stop_after: pending.stop_after || session.active_stage || "msa",
          target_node: targetNode,
          created_at: new Date().toISOString(),
        },
        ...(Array.isArray(session.history) ? session.history : []),
      ].slice(0, 20);
      sessionTouched = true;
    } else {
      const failedStage = targetNode || normalizePipelineStage(pending.stop_after || session.active_stage || "", "");
      if (failedStage) {
        sessionTouched =
          upsertWorkflowStudioStageStatus(
            session.stage_states,
            session.stage_run_ids,
            failedStage,
            runState === "error" ? "failed" : runState,
            runId
          ) || sessionTouched;
      }
    }
    session.pending = null;
    sessionTouched = true;
    if (sessionTouched) {
      session.updated_at = new Date().toISOString();
      touched = true;
      void saveWorkflowStudioSessionToRun(session, runId);
    }
  });
  workflowStudioSessionsOrdered().forEach((session) => {
    if (session?.pending || String(session?.head_run_id || "").trim() !== runId) return;
    let normalizedRunState = runState;
    if (normalizedRunState === "done") normalizedRunState = "completed";
    if (normalizedRunState === "error") normalizedRunState = "failed";
    if (!["running", "completed", "failed", "cancelled", "canceled", "stopped"].includes(normalizedRunState)) {
      return;
    }
    const resolvedStatusStage = resolveWorkflowStudioStageForSession(session?.nodes, workflowStudioStatusStageValue(status, ""), "");
    const resolvedCompletedStages = new Set();
    if (Array.isArray(status?._studio_completed_nodes)) {
      status._studio_completed_nodes.forEach((stage) => {
        const resolvedStage = resolveWorkflowStudioStageForSession(session?.nodes, stage, "");
        if (resolvedStage) {
          resolvedCompletedStages.add(resolvedStage);
        }
      });
    }
    let sessionTouched = false;
    resolvedCompletedStages.forEach((stage) => {
      sessionTouched =
        upsertWorkflowStudioStageStatus(
          session.stage_states,
          session.stage_run_ids,
          stage,
          "completed",
          runId
        ) || sessionTouched;
    });
    if (resolvedStatusStage) {
      sessionTouched =
        upsertWorkflowStudioStageStatus(
          session.stage_states,
          session.stage_run_ids,
          resolvedStatusStage,
          normalizedRunState === "completed" ? "completed" : normalizedRunState,
          runId
        ) || sessionTouched;
      const currentActiveStage = workflowStudioNodeId(session?.active_stage || "", "");
      const initialStage = workflowStudioNodeId(session?.nodes?.[0] || "", "");
      const activeState = String(session.stage_states?.[currentActiveStage] || "").trim().toLowerCase();
      if (
        normalizedRunState === "running" &&
        resolvedStatusStage !== currentActiveStage &&
        (!currentActiveStage || currentActiveStage === initialStage || ["", "idle", "launching"].includes(activeState))
      ) {
        session.active_stage = resolvedStatusStage;
        sessionTouched = true;
      }
    }
    if (!sessionTouched) return;
    if (sessionTouched) {
      session.updated_at = new Date().toISOString();
      touched = true;
      void saveWorkflowStudioSessionToRun(session, runId);
    }
  });
  if (touched) {
    persistWorkflowStudioSessions();
  }
  if (activeTabId() === "studio") {
    if (touched) {
      renderWorkflowStudio();
    } else {
      updateWorkflowStudioRunStatus();
    }
  }
}

function workflowStudioSummaryCards(session, preview) {
  const currentRun = String(session?.head_run_id || "").trim() || "-";
  const noteKey = workflowStudioExecutionNoteKey(preview, session?.active_stage || "");
  return [
    { label: t("studio.summary.session"), value: workflowStudioSessionLabel(session) || "-" },
    { label: t("studio.summary.headRun"), value: currentRun },
    { label: t("studio.summary.currentStage"), value: formatStageLabel(session?.active_stage || "") || "-" },
    {
      label: t("studio.summary.execution"),
      value: t(noteKey, { stage: formatStageLabel(preview.requiredStart) }),
    },
  ];
}

function workflowStudioFieldAccept(fieldId) {
  if (fieldId === "target_input") {
    return ".pdb,.ent,.fa,.fasta,.faa,.txt";
  }
  if (fieldId === "rfd3_input_pdb") {
    return ".pdb,.ent,.txt";
  }
  return ".txt";
}

async function loadWorkflowStudioSession(sessionId) {
  const key = String(sessionId || "").trim();
  if (!key) return;
  const session = workflowStudioSessionForId(key);
  if (!session) return;
  setCurrentWorkflowStudioSessionId(key);
  renderWorkflowStudio();
  const headRunId = String(session?.head_run_id || "").trim();
  if (!headRunId) return;
  if (headRunId !== String(state.currentRunId || "").trim()) {
    setCurrentRunId(headRunId);
  }
  await pollStatus(headRunId);
  await refreshArtifacts({ runId: headRunId });
  await refreshAgentPanel();
  await refreshRunCompare();
  await refreshHitList();
  ensureAutoPoll();
}

async function openWorkflowStudioRunInMonitor(session = workflowStudioSessionForId()) {
  const runId = workflowStudioActionRunId(session);
  setActiveTab("monitor");
  if (!runId) return;
  const currentRunId = String(state.currentRunId || "").trim();
  if (runId !== currentRunId) {
    await handleRunSelectorChange(runId);
    return;
  }
  await pollStatus(runId);
  await refreshArtifacts({ runId });
  await refreshAgentPanel();
  await refreshRunCompare();
  await refreshHitList();
  ensureAutoPoll();
}

function normalizeDetachedResiduePickerContext(value) {
  return String(value || "").trim().toLowerCase() === "studio" ? "studio" : "setup";
}

function residuePickerDetachedRequestStorageKey(token) {
  return `${RESIDUE_PICKER_REQUEST_STORAGE_KEY_PREFIX}${String(token || "").trim()}`;
}

function residuePickerDetachedResultStorageKey(token) {
  return `${RESIDUE_PICKER_RESULT_STORAGE_KEY_PREFIX}${String(token || "").trim()}`;
}

function detachedResiduePickerRequestRegistry(target = window, { create = false } = {}) {
  if (!target || (typeof target !== "object" && typeof target !== "function")) return null;
  try {
    const existing = target[RESIDUE_PICKER_REQUEST_REGISTRY_KEY];
    if (existing && typeof existing === "object" && !Array.isArray(existing)) {
      return existing;
    }
    if (!create) return null;
    const registry = {};
    target[RESIDUE_PICKER_REQUEST_REGISTRY_KEY] = registry;
    return registry;
  } catch (_err) {
    return null;
  }
}

function setDetachedResiduePickerRequestRegistryValue(token = "", payload = null, target = window) {
  const key = String(token || "").trim();
  if (!key || !payload || typeof payload !== "object" || Array.isArray(payload)) return;
  const registry = detachedResiduePickerRequestRegistry(target, { create: true });
  if (!registry) return;
  registry[key] = cloneWorkflowStudioValue(payload);
}

function getDetachedResiduePickerRequestRegistryValue(token = "", target = window) {
  const key = String(token || "").trim();
  if (!key) return null;
  const registry = detachedResiduePickerRequestRegistry(target, { create: false });
  if (!registry || !registry[key] || typeof registry[key] !== "object" || Array.isArray(registry[key])) return null;
  return cloneWorkflowStudioValue(registry[key]);
}

function deleteDetachedResiduePickerRequestRegistryValue(token = "", target = window) {
  const key = String(token || "").trim();
  if (!key) return;
  const registry = detachedResiduePickerRequestRegistry(target, { create: false });
  if (!registry || !Object.prototype.hasOwnProperty.call(registry, key)) return;
  delete registry[key];
}

function removeDetachedResiduePickerRequest(token = "") {
  const key = String(token || "").trim();
  if (!key) return;
  deleteDetachedResiduePickerRequestRegistryValue(key, window);
  try {
    if (window.opener && !window.opener.closed) {
      deleteDetachedResiduePickerRequestRegistryValue(key, window.opener);
    }
  } catch (_err) {
    // ignore opener cleanup errors
  }
  try {
    sessionStorage.removeItem(residuePickerDetachedRequestStorageKey(key));
  } catch (_err) {
    // ignore sessionStorage cleanup errors
  }
  try {
    localStorage.removeItem(residuePickerDetachedRequestStorageKey(key));
  } catch (_err) {
    // ignore localStorage cleanup errors
  }
}

function residuePickerContextLabel(context) {
  return t(normalizeDetachedResiduePickerContext(context) === "studio" ? "tabs.studio" : "tabs.advanced");
}

function buildDetachedResiduePickerUrl(token) {
  const url = new URL(window.location.href);
  url.searchParams.set(RESIDUE_PICKER_DETACHED_QUERY_KEY, String(token || "").trim());
  return url.toString();
}

function buildResiduePickerStateSnapshot() {
  return {
    pdbText: String(state.setupResiduePicker.pdbText || "").trim(),
    sourceLabel: String(state.setupResiduePicker.sourceLabel || "").trim(),
    sourceKey: String(state.setupResiduePicker.sourceKey || "").trim(),
    selection: cloneWorkflowStudioValue(state.setupResiduePicker.selection || {}),
    manualSelection: cloneWorkflowStudioValue(state.setupResiduePicker.manualSelection || {}),
    excludedSelection: cloneWorkflowStudioValue(state.setupResiduePicker.excludedSelection || {}),
    activePresetIds: Array.isArray(state.setupResiduePicker.activePresetIds)
      ? state.setupResiduePicker.activePresetIds.map((presetId) => String(presetId || "").trim()).filter(Boolean)
      : [],
    surfaceAreaCutoff: normalizeSurfaceAreaCutoff(
      state.setupResiduePicker.surfaceAreaCutoff,
      DEFAULT_SURFACE_AREA_CUTOFF
    ),
    structureColorMode: String(state.setupResiduePicker.structureColorMode || "secondary").trim() || "secondary",
    conservationPreview:
      state.setupResiduePicker.conservationPreview && typeof state.setupResiduePicker.conservationPreview === "object"
        ? cloneWorkflowStudioValue(state.setupResiduePicker.conservationPreview)
        : null,
  };
}

function buildResiduePickerRequestSnapshot({ targetPdbText = "", rfd3PdbText = "", selectedRunId = "" } = {}) {
  const snapshot = buildResiduePickerStateSnapshot();
  const snapshotPdbText = String(snapshot.pdbText || "").trim();
  if (!snapshotPdbText) return snapshot;

  const normalizedTargetPdb = String(targetPdbText || "").trim();
  const normalizedRfd3Pdb = String(rfd3PdbText || "").trim();
  const normalizedSourceKey = String(snapshot.sourceKey || "").trim();
  const normalizedSelectedRunId = String(selectedRunId || "").trim();
  const sameInlineSource =
    (normalizedTargetPdb && snapshotPdbText === normalizedTargetPdb) ||
    (normalizedRfd3Pdb && snapshotPdbText === normalizedRfd3Pdb) ||
    (normalizedSelectedRunId && normalizedSourceKey === `run_target:${normalizedSelectedRunId}`);
  if (sameInlineSource) {
    return snapshot;
  }

  return {
    ...snapshot,
    pdbText: "",
    sourceLabel: "",
    sourceKey: "",
    selection: {},
    manualSelection: {},
    excludedSelection: {},
    activePresetIds: [],
    conservationPreview: null,
  };
}

function buildWorkflowStudioResiduePickerSnapshot(session, { targetPdbText = "", rfd3PdbText = "" } = {}) {
  const mergedAnswers = workflowStudioDraftAnswers(session);
  const persisted =
    session?.residue_picker_state && typeof session.residue_picker_state === "object" && !Array.isArray(session.residue_picker_state)
      ? cloneWorkflowStudioValue(session.residue_picker_state)
      : null;
  const structureText = String(persisted?.pdbText || targetPdbText || rfd3PdbText || "").trim();
  const sourceLabel = String(
    persisted?.sourceLabel ||
      (targetPdbText
        ? t("setup.residuePicker.loadTargetInput")
        : rfd3PdbText
          ? t("setup.residuePicker.loadRfd3Input")
          : "")
  ).trim();
  const sourceKey = String(
    persisted?.sourceKey || (targetPdbText ? "target_input" : rfd3PdbText ? "rfd3_input_pdb" : "")
  ).trim();
  const residueOrderByChain = structureText ? parsePdbResidueOrderByChain(structureText) : {};
  const fixedPositions = normalizeFixedPositionsValue(mergedAnswers?.fixed_positions_extra);
  const selectionFromFixedPositions =
    structureText && Object.keys(residueOrderByChain).length
      ? queryPositionsToResidueSelectionMap(fixedPositions, residueOrderByChain)
      : {};
  const hasAppliedSelection = countSelectedResidues(selectionFromFixedPositions) > 0;
  const selection =
    hasAppliedSelection ? selectionFromFixedPositions : {};
  return {
    pdbText: structureText,
    sourceLabel,
    sourceKey,
    selection,
    manualSelection:
      hasAppliedSelection ? selectionFromFixedPositions : {},
    excludedSelection: {},
    activePresetIds: [],
    surfaceAreaCutoff: normalizeSurfaceAreaCutoff(
      persisted?.surfaceAreaCutoff,
      DEFAULT_SURFACE_AREA_CUTOFF
    ),
    structureColorMode: String(persisted?.structureColorMode || "secondary").trim() || "secondary",
    conservationPreview:
      persisted?.conservationPreview && typeof persisted.conservationPreview === "object" && !Array.isArray(persisted.conservationPreview)
        ? cloneWorkflowStudioValue(persisted.conservationPreview)
        : null,
  };
}

function restoreResiduePickerStateSnapshot(snapshot, { fallbackTargetPdbText = "", fallbackRfd3PdbText = "" } = {}) {
  const payload = snapshot && typeof snapshot === "object" && !Array.isArray(snapshot) ? snapshot : {};
  const selection = normalizeResidueSelectionMap(payload.selection || {});
  const manualSelection = normalizeResidueSelectionMap(payload.manualSelection || {});
  const excludedSelection = normalizeResidueSelectionMap(payload.excludedSelection || {});
  const activePresetIds = Array.isArray(payload.activePresetIds)
    ? payload.activePresetIds.map((presetId) => String(presetId || "").trim()).filter(Boolean)
    : [];
  const surfaceAreaCutoff = normalizeSurfaceAreaCutoff(
    payload.surfaceAreaCutoff,
    DEFAULT_SURFACE_AREA_CUTOFF
  );
  const structureColorMode = String(payload.structureColorMode || state.setupResiduePicker.structureColorMode || "secondary").trim() || "secondary";
  const conservationPreview =
    payload.conservationPreview && typeof payload.conservationPreview === "object" && !Array.isArray(payload.conservationPreview)
      ? cloneWorkflowStudioValue(payload.conservationPreview)
      : null;

  resetSetupResiduePicker();
  state.setupResiduePicker.surfaceAreaCutoff = surfaceAreaCutoff;
  state.setupResiduePicker.structureColorMode = structureColorMode;
  state.setupResiduePicker.conservationPreview = conservationPreview;

  const snapshotPdbText = String(payload.pdbText || "").trim();
  const sourceLabel = String(payload.sourceLabel || "").trim();
  const sourceKey = String(payload.sourceKey || "").trim();
  let loaded = false;

  if (snapshotPdbText) {
    loaded = setSetupResiduePickerStructure(snapshotPdbText, {
      sourceLabel,
      sourceKey,
    });
  } else if (String(fallbackTargetPdbText || "").trim()) {
    loaded = setSetupResiduePickerStructure(fallbackTargetPdbText, {
      sourceLabel: t("setup.residuePicker.loadTargetInput"),
      sourceKey: "target_input",
    });
  } else if (String(fallbackRfd3PdbText || "").trim()) {
    loaded = setSetupResiduePickerStructure(fallbackRfd3PdbText, {
      sourceLabel: t("setup.residuePicker.loadRfd3Input"),
      sourceKey: "rfd3_input_pdb",
    });
  }

  if (loaded) {
    syncSetupResiduePickerSelectionState({
      selectionFallback: selection,
      manualSelection,
      excludedSelection,
      activePresetIds,
      allowFallback: true,
    });
    state.setupResiduePicker.surfaceAreaCutoff = surfaceAreaCutoff;
    state.setupResiduePicker.structureColorMode = structureColorMode;
    if (conservationPreview) {
      state.setupResiduePicker.conservationPreview = conservationPreview;
    }
    return;
  }

  state.setupResiduePicker.manualSelection = manualSelection;
  state.setupResiduePicker.excludedSelection = excludedSelection;
  state.setupResiduePicker.activePresetIds = activePresetIds;
  state.setupResiduePicker.selection = selection;
}

function loadDetachedResiduePickerRequest(token = detachedResiduePickerToken) {
  const key = String(token || "").trim();
  if (!key) return null;
  try {
    const liveRequest =
      getDetachedResiduePickerRequestRegistryValue(key, window) ||
      (() => {
        try {
          if (window.opener && !window.opener.closed) {
            return getDetachedResiduePickerRequestRegistryValue(key, window.opener);
          }
        } catch (_err) {
          return null;
        }
        return null;
      })();
    const raw =
      sessionStorage.getItem(residuePickerDetachedRequestStorageKey(key)) ||
      localStorage.getItem(residuePickerDetachedRequestStorageKey(key));
    if (!raw && !liveRequest) return null;
    const parsed = raw ? JSON.parse(raw) : {};
    const merged =
      liveRequest && typeof liveRequest === "object" && !Array.isArray(liveRequest)
        ? {
            ...(parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed : {}),
            ...liveRequest,
          }
        : parsed;
    if (!merged || typeof merged !== "object" || Array.isArray(merged)) return null;
    return {
      token: key,
      context: normalizeDetachedResiduePickerContext(merged.context),
      sessionId: String(merged.sessionId || "").trim(),
      activeStage: String(merged.activeStage || "").trim(),
      targetPdbText: String(merged.targetPdbText || "").trim(),
      targetFastaText: String(merged.targetFastaText || "").trim(),
      rfd3PdbText: String(merged.rfd3PdbText || "").trim(),
      selectedRunId: String(merged.selectedRunId || "").trim(),
      pickerProvider: normalizeAf2Provider(merged.pickerProvider || "colabfold"),
      snapshot: merged.snapshot && typeof merged.snapshot === "object" ? cloneWorkflowStudioValue(merged.snapshot) : {},
    };
  } catch (_err) {
    return null;
  }
}

function openDetachedResiduePicker({
  context = "setup",
  sessionId = "",
  activeStage = "design",
  targetPdbText = "",
  targetFastaText = "",
  rfd3PdbText = "",
  selectedRunId = "",
  pickerProvider = "colabfold",
  snapshotOverride = null,
} = {}) {
  const token = createRunId("picker_tab");
  const request = {
    token,
    context: normalizeDetachedResiduePickerContext(context),
    sessionId: String(sessionId || "").trim(),
    activeStage: String(activeStage || "").trim() || "design",
    targetPdbText: String(targetPdbText || "").trim(),
    targetFastaText: String(targetFastaText || "").trim(),
    rfd3PdbText: String(rfd3PdbText || "").trim(),
    selectedRunId: String(selectedRunId || "").trim(),
    pickerProvider: normalizeAf2Provider(pickerProvider || "colabfold"),
    snapshot:
      snapshotOverride && typeof snapshotOverride === "object" && !Array.isArray(snapshotOverride)
        ? cloneWorkflowStudioValue(snapshotOverride)
        : buildResiduePickerRequestSnapshot({
            targetPdbText,
            rfd3PdbText,
            selectedRunId,
          }),
    created_at: new Date().toISOString(),
  };
  setDetachedResiduePickerRequestRegistryValue(token, request, window);
  try {
    sessionStorage.setItem(
      residuePickerDetachedRequestStorageKey(token),
      JSON.stringify(buildDetachedResiduePickerStoragePayload(request))
    );
  } catch (_err) {
    // Popup can still recover the full request from the opener registry.
  }
  const popupFeatures = buildPopupWindowFeatures({
    screenX: window.screenX,
    screenY: window.screenY,
    outerWidth: window.outerWidth,
    outerHeight: window.outerHeight,
    availWidth: window.screen?.availWidth || window.outerWidth,
    availHeight: window.screen?.availHeight || window.outerHeight,
  });
  const opened = openPopupWindow({
    open: window.open.bind(window),
    url: buildDetachedResiduePickerUrl(token),
    name: RESIDUE_PICKER_POPUP_WINDOW_NAME,
    features: popupFeatures,
  });
  if (opened) return;
  removeDetachedResiduePickerRequest(token);
  setMessage(t("setup.residuePicker.loadFailed", { error: "popup blocked" }), "ai");
}

function createDetachedResiduePickerResultPayload(request, mappedSelection, selectedCount) {
  return {
    token: String(request?.token || detachedResiduePickerToken || "").trim(),
    context: normalizeDetachedResiduePickerContext(request?.context),
    sessionId: String(request?.sessionId || "").trim(),
    activeStage: String(request?.activeStage || "").trim(),
    mappedSelection: normalizeFixedPositionsValue(mappedSelection),
    selectedCount: Number(selectedCount) || countSelectedResidues(mappedSelection),
    snapshot: buildResiduePickerStateSnapshot(),
    predictedResult:
      state.detachedResiduePicker.predictedResult && typeof state.detachedResiduePicker.predictedResult === "object"
        ? cloneWorkflowStudioValue(state.detachedResiduePicker.predictedResult)
        : null,
    applied_at: new Date().toISOString(),
  };
}

function markDetachedResiduePickerTokenProcessed(token = "") {
  const key = String(token || "").trim();
  if (!key) return true;
  const now = Date.now();
  const seenAt = Number(state.detachedResiduePicker.processedTokens?.[key] || 0);
  if (Number.isFinite(seenAt) && now - seenAt < 5000) {
    return false;
  }
  if (!state.detachedResiduePicker.processedTokens || typeof state.detachedResiduePicker.processedTokens !== "object") {
    state.detachedResiduePicker.processedTokens = {};
  }
  state.detachedResiduePicker.processedTokens[key] = now;
  Object.entries(state.detachedResiduePicker.processedTokens).forEach(([tokenKey, timestamp]) => {
    if (!Number.isFinite(Number(timestamp)) || now - Number(timestamp) > 300000) {
      delete state.detachedResiduePicker.processedTokens[tokenKey];
    }
  });
  return true;
}

function dispatchDetachedResiduePickerResult(payload) {
  const message = {
    type: RESIDUE_PICKER_RESULT_MESSAGE_TYPE,
    payload,
  };
  let delivered = false;
  try {
    if (window.opener && !window.opener.closed) {
      window.opener.postMessage(message, window.location.origin);
      delivered = true;
    }
  } catch (_err) {
    delivered = false;
  }
  try {
    localStorage.setItem(
      residuePickerDetachedResultStorageKey(payload?.token || ""),
      JSON.stringify(buildDetachedResiduePickerResultStoragePayload(payload))
    );
    return true;
  } catch (_err) {
    return delivered;
  }
}

function dispatchDetachedResiduePickerReset(request = null) {
  try {
    if (window.opener && !window.opener.closed) {
      window.opener.postMessage(
        {
          type: RESIDUE_PICKER_RESET_MESSAGE_TYPE,
          payload: {
            context: normalizeDetachedResiduePickerContext(request?.context),
            sessionId: String(request?.sessionId || "").trim(),
          },
        },
        window.location.origin
      );
      return true;
    }
  } catch (_err) {
    return false;
  }
  return false;
}

function clearSetupFixedPositionsExtraState() {
  state.answers = withFixedPositionsExtra(state.answers, {});
  state.answerMeta.fixed_positions_extra = {
    ...(state.answerMeta.fixed_positions_extra || {}),
    error: "",
    raw: "",
  };
  clearSetupResiduePickerSelectionState();
  state.setupResiduePicker.notice = t("setup.residuePicker.cleared");
}

function clearWorkflowStudioFixedPositionsExtraState(sessionId = state.currentWorkflowStudioSessionId || "") {
  const key = String(sessionId || "").trim();
  if (!key) return null;
  const current = workflowStudioSessionForId(key);
  if (!current) return null;
  if (!current.stage_drafts || typeof current.stage_drafts !== "object") {
    current.stage_drafts = {};
  }
  current.stage_drafts.design = withFixedPositionsExtra(current.stage_drafts.design, {});
  current.residue_picker_state = clearResiduePickerSelectionState(current.residue_picker_state || {});
  current.updated_at = new Date().toISOString();
  setWorkflowStudioFieldError(current.session_id, "fixed_positions_extra", "");
  return upsertWorkflowStudioSession(current);
}

function applyDetachedResiduePickerReset(payload = null) {
  const context = normalizeDetachedResiduePickerContext(payload?.context);
  if (context === "studio") {
    clearSetupResiduePickerSelectionState();
    clearWorkflowStudioFixedPositionsExtraState(payload?.sessionId);
    renderWorkflowStudio();
  } else {
    clearSetupFixedPositionsExtraState();
    renderQuestions(state.plan?.questions || []);
  }
}

function applyDetachedResiduePickerResult(result) {
  const payload = result && typeof result === "object" && !Array.isArray(result) ? result : null;
  if (!payload) return;
  if (!markDetachedResiduePickerTokenProcessed(payload.token)) return;
  const mappedSelection = normalizeFixedPositionsValue(payload.mappedSelection);
  const selectedCount = countSelectedResidues(mappedSelection);
  const predicted = payload.predictedResult && typeof payload.predictedResult === "object" ? payload.predictedResult : null;
  const context = normalizeDetachedResiduePickerContext(payload.context);

  if (context === "studio") {
    const sessionId = String(payload.sessionId || state.currentWorkflowStudioSessionId || "").trim();
    const current = workflowStudioSessionForId(sessionId);
    if (!current) return;
    if (!current.stage_drafts.design) current.stage_drafts.design = {};
    const nextFixedPositions = selectedCount
      ? mergeFixedPositionsMap(workflowStudioDraftAnswers(current).fixed_positions_extra, mappedSelection)
      : {};
    current.stage_drafts.design = withFixedPositionsExtra(current.stage_drafts.design, nextFixedPositions);
    if (predicted?.selectedPdb) {
      current.base_answers = current.base_answers && typeof current.base_answers === "object" ? current.base_answers : {};
      current.base_answers.target_fasta = String(
        predicted.fastaText || getTargetInputFastaTextFromAnswers(workflowStudioDraftAnswers(current)) || ""
      ).trim();
      current.base_answers.target_pdb = String(predicted.selectedPdb || "").trim();
    }
    current.updated_at = new Date().toISOString();
    current.residue_picker_state =
      payload.snapshot && typeof payload.snapshot === "object" && !Array.isArray(payload.snapshot)
        ? cloneWorkflowStudioValue(payload.snapshot)
        : current.residue_picker_state || null;
    setWorkflowStudioFieldError(current.session_id, "fixed_positions_extra", "");
    upsertWorkflowStudioSession(current);
    renderWorkflowStudio();
  } else {
    const nextFixedPositions = selectedCount ? mergeFixedPositionsMap(state.answers.fixed_positions_extra, mappedSelection) : {};
    state.answers = withFixedPositionsExtra(state.answers, nextFixedPositions);
    state.answerMeta.fixed_positions_extra = {
      ...(state.answerMeta.fixed_positions_extra || {}),
      error: "",
      raw: selectedCount ? JSON.stringify(nextFixedPositions) : "",
    };
    if (predicted?.selectedPdb) {
      state.answers.target_fasta = String(predicted.fastaText || getTargetInputFastaText() || "").trim();
      state.answers.target_pdb = String(predicted.selectedPdb || "").trim();
      state.answerMeta.target_pdb = {
        fileName: `${String(predicted.outRunId || "").trim()}:${String(predicted.selectedPath || "").trim()}`,
      };
      refreshChainRangesFromAnswers();
    }
    restoreResiduePickerStateSnapshot(payload.snapshot, {
      fallbackTargetPdbText: predicted?.selectedPdb || getTargetInputPdbText(),
      fallbackRfd3PdbText: getRfd3InputPdbText(),
    });
    state.setupResiduePicker.notice = selectedCount
      ? t("setup.residuePicker.applied", { count: selectedCount })
      : t("setup.residuePicker.cleared");
    renderQuestions(state.plan?.questions || []);
  }

  setMessage(
    selectedCount
      ? t("setup.residuePicker.detached.sent", {
          count: selectedCount,
          context: residuePickerContextLabel(context),
        })
      : t("setup.residuePicker.detached.sentCleared", {
          context: residuePickerContextLabel(context),
        }),
    "ai"
  );
}

function renderDetachedResiduePickerWorkspace() {
  if (!el.detachedResiduePickerRoot) return;
  if (!detachedResiduePickerToken) {
    el.detachedResiduePickerRoot.classList.add("hidden");
    el.detachedResiduePickerRoot.innerHTML = "";
    return;
  }
  el.detachedResiduePickerRoot.classList.remove("hidden");
  if (state.detachedResiduePicker.initializedToken !== detachedResiduePickerToken) {
    const request = loadDetachedResiduePickerRequest(detachedResiduePickerToken);
    state.detachedResiduePicker.initializedToken = detachedResiduePickerToken;
    state.detachedResiduePicker.request = request;
    state.detachedResiduePicker.predictedResult = null;
    if (request) {
      restoreResiduePickerStateSnapshot(request.snapshot, {
        fallbackTargetPdbText: request.targetPdbText,
        fallbackRfd3PdbText: request.rfd3PdbText,
      });
    }
  }

  const request = state.detachedResiduePicker.request;
  if (!request) {
    el.detachedResiduePickerRoot.innerHTML = `
      <div class="detached-picker-shell">
        <div class="detached-picker-hero">
          <div class="detached-picker-copy">
            <strong>${escapeHtml(t("setup.residuePicker.detached.title"))}</strong>
            <p>${escapeHtml(t("setup.residuePicker.detached.missing"))}</p>
          </div>
          <button type="button" class="ghost" data-detached-picker-close>${escapeHtml(
            t("setup.residuePicker.detached.close")
          )}</button>
        </div>
      </div>
    `;
    const closeBtn = el.detachedResiduePickerRoot.querySelector("[data-detached-picker-close]");
    if (closeBtn instanceof HTMLElement) {
      closeBtn.addEventListener("click", () => {
        window.close();
      });
    }
    return;
  }

  const contextLabel = residuePickerContextLabel(request.context);
  el.detachedResiduePickerRoot.innerHTML = `
    <div class="detached-picker-shell">
      <div class="detached-picker-hero">
        <div class="detached-picker-copy">
          <strong>${escapeHtml(t("setup.residuePicker.detached.title"))}</strong>
          <p>${escapeHtml(t("setup.residuePicker.detached.desc", { context: contextLabel }))}</p>
        </div>
        <button type="button" class="ghost" data-detached-picker-close>${escapeHtml(
          t("setup.residuePicker.detached.close")
        )}</button>
      </div>
      <div class="detached-picker-card-slot"></div>
    </div>
  `;

  const closeBtn = el.detachedResiduePickerRoot.querySelector("[data-detached-picker-close]");
  if (closeBtn instanceof HTMLElement) {
    closeBtn.addEventListener("click", () => {
      window.close();
    });
  }

  const cardSlot = el.detachedResiduePickerRoot.querySelector(".detached-picker-card-slot");
  if (!(cardSlot instanceof HTMLElement)) return;
  const card = buildResiduePickerCard({
    targetPdbText: request.targetPdbText,
    targetFastaText: request.targetFastaText,
    rfd3PdbText: request.rfd3PdbText,
    selectedRunId: request.selectedRunId,
    pickerProvider: request.pickerProvider || "colabfold",
    detached: true,
    applyButtonLabel: t("setup.residuePicker.detached.applyClose"),
    rerender: () => renderDetachedResiduePickerWorkspace(),
    onPredictLoaded: ({ outRunId, selectedPath, selectedPdb }) => {
      state.detachedResiduePicker.predictedResult = {
        outRunId,
        selectedPath,
        selectedPdb,
        fastaText: request.targetFastaText,
      };
    },
    onApplySelection: (mappedSelection, selectedCount) => {
      const payload = createDetachedResiduePickerResultPayload(request, mappedSelection, selectedCount);
      const delivered = dispatchDetachedResiduePickerResult(payload);
      if (delivered) {
        removeDetachedResiduePickerRequest(request.token);
      }
      return delivered;
    },
    onApplyCompleted: () => {
      window.setTimeout(() => {
        window.close();
      }, 80);
    },
  });
  cardSlot.appendChild(card);
}

function renderWorkflowStudioResiduePicker(mountEl, session, activeStage) {
  if (!mountEl || !session || activeStage !== "design") return;
  const mergedAnswers = workflowStudioDraftAnswers(session);
  const selectedRunIdForPicker = String(workflowStudioSessionRunKey(session) || "").trim();
  const targetPdbText = getTargetInputPdbTextFromAnswers(mergedAnswers);
  const targetFastaText = getTargetInputFastaTextFromAnswers(mergedAnswers);
  const rfd3PdbText = getRfd3InputPdbTextFromAnswers(mergedAnswers);
  const pickerProvider = mergedAnswers.af2_provider || "colabfold";
  const card = buildResiduePickerLauncherCard({
    runId: selectedRunIdForPicker,
    onResetSelection: () => {
      clearSetupResiduePickerSelectionState();
      clearWorkflowStudioFixedPositionsExtraState(session.session_id);
      renderWorkflowStudio();
    },
    onOpenDetached: () => {
      openDetachedResiduePicker({
        context: "studio",
        sessionId: session.session_id,
        activeStage,
        targetPdbText,
        targetFastaText,
        rfd3PdbText,
        selectedRunId: selectedRunIdForPicker,
        pickerProvider,
        snapshotOverride: buildWorkflowStudioResiduePickerSnapshot(session, {
          targetPdbText,
          rfd3PdbText,
        }),
      });
    },
  });
  card.classList.add("studio-residue-picker-card");
  mountEl.appendChild(card);
}

function renderWorkflowStudioSessionList() {
  if (!el.studioSessionList) return;
  const sessions = workflowStudioSessionsOrdered();
  const duplicateCounts = workflowStudioSessionDuplicateCounts(sessions);
  el.studioSessionList.innerHTML = "";
  if (!sessions.length) {
    el.studioSessionList.innerHTML = `<div class="placeholder">${escapeHtml(t("studio.sessions.none"))}</div>`;
    return;
  }
  sessions.forEach((session) => {
    const sessionId = String(session?.session_id || "").trim();
    if (!sessionId) return;
    const item = document.createElement("div");
    item.className = "run-item studio-session-item";
    if (sessionId === String(state.currentWorkflowStudioSessionId || "").trim()) {
      item.classList.add("active");
    }

    const summary = document.createElement("div");
    summary.className = "studio-session-copy";
    const title = document.createElement("strong");
    title.textContent = workflowStudioSessionLabel(session) || sessionId;
    const metaText = workflowStudioSessionDetailLabel(session);
    summary.appendChild(title);
    if (metaText) {
      const meta = document.createElement("div");
      meta.className = "studio-session-meta";
      meta.textContent = metaText;
      summary.appendChild(meta);
    }

    const actions = document.createElement("div");
    actions.className = "run-item-actions studio-session-actions";
    if (sessionId === String(state.currentWorkflowStudioSessionId || "").trim()) {
      const currentTag = document.createElement("span");
      currentTag.className = "stage-tag";
      currentTag.textContent = t("studio.current");
      actions.appendChild(currentTag);
    } else {
      const loadBtn = document.createElement("button");
      loadBtn.type = "button";
      loadBtn.className = "ghost studio-session-action";
      loadBtn.dataset.studioSessionAction = "load";
      loadBtn.dataset.sessionId = sessionId;
      loadBtn.textContent = t("runs.load");
      actions.appendChild(loadBtn);
    }

    const runKey = workflowStudioSessionRunKey(session);
    const duplicateCount = runKey ? duplicateCounts.get(runKey) || 0 : 0;
    if (duplicateCount > 1) {
      const cleanupBtn = document.createElement("button");
      cleanupBtn.type = "button";
      cleanupBtn.className = "ghost studio-session-action";
      cleanupBtn.dataset.studioSessionAction = "cleanup";
      cleanupBtn.dataset.sessionId = sessionId;
      cleanupBtn.textContent = t("studio.cleanupDuplicates");
      actions.appendChild(cleanupBtn);
    }

    const deleteBtn = document.createElement("button");
    deleteBtn.type = "button";
    deleteBtn.className = "run-delete";
    deleteBtn.dataset.studioSessionAction = "delete";
    deleteBtn.dataset.sessionId = sessionId;
    deleteBtn.textContent = t("runs.delete");
    actions.appendChild(deleteBtn);

    item.appendChild(summary);
    item.appendChild(actions);
    el.studioSessionList.appendChild(item);
  });
}

function renderWorkflowStudio() {
  const session = workflowStudioSessionForId();
  const showCreationBuilder = Boolean(state.studioBuilderOpen) || !session;
  const studioBuilderCard = showCreationBuilder
    ? buildWorkflowDesignerCard({
        onLaunch: async () => {
          await createWorkflowStudioFromStudio();
        },
        rerender: () => {
          renderWorkflowStudio();
        },
        allowTargetInputEdit: true,
        secondaryAction: session
          ? {
              label: t("common.close"),
              onClick: () => {
                state.studioBuilderOpen = false;
                renderWorkflowStudio();
              },
            }
          : null,
        extraClass: "studio-workflow-designer",
      })
    : null;
  renderWorkflowStudioSessionList();
  if (el.studioAdoptRunBtn) {
    el.studioAdoptRunBtn.disabled = !String(state.currentRunId || "").trim();
  }
  if (el.studioRunBtn) {
    el.studioRunBtn.disabled = !session || state.runSubmitting || workflowStudioRunActive(session);
  }
  if (el.studioStopBtn) {
    el.studioStopBtn.disabled = !session || !workflowStudioRunActive(session);
  }
  if (el.studioResumeBtn) {
    el.studioResumeBtn.disabled = !session || !workflowStudioActionRunId(session) || workflowStudioRunActive(session) || Boolean(state.runSubmitting);
  }
  if (el.studioRefreshBtn) {
    el.studioRefreshBtn.disabled = false;
  }
  if (el.studioOpenMonitorBtn) {
    el.studioOpenMonitorBtn.disabled = !String(workflowStudioActionRunId(session) || "").trim();
  }
  updateWorkflowStudioRunStatus(session);
  if (!el.workflowStudioRoot) return;
  el.workflowStudioRoot.innerHTML = "";
  if (!session) {
    setFilePreviewPlaceholder("studio");
    if (studioBuilderCard) {
      el.workflowStudioRoot.appendChild(studioBuilderCard);
    }
    const emptyNote = document.createElement("div");
    emptyNote.className = "studio-empty";
    emptyNote.innerHTML = `
      <div>
        <strong>${escapeHtml(t("studio.empty.title"))}</strong>
        <p>${escapeHtml(t("studio.empty.desc"))}</p>
      </div>
    `;
    el.workflowStudioRoot.appendChild(emptyNote);
    return;
  }
  const activeStage = resolveWorkflowStudioStageForSession(
    session?.nodes,
    session.active_stage || session.nodes?.[0] || "",
    session.nodes?.[0] || "msa"
  );
  const preview = workflowStudioExecutionPreview(session, activeStage);
  const preflightRequest = buildWorkflowStudioPreflightRequest(session, activeStage, preview);
  const activeCheckState = workflowStudioCheckState(session.session_id);
  const studioCheck =
    activeCheckState && activeCheckState.stage === preflightRequest.stage && activeCheckState.key === preflightRequest.key
      ? activeCheckState
      : null;
  const dependencyState = workflowStudioDependencyState(session, activeStage, preview);
  const fieldErrors = Object.values(state.workflowStudioFieldErrorsBySession?.[session.session_id] || {})
    .map((item) => String(item || "").trim())
    .filter(Boolean);
  const requiredInputs = (studioCheck?.required_inputs || [])
    .map((item) => String(item?.message || item?.id || "").trim())
    .filter(Boolean);
  const preflightBlockingErrors =
    studioCheck?.status === "ready" && studioCheck.ok === false
      ? (studioCheck.errors || []).map((item) => String(item || "").trim()).filter(Boolean)
      : [];
  const blockingErrors = [...preflightBlockingErrors, ...dependencyState.blockingErrors];
  const warningMessages = [
    ...(studioCheck?.warnings || []).map((item) => String(item || "").trim()).filter(Boolean),
    ...dependencyState.warnings,
  ];
  const hasBlockingIssues = fieldErrors.length > 0 || requiredInputs.length > 0 || blockingErrors.length > 0;
  const checkPending = !studioCheck || studioCheck.status === "loading" || dependencyState.pending;
  const validationTone =
    hasBlockingIssues
        ? "error"
        : checkPending
          ? "loading"
        : studioCheck?.status === "error" || warningMessages.length
          ? "warn"
          : "ok";
  const validationTitle =
    hasBlockingIssues
        ? t("studio.validation.blocked")
        : checkPending
          ? t("studio.validation.loading")
        : studioCheck?.status === "error"
          ? t("studio.validation.failed")
          : t("studio.validation.ready");
  const summaryCards = workflowStudioSummaryCards(session, preview);
  if (el.studioRunBtn) {
    el.studioRunBtn.disabled = !session || state.runSubmitting || workflowStudioRunActive(session) || hasBlockingIssues;
  }
  const stageButtons = (Array.isArray(session.nodes) ? session.nodes : []).map((stage) => {
    const stageState = workflowStudioStageState(session, stage);
    const active = stage === activeStage;
    const runId = String(session.stage_run_ids?.[stage] || "").trim();
    return `
      <button
        type="button"
        class="studio-stage-btn ${escapeAttr(stageState)}${active ? " active" : ""}"
        data-studio-stage="${escapeAttr(stage)}"
      >
        <span class="studio-stage-title">
          <span>${escapeHtml(formatStageLabel(stage))}</span>
          <span class="studio-badge ${escapeAttr(stageState)}">${escapeHtml(t(`studio.status.${stageState}`))}</span>
        </span>
        <span class="studio-stage-meta">${escapeHtml(runId || "-")}</span>
      </button>
    `;
  }).join("");
  const mergedAnswers = workflowStudioDraftAnswers(session);
  const studioTargetPdbText = targetInputPdbText(mergedAnswers);
  const showStudioRfd3InputField = shouldShowRfd3InputPdbField({
    mode: "workflow",
    answers: mergedAnswers,
    nodes: session?.nodes || [],
    overrideVisible: workflowStudioRfd3InputOverrideVisible(session),
  });
  const studioRfd3Enabled = rfd3EnabledForContext({
    mode: "workflow",
    answers: mergedAnswers,
    nodes: session?.nodes || [],
  });
  const studioRfd3Mode = effectiveRfd3Mode(mergedAnswers) || "local_diversify";
  const visibleFields = workflowStudioVisibleStageFields(activeStage, {
    answers: mergedAnswers,
    nodes: session?.nodes || [],
    overrideVisible: workflowStudioRfd3InputOverrideVisible(session),
  });
  const designChainValue = Array.isArray(mergedAnswers.design_chains) ? mergedAnswers.design_chains : [];
  const designChainOptions = workflowStudioDesignChainOptionsForAnswers(mergedAnswers, designChainValue);
  const hasExplicitContig = workflowStudioHasExplicitContigDraft(session);
  const computedContigValue = String(mergedAnswers.rfd3_contig || "").trim();
  const previewContigOptions = workflowStudioContigOptionsForAnswers(mergedAnswers, computedContigValue);
  const contigValue =
    computedContigValue ||
    (!hasExplicitContig && activeStage === "rfd3" && rfd3ModeUsesContig(studioRfd3Mode) && previewContigOptions.length
      ? previewContigOptions[0].value
      : "");
  const contigOptions = workflowStudioContigOptionsForAnswers(mergedAnswers, contigValue);
  const fieldCards = visibleFields.length
    ? visibleFields
        .map((fieldId) => {
          const question = normalizeQuestion({ id: fieldId }) || { id: fieldId };
          const value = mergedAnswers[fieldId] !== undefined ? mergedAnswers[fieldId] : question.default;
          const label = question.labelKey ? t(question.labelKey) : question.label || fieldId;
          const help = question.questionKey ? t(question.questionKey) : question.question || "";
          const error = workflowStudioFieldError(session.session_id, fieldId);
          const isBool = ANSWER_BOOL_KEYS.has(fieldId);
          const isChoice = fieldId === "af2_provider";
          const isDesignChains = fieldId === "design_chains";
          const isContigField = fieldId === "rfd3_contig";
          const isAttachable = fieldId === "target_input" || fieldId === "rfd3_input_pdb";
          const isLongText =
            ["target_input", "rfd3_input_pdb", "fixed_positions_extra"].includes(fieldId) ||
            ANSWER_TEXTAREA_KEYS.has(fieldId) ||
            question.multiline;
          const isNumeric = ANSWER_INT_KEYS.has(fieldId) || ANSWER_FLOAT_KEYS.has(fieldId);
          const placeholder = question.placeholder ? ` placeholder="${escapeAttr(String(question.placeholder))}"` : "";
          const renderedValue = isContigField ? contigValue : value;
          let detailNote = "";
          const control = isBool
            ? `
              <label class="studio-field-toggle">
                <input type="checkbox" data-studio-field="${escapeAttr(fieldId)}" ${
                  value === true ? "checked" : ""
                } />
                <span>${escapeHtml(value === true ? t("common.enabled") : t("common.disabled"))}</span>
              </label>
            `
            : isDesignChains && designChainOptions.length
              ? `
                <details
                  class="studio-multiselect"
                  data-studio-multiselect="${escapeAttr(fieldId)}"
                  ${state.studioOpenField === fieldId ? "open" : ""}
                >
                  <summary>${escapeHtml(
                    Array.isArray(value) && value.length ? value.join(", ") : t("choice.allChains")
                  )}</summary>
                  <div class="studio-multiselect-menu">
                    <button type="button" class="ghost small" data-studio-design-all>${escapeHtml(
                      t("choice.allChains")
                    )}</button>
                    <div class="studio-multiselect-options">
                      ${designChainOptions
                        .map((chain) => {
                          const checked = Array.isArray(value) && value.includes(chain);
                          return `
                            <label class="studio-multiselect-option">
                              <input type="checkbox" data-studio-chain-option="${escapeAttr(chain)}" ${
                                checked ? "checked" : ""
                              } />
                              <span>${escapeHtml(denormalizeChainId(chain) || "_")}</span>
                            </label>
                          `;
                        })
                        .join("")}
                    </div>
                  </div>
                </details>
              `
            : isContigField && contigOptions.length
              ? `
                <select data-studio-field="${escapeAttr(fieldId)}">
                  <option value=""${!String(renderedValue || "").trim() ? " selected" : ""}>${escapeHtml(
                    t("choice.contigNone")
                  )}</option>
                  ${contigOptions
                    .map(
                      (item) => `
                        <option value="${escapeAttr(item.value)}"${String(renderedValue || "") === item.value ? " selected" : ""}>
                          ${escapeHtml(item.label)}
                        </option>
                      `
                    )
                    .join("")}
                </select>
              `
            : isChoice
              ? `
                <select data-studio-field="${escapeAttr(fieldId)}">
                  <option value="colabfold"${String(value || "colabfold") === "colabfold" ? " selected" : ""}>${escapeHtml(
                    af2ProviderName("colabfold", state.lang || "en")
                  )}</option>
                  <option value="af2"${String(value || "") === "af2" ? " selected" : ""}>${escapeHtml(
                    af2ProviderName("af2", state.lang || "en")
                  )}</option>
                </select>
              `
            : isLongText
                ? `<textarea data-studio-field="${escapeAttr(fieldId)}"${placeholder}>${escapeHtml(
                    formatAnswerValue(value)
                  )}</textarea>`
                : `<input type="${isNumeric ? "number" : "text"}" data-studio-field="${escapeAttr(
                    fieldId
                  )}" value="${escapeAttr(formatAnswerValue(value))}"${placeholder} />`;
          if (isDesignChains) {
            detailNote = designChainOptions.length ? t("choice.chainDefaultNote") : t("choice.chainNote");
          } else if (isContigField) {
            detailNote = contigOptions.length ? t("choice.contigPositiveOnly") : t("choice.contigNote");
          }
          const cardClass = isLongText ? "studio-field full" : "studio-field";
          return `
            <div class="${cardClass}">
              <div class="studio-field-head">
                <span class="studio-field-label">${escapeHtml(label)}</span>
                <span class="studio-field-help">${escapeHtml(help)}</span>
              </div>
              ${
                isAttachable
                  ? `<div class="studio-field-actions">
                      <button type="button" class="ghost" data-studio-attach="${escapeAttr(fieldId)}">${escapeHtml(
                        t("attachment.select")
                      )}</button>
                    </div>`
                  : ""
              }
              ${control}
              ${detailNote ? `<div class="studio-field-note">${escapeHtml(detailNote)}</div>` : ""}
              ${error ? `<div class="studio-field-error">${escapeHtml(error)}</div>` : ""}
            </div>
          `;
        })
        .join("")
    : `<div class="placeholder">${escapeHtml(t("hint.none"))}</div>`;
  const studioRfd3Note =
    workflowStudioNodeBaseStage(activeStage, "") === "rfd3" && studioRfd3Enabled && studioTargetPdbText
      ? `
          <div class="studio-note">
            ${escapeHtml(
              showStudioRfd3InputField
                ? t("studio.rfd3.defaultFromTargetOverride")
                : t("studio.rfd3.defaultFromTarget")
            )}
          </div>
          <div class="studio-field-actions">
            <button type="button" class="ghost" data-studio-rfd3-override="${
              showStudioRfd3InputField ? "reset" : "show"
            }">${escapeHtml(
              showStudioRfd3InputField ? t("setup.rfd3.useTargetDefault") : t("setup.rfd3.useSeparateInput")
            )}</button>
          </div>
        `
      : "";
  const activeStageState = workflowStudioStageState(session, activeStage);
  const stageArtifacts = workflowStudioStageArtifacts(activeStage);
  const retainedArtifactPath = workflowStudioRetainedArtifactPath(stageArtifacts, state.studioArtifactPath);
  const selectedArtifact =
    stageArtifacts.find((item) => String(item?.path || "").trim() === retainedArtifactPath) || null;
  const selectedArtifactPath = String(selectedArtifact?.path || "").trim();
  const autoPreviewNeeded = selectedArtifactPath !== String(state.studioArtifactPath || "").trim();
  state.studioArtifactPath = selectedArtifactPath;
  const artifactList = stageArtifacts.length
    ? `
        <label class="studio-result-select">
          <span>${escapeHtml(t("studio.results.select"))}</span>
          <select data-studio-artifact-select>
            <option value="">${escapeHtml(t("studio.results.selectPlaceholder"))}</option>
            ${stageArtifacts
              .map((item) => {
                const path = String(item?.path || "");
                return `
                  <option value="${escapeAttr(path)}"${selectedArtifactPath === path ? " selected" : ""}>
                    ${escapeHtml(displayArtifactPath(path))}
                  </option>
                `;
              })
              .join("")}
          </select>
          <span class="studio-result-meta">${escapeHtml(t("studio.results.fileCount", { count: stageArtifacts.length }))}</span>
        </label>
      `
    : `<div class="placeholder">${escapeHtml(
        t(activeStageState === "skipped" ? "studio.noResultsSkipped" : "studio.noResults")
      )}</div>`;
  const history = Array.isArray(session.history) ? session.history : [];
  const historyHtml = history.length
    ? history
        .map((item) => {
          const start = formatStageLabel(item.target_node || item.start_from || "");
          const stop = formatStageLabel(item.target_node || item.stop_after || "");
          return `
            <div class="studio-history-item">
              <strong>${escapeHtml(String(item.run_id || ""))}</strong><br />
              ${escapeHtml(`${start} -> ${stop}`)}${item.created_at ? ` · ${escapeHtml(String(item.created_at))}` : ""}
            </div>
          `;
        })
        .join("")
    : `<div class="placeholder">${escapeHtml(t("studio.noHistory"))}</div>`;
  const nextStage = nextWorkflowStudioStage(session.nodes, activeStage);
  const rerunNoteKey = workflowStudioExecutionNoteKey(preview, activeStage);
  const rerunNote = t(rerunNoteKey, { stage: formatStageLabel(preview.requiredStart) });
  const validationLists = [
    fieldErrors.length
      ? `<div class="studio-validation-group">
          <strong>${escapeHtml(t("studio.validation.editor"))}</strong>
          <ul>${fieldErrors.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>
        </div>`
      : "",
    requiredInputs.length
      ? `<div class="studio-validation-group">
          <strong>${escapeHtml(t("studio.validation.required"))}</strong>
          <ul>${requiredInputs.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>
        </div>`
      : "",
    blockingErrors.length
      ? `<div class="studio-validation-group">
          <strong>${escapeHtml(t("studio.validation.errors"))}</strong>
          <ul>${blockingErrors.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>
        </div>`
      : "",
    warningMessages.length
      ? `<div class="studio-validation-group">
          <strong>${escapeHtml(t("studio.validation.warnings"))}</strong>
          <ul>${warningMessages.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>
        </div>`
      : "",
    studioCheck?.status === "error" && !warningMessages.length
      ? `<div class="studio-validation-group">
          <strong>${escapeHtml(t("studio.validation.warnings"))}</strong>
          <ul>${(studioCheck.errors || []).map((item) => `<li>${escapeHtml(String(item || ""))}</li>`).join("")}</ul>
        </div>`
      : "",
  ]
    .filter(Boolean)
    .join("");
  const validationPanel = `
    <div class="studio-validation-panel ${escapeAttr(validationTone)}">
      <div class="studio-validation-title">${escapeHtml(t("studio.validation.title"))}</div>
      <div class="studio-validation-message">${escapeHtml(validationTitle)}</div>
      ${validationLists ? `<div class="studio-validation-list">${validationLists}</div>` : ""}
    </div>
  `;
  el.workflowStudioRoot.innerHTML = `
    <div class="studio-grid">
      <aside class="studio-stage-rail">
        <section class="studio-section">
          <div class="studio-section-head">
            <strong>${escapeHtml(t("studio.section.stages"))}</strong>
          </div>
          <div class="studio-stage-list">${stageButtons}</div>
        </section>
        <section class="studio-section">
          <div class="studio-section-head">
            <strong>${escapeHtml(t("studio.section.history"))}</strong>
          </div>
          <div class="studio-history-list">${historyHtml}</div>
        </section>
      </aside>
      <div class="studio-main">
        <section class="studio-section">
          <div class="studio-section-head">
            <strong>${escapeHtml(t("studio.section.summary"))}</strong>
          </div>
          <div class="studio-summary-grid">
            ${summaryCards
              .map(
                (item) => `
                  <div class="studio-summary-card">
                    <span class="label">${escapeHtml(item.label)}</span>
                    <span class="value">${escapeHtml(item.value)}</span>
                  </div>
                `
              )
              .join("")}
          </div>
          ${validationPanel}
          <div class="studio-note${
            preview.requiredStart !== workflowStudioNodeBaseStage(activeStage, "") && preview.requiredStart !== "msa"
              ? " warn"
              : ""
          }">
            ${escapeHtml(rerunNote)}
          </div>
          <div class="studio-summary-actions">
            <button type="button" class="primary" data-studio-action="run"${hasBlockingIssues ? " disabled" : ""}>${escapeHtml(
              t("studio.action.run")
            )}</button>
            <button type="button" class="ghost" data-studio-action="stop"${workflowStudioRunActive(session) ? "" : " disabled"}>${escapeHtml(
              t("monitor.stop")
            )}</button>
            <button
              type="button"
              class="ghost"
              data-studio-action="resume"
              ${!workflowStudioActionRunId(session) || workflowStudioRunActive(session) || state.runSubmitting ? " disabled" : ""}
            >${escapeHtml(t("monitor.resume"))}</button>
            ${
              nextStage
                ? `<button type="button" class="ghost" data-studio-action="next">${escapeHtml(
                    t("studio.action.next", { stage: formatStageLabel(nextStage) })
                  )}</button>`
                : ""
            }
            <button type="button" class="ghost" data-studio-action="monitor">${escapeHtml(t("studio.action.monitor"))}</button>
          </div>
        </section>
        <section class="studio-section">
          <div class="studio-section-head">
            <strong>${escapeHtml(
              t("studio.section.editor", { stage: formatStageLabel(activeStage) })
            )}</strong>
          </div>
          ${studioRfd3Note}
          <div class="studio-editor-grid">${fieldCards}</div>
          ${
            workflowStudioNodeBaseStage(activeStage, "") === "design"
              ? `<div class="studio-inline-slot" data-studio-residue-picker></div>`
              : ""
          }
        </section>
        <section class="studio-section">
          <div class="studio-section-head">
            <strong>${escapeHtml(
              t("studio.section.results", { stage: formatStageLabel(activeStage) })
            )}</strong>
          </div>
          <div class="studio-artifact-list">${artifactList}</div>
        </section>
      </div>
    </div>
  `;
  if (studioBuilderCard) {
    el.workflowStudioRoot.prepend(studioBuilderCard);
  }
  queueWorkflowStudioCheck(session, activeStage, preflightRequest);
  const residuePickerMount = el.workflowStudioRoot.querySelector("[data-studio-residue-picker]");
  if (residuePickerMount) {
    renderWorkflowStudioResiduePicker(residuePickerMount, session, activeStage);
  }
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-stage]")).forEach((btn) => {
    btn.addEventListener("click", () => {
      const stage = workflowStudioNodeId(btn.getAttribute("data-studio-stage") || "", activeStage);
      if (!stage) return;
      session.active_stage = stage;
      session.updated_at = new Date().toISOString();
      upsertWorkflowStudioSession(session);
      renderWorkflowStudio();
    });
  });
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-artifact-select]")).forEach((select) => {
    select.addEventListener("change", async () => {
      const path = String(select.value || "").trim();
      if (!path) {
        state.studioArtifactPath = "";
        setFilePreviewPlaceholder("studio");
        renderWorkflowStudio();
        return;
      }
      const artifact = (Array.isArray(state.artifacts) ? state.artifacts : []).find(
        (item) => item && item.type === "file" && String(item.path || "") === path
      );
      if (!artifact) return;
      state.studioArtifactPath = path;
      await previewArtifact(artifact, {
        target: "studio",
        runId: String(session.head_run_id || state.currentRunId || "").trim(),
      });
      renderWorkflowStudio();
    });
  });
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-rfd3-override]")).forEach((btn) => {
    btn.addEventListener("click", () => {
      const action = String(btn.getAttribute("data-studio-rfd3-override") || "").trim().toLowerCase();
      const current = workflowStudioSessionForId(session.session_id);
      if (!current) return;
      if (!current.stage_drafts.rfd3) current.stage_drafts.rfd3 = {};
      delete current.stage_drafts.rfd3.rfd3_input_pdb;
      if (!current.ui_state || typeof current.ui_state !== "object" || Array.isArray(current.ui_state)) {
        current.ui_state = {};
      }
      if (action === "show") {
        current.ui_state.rfd3_input_override_visible = true;
        current.stage_drafts.rfd3.rfd3_use = true;
      } else {
        delete current.ui_state.rfd3_input_override_visible;
      }
      current.updated_at = new Date().toISOString();
      upsertWorkflowStudioSession(current);
      renderWorkflowStudio();
    });
  });
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-attach]")).forEach((btn) => {
    btn.addEventListener("click", () => {
      const fieldId = String(btn.getAttribute("data-studio-attach") || "").trim();
      if (!fieldId) return;
      const picker = document.createElement("input");
      picker.type = "file";
      picker.accept = workflowStudioFieldAccept(fieldId);
      picker.addEventListener("change", async () => {
        const file = picker.files?.[0];
        if (!file) return;
        try {
          const text = await file.text();
          const current = workflowStudioSessionForId(session.session_id);
          if (!current) return;
          if (!current.stage_drafts[activeStage]) current.stage_drafts[activeStage] = {};
          current.stage_drafts[activeStage][fieldId] = text;
          if (fieldId === "rfd3_input_pdb") {
            if (!current.ui_state || typeof current.ui_state !== "object" || Array.isArray(current.ui_state)) {
              current.ui_state = {};
            }
            current.ui_state.rfd3_input_override_visible = true;
            if (!current.stage_drafts.rfd3) current.stage_drafts.rfd3 = {};
            current.stage_drafts.rfd3.rfd3_use = true;
          }
          current.updated_at = new Date().toISOString();
          setWorkflowStudioFieldError(current.session_id, fieldId, "");
          upsertWorkflowStudioSession(current);
          setMessage(t("attachment.attachedName", { name: file.name }), "ai");
          renderWorkflowStudio();
        } catch (err) {
          setMessage(t("attachment.failed", { error: err.message }), "ai");
        }
      });
      picker.click();
    });
  });
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-multiselect]")).forEach((details) => {
    details.addEventListener("toggle", () => {
      const fieldId = String(details.getAttribute("data-studio-multiselect") || "").trim();
      if (!fieldId) return;
      state.studioOpenField = details.open ? fieldId : state.studioOpenField === fieldId ? "" : state.studioOpenField;
    });
  });
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-design-all]")).forEach((btn) => {
    btn.addEventListener("click", () => {
      const current = workflowStudioSessionForId(session.session_id);
      if (!current) return;
      if (!current.stage_drafts[activeStage]) current.stage_drafts[activeStage] = {};
      current.stage_drafts[activeStage].design_chains = [];
      current.updated_at = new Date().toISOString();
      state.studioOpenField = "design_chains";
      setWorkflowStudioFieldError(current.session_id, "design_chains", "");
      upsertWorkflowStudioSession(current);
      renderWorkflowStudio();
    });
  });
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-chain-option]")).forEach((input) => {
    input.addEventListener("change", () => {
      const chain = String(input.getAttribute("data-studio-chain-option") || "").trim();
      if (!chain) return;
      const current = workflowStudioSessionForId(session.session_id);
      if (!current) return;
      if (!current.stage_drafts[activeStage]) current.stage_drafts[activeStage] = {};
      const existing = Array.isArray(current.stage_drafts[activeStage].design_chains)
        ? current.stage_drafts[activeStage].design_chains
        : Array.isArray(mergedAnswers.design_chains)
          ? mergedAnswers.design_chains
          : [];
      const next = new Set(existing.map((item) => String(item || "").trim()).filter(Boolean));
      if (input.checked) {
        next.add(chain);
      } else {
        next.delete(chain);
      }
      current.stage_drafts[activeStage].design_chains = Array.from(next).sort((a, b) => a.localeCompare(b));
      current.updated_at = new Date().toISOString();
      state.studioOpenField = "design_chains";
      setWorkflowStudioFieldError(current.session_id, "design_chains", "");
      upsertWorkflowStudioSession(current);
      renderWorkflowStudio();
    });
  });
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-field]")).forEach((input) => {
    const fieldId = String(input.getAttribute("data-studio-field") || "").trim();
    input.addEventListener("change", () => {
      const current = workflowStudioSessionForId(session.session_id);
      if (!current) return;
      if (!current.stage_drafts[activeStage]) current.stage_drafts[activeStage] = {};
      let nextValue = "";
      if (input.type === "checkbox") {
        nextValue = Boolean(input.checked);
      } else {
        const parsed = parseAnswerValue(fieldId, input.value);
        if (parsed.error) {
          setWorkflowStudioFieldError(current.session_id, fieldId, parsed.error);
          renderWorkflowStudio();
          return;
        }
        nextValue = parsed.value;
      }
      setWorkflowStudioFieldError(current.session_id, fieldId, "");
      current.stage_drafts[activeStage][fieldId] = nextValue;
      if (fieldId === "rfd3_contig") {
        if (!current.stage_explicit_empty) current.stage_explicit_empty = {};
        if (!current.stage_explicit_empty.rfd3) current.stage_explicit_empty.rfd3 = {};
        current.stage_explicit_empty.rfd3.rfd3_contig = typeof nextValue === "string" && !nextValue.trim();
      }
      current.updated_at = new Date().toISOString();
      upsertWorkflowStudioSession(current);
      renderWorkflowStudio();
    });
  });
  Array.from(el.workflowStudioRoot.querySelectorAll("[data-studio-action]")).forEach((btn) => {
    btn.addEventListener("click", async () => {
      const action = String(btn.getAttribute("data-studio-action") || "").trim().toLowerCase();
      if (action === "run") {
        await runWorkflowStudioStage(session.session_id);
        return;
      }
      if (action === "stop") {
        await cancelCurrentRun(workflowStudioActionRunId(session));
        renderWorkflowStudio();
        return;
      }
      if (action === "resume") {
        await resumeCurrentRun(workflowStudioActionRunId(session), { targetTab: "studio" });
        renderWorkflowStudio();
        return;
      }
      if (action === "next") {
        const current = workflowStudioSessionForId(session.session_id);
        if (!current) return;
        const next = nextWorkflowStudioStage(current.nodes, current.active_stage);
        if (!next) return;
        current.active_stage = next;
        current.updated_at = new Date().toISOString();
        upsertWorkflowStudioSession(current);
        renderWorkflowStudio();
        return;
      }
      if (action === "monitor") {
        await openWorkflowStudioRunInMonitor(workflowStudioSessionForId(session.session_id) || session);
        return;
      }
      if (action === "setup") {
        setActiveTab("advanced");
      }
    });
  });
  if (!selectedArtifact) {
    if (stageArtifacts.length) {
      setFilePreviewPlaceholder("studio");
    } else {
      setFilePreviewPlaceholder("studio", activeStageState === "skipped" ? "studio.noResultsSkipped" : "studio.noResults");
    }
  } else if (autoPreviewNeeded) {
    const previewRunId = String(session.head_run_id || state.currentRunId || "").trim();
    if (previewRunId) {
      void previewArtifact(selectedArtifact, {
        target: "studio",
        runId: previewRunId,
      });
    }
  }
}

async function runWorkflowStudioStage(sessionId = state.currentWorkflowStudioSessionId) {
  if (state.runSubmitting) {
    setMessage(t("run.alreadyRunning"), "ai");
    return;
  }
  const session = workflowStudioSessionForId(sessionId);
  if (!session) return;
  const fieldErrors = Object.values(state.workflowStudioFieldErrorsBySession?.[session.session_id] || {}).filter(Boolean);
  if (fieldErrors.length) {
    setMessage(t("studio.runFailed", { error: fieldErrors[0] }), "ai");
    return;
  }
  const targetStage = resolveWorkflowStudioStageForSession(
    session?.nodes,
    session.active_stage || session.nodes?.[0] || "",
    session.nodes?.[0] || "msa"
  );
  const route = workflowStudioExecutionTarget(targetStage);
  if (!targetStage || !route.stopAfter) return;
  const preview = workflowStudioExecutionPreview(session, targetStage);
  const actionRunId = String(workflowStudioActionRunId(session) || "").trim();
  if (actionRunId && actionRunId !== String(state.currentRunId || "").trim()) {
    setCurrentRunId(actionRunId);
    await pollStatus(actionRunId);
    await refreshArtifacts({ runId: actionRunId });
  }
  const dependencyState = workflowStudioDependencyState(session, targetStage, preview);
  if (dependencyState.blockingErrors.length) {
    setMessage(t("studio.runFailed", { error: dependencyState.blockingErrors[0] }), "ai");
    renderWorkflowStudio();
    return;
  }
  const prefix = state.user?.run_prefix || buildUserPrefix({ name: state.user?.username || "user" });
  const runId = preview.reuseRun ? session.head_run_id : createRunId(prefix);
  const args = reconcileUserInputsIntoArgs(
    withProjectRoundContext(
      buildRunArguments({
        prompt: session.prompt || el.promptInput.value.trim(),
        routed: { stop_after: route.stopAfter },
        answers: {
          ...preview.nextPayload,
          ...(route.selectedTiers ? { selected_tiers: route.selectedTiers } : {}),
        },
        runId,
      }),
      currentProjectRoundContext()
    )
  );
  if (preview.reuseRun && preview.requiredStart !== "msa") {
    args.start_from = preview.requiredStart;
  } else {
    delete args.start_from;
  }
  args.stop_after = route.stopAfter;
  if (route.selectedTiers) {
    args.selected_tiers = [...route.selectedTiers];
  } else {
    delete args.selected_tiers;
  }
  args.auto_recover = true;
  args.force = false;
  try {
    const preflight = await apiCall("pipeline.preflight", { ...args });
    if (preflight && preflight.ok === false) {
      const required = (preflight.required_inputs || []).map((item) => String(item?.message || item?.id || ""));
      const errors = (preflight.errors || []).map((item) => String(item || ""));
      const detail = [...required, ...errors].filter(Boolean).join(" / ");
      if (detail) {
        throw new Error(detail);
      }
    }
  } catch (err) {
    setMessage(t("studio.runFailed", { error: err.message }), "ai");
    return;
  }
  const requestSnapshot = cloneWorkflowStudioValue({
    ...preview.nextPayload,
    start_from: String(args.start_from || "msa").trim().toLowerCase(),
    stop_after: route.stopAfter,
    ...(route.selectedTiers ? { selected_tiers: [...route.selectedTiers] } : {}),
  });
  const previousPending = session.pending ? cloneWorkflowStudioValue(session.pending) : null;
  const previousHeadRunId = String(session.head_run_id || "").trim();
  const hadPreviousStageState = Object.prototype.hasOwnProperty.call(session.stage_states || {}, targetStage);
  const previousStageState = String(session.stage_states?.[targetStage] || "");
  const hadPreviousStageRunId = Object.prototype.hasOwnProperty.call(session.stage_run_ids || {}, targetStage);
  const previousStageRunId = String(session.stage_run_ids?.[targetStage] || "").trim();
  session.pending = {
    run_id: runId,
    start_from: String(args.start_from || "msa").trim().toLowerCase(),
    stop_after: route.stopAfter,
    target_node: targetStage,
    request_snapshot: requestSnapshot,
  };
  session.head_run_id = runId;
  session.updated_at = new Date().toISOString();
  session.stage_states[targetStage] = "launching";
  session.stage_run_ids[targetStage] = runId;
  upsertWorkflowStudioSession(session);
  state.runSubmitting = true;
  state.runningRunIds.add(runId);
  renderWorkflowStudio();
  updateRunEligibility(state.plan?.questions || []);
  updateMonitorActionButtons();
  try {
    const result = await apiCall("pipeline.run", args);
    const launchedRunId = String(result?.run_id || runId).trim() || runId;
    state.runningRunIds.add(launchedRunId);
    session.pending = {
      run_id: launchedRunId,
      start_from: String(args.start_from || "msa").trim().toLowerCase(),
      stop_after: route.stopAfter,
      target_node: targetStage,
      request_snapshot: requestSnapshot,
    };
    session.head_run_id = launchedRunId;
    session.updated_at = new Date().toISOString();
    session.stage_states[targetStage] = "running";
    session.stage_run_ids[targetStage] = launchedRunId;
    upsertWorkflowStudioSession(session);
    ensureWorkflowPlanForSessionRun(launchedRunId, session);
    await saveWorkflowStudioSessionToRun(session, launchedRunId);
    setMessage(
      t("studio.runStarted", {
        id: launchedRunId,
        start: formatStageLabel(String(args.start_from || "msa")),
        stop: formatStageLabel(targetStage),
      }),
      "ai"
    );
    setCurrentRunId(launchedRunId);
    armRunStatusGracePeriod(launchedRunId);
    updateRunInfo({
      run_id: launchedRunId,
      stage: String(args.start_from || targetStage || "msa"),
      state: "running",
      updated_at: new Date().toISOString(),
      detail: "",
    });
    setActiveTab("studio");
    await refreshRuns();
    ensureAutoPoll();
    await pollStatus(launchedRunId);
    await refreshArtifacts({ runId: launchedRunId });
  } catch (err) {
    session.pending = previousPending;
    session.head_run_id = previousHeadRunId;
    if (hadPreviousStageState) {
      session.stage_states[targetStage] = previousStageState;
    } else {
      delete session.stage_states[targetStage];
    }
    if (hadPreviousStageRunId) {
      session.stage_run_ids[targetStage] = previousStageRunId;
    } else {
      delete session.stage_run_ids[targetStage];
    }
    session.updated_at = new Date().toISOString();
    upsertWorkflowStudioSession(session);
    setMessage(t("studio.runFailed", { error: err.message }), "ai");
  } finally {
    state.runSubmitting = false;
    updateRunEligibility(state.plan?.questions || []);
    updateMonitorActionButtons();
    renderWorkflowStudio();
  }
}

function workflowCountsSvg(nodes, counts) {
  const stages = Array.isArray(nodes) ? nodes : [];
  if (!stages.length) return "";
  const values = stages.map((stage) => Number(counts?.[stage] || 0));
  const maxValue = Math.max(1, ...values);
  const width = Math.max(320, stages.length * 72);
  const height = 160;
  const bottom = 128;
  const barWidth = 34;
  const gap = (width - 40) / Math.max(1, stages.length);
  const bars = stages
    .map((stage, idx) => {
      const value = Number(counts?.[stage] || 0);
      const h = Math.round((value / maxValue) * 82);
      const x = Math.round(24 + idx * gap);
      const y = bottom - h;
      const stageLabel = stage === "novelty" ? t("stop.full") : formatStageLabel(stage);
      return `
        <g class="workflow-mini-bar">
          <rect x="${x}" y="${y}" width="${barWidth}" height="${h}" rx="6" />
          <text x="${x + barWidth / 2}" y="${Math.max(16, y - 6)}" text-anchor="middle">${value}</text>
          <text x="${x + barWidth / 2}" y="${bottom + 16}" text-anchor="middle">${escapeHtml(stageLabel)}</text>
        </g>
      `;
    })
    .join("");
  return `
    <svg viewBox="0 0 ${width} ${height}" role="img" aria-label="workflow-stage-counts">
      <line x1="12" y1="${bottom}" x2="${width - 10}" y2="${bottom}" />
      ${bars}
    </svg>
  `;
}

function setupWizardEnabled(questions) {
  return ENABLE_SETUP_WIZARD && state.runMode === "pipeline" && Array.isArray(questions) && questions.length > 0;
}

function activeSetupWizardStepIndex() {
  const maxStep = SETUP_WIZARD_STEPS.length - 1;
  const currentStep = Math.max(0, Math.min(maxStep, Number(state.setupStepIndex || 0)));
  state.setupStepIndex = currentStep;
  return currentStep;
}

function activeSetupWizardStepId() {
  return SETUP_WIZARD_STEPS[activeSetupWizardStepIndex()]?.id || "input";
}

function questionSetupStepId(questionId) {
  if (questionId === "confirm_run") {
    return "review";
  }
  if (
    questionId === "target_input" ||
    questionId === "target_pdb" ||
    questionId === "target_fasta" ||
    questionId === "rfd3_input_pdb" ||
    questionId === "diffdock_ligand"
  ) {
    return "input";
  }
  if (SETUP_EXPERT_QUESTION_IDS.has(questionId) || SETUP_RFD3_MODE_DETAIL_IDS.has(questionId)) {
    return "expert";
  }
  if (SETUP_WORKFLOW_QUESTION_IDS.has(questionId)) {
    return "workflow";
  }
  if (SETUP_CRITERIA_QUESTION_IDS.has(questionId)) {
    return "criteria";
  }
  return "criteria";
}

function isSetupWizardFinalStep() {
  const lastIndex = SETUP_WIZARD_STEPS.length - 1;
  return Number(state.setupStepIndex || 0) >= lastIndex;
}

function renderSetupWizard(questions) {
  const enabled = setupWizardEnabled(questions);
  if (!el.setupStepper || !el.setupStepMeta || !el.setupStepDots || !el.setupStepPrev || !el.setupStepNext) {
    return questions;
  }
  if (!enabled) {
    state.setupStepIndex = 0;
    el.setupStepper.classList.add("hidden");
    return questions;
  }

  const maxStep = SETUP_WIZARD_STEPS.length - 1;
  const currentStep = activeSetupWizardStepIndex();
  const activeStepId = activeSetupWizardStepId();

  el.setupStepper.classList.remove("hidden");
  const label = t(SETUP_WIZARD_STEPS[currentStep].labelKey);
  el.setupStepMeta.textContent = t("setup.wizard.stepMeta", {
    current: currentStep + 1,
    total: SETUP_WIZARD_STEPS.length,
    label,
  });

  el.setupStepDots.innerHTML = SETUP_WIZARD_STEPS.map((step, index) => {
    const cls = index === currentStep ? "setup-step-dot active" : "setup-step-dot";
    return `<button type="button" class="${cls}" data-step-index="${index}">${escapeHtml(
      t(step.labelKey)
    )}</button>`;
  }).join("");
  Array.from(el.setupStepDots.querySelectorAll("[data-step-index]")).forEach((node) => {
    node.addEventListener("click", () => {
      const nextIndex = Number.parseInt(String(node.getAttribute("data-step-index") || "0"), 10);
      if (!Number.isFinite(nextIndex)) return;
      state.setupStepIndex = Math.max(0, Math.min(maxStep, nextIndex));
      renderQuestions(state.plan?.questions || []);
    });
  });

  el.setupStepPrev.textContent = t("setup.wizard.prev");
  el.setupStepNext.textContent = t("setup.wizard.next");
  el.setupStepPrev.disabled = currentStep <= 0;
  el.setupStepNext.disabled = currentStep >= maxStep;

  return (questions || []).filter((q) => questionSetupStepId(q.id) === activeStepId);
}

