function applyFastLaunchPresetToState(preset) {
  if (!preset || typeof preset !== "object") return;
  const selectedTiers = normalizeSelectedTierValues(
    preset.answers?.selected_tiers ?? preset.routed?.selected_tiers ?? preset.answers?.conservation_tiers,
    FAST_SELECTED_TIER_VALUES
  );
  state.answerMeta = {};
  state.setupLoadedRequestRunId = "";
  state.chainRanges = null;
  resetSetupResiduePicker();
  state.runMode = preset.mode || "pipeline";
  state.plan = {
    ...buildManualPlan("pipeline"),
    source: "fast",
    routed_request: { ...(preset.routed || {}), selected_tiers: selectedTiers },
  };
  state.answers = {
    ...(preset.answers || {}),
    selected_tiers: selectedTiers,
    confirm_run: true,
  };
  delete state.answers.conservation_tiers;
  state.setupStepIndex = 0;
  if (el.promptInput) {
    el.promptInput.value = String(preset.prompt || "").trim();
  }
  updateRunLabel();
  renderQuestions(state.plan.questions || []);
  updateRunEligibility(state.plan.questions || []);
}

const FAST_SELECTED_TIER_VALUES = Object.freeze([0.3, 0.5, 0.7]);

function normalizeSelectedTierValues(values, fallback = FAST_SELECTED_TIER_VALUES) {
  const source = Array.isArray(values) ? values : values === undefined || values === null ? [] : [values];
  const normalized = Array.from(
    new Set(source.map((value) => normalizeConservationTier(value)).filter((value) => value !== null))
  ).sort((left, right) => left - right);
  return normalized.length ? normalized : Array.isArray(fallback) ? [...fallback] : [];
}

function readFastSelectedTiers() {
  const values = Array.from(el.fastSelectedTiers?.querySelectorAll("[data-fast-tier].selected") || []).map((button) =>
    button.getAttribute("data-fast-tier")
  );
  return normalizeSelectedTierValues(values, FAST_SELECTED_TIER_VALUES);
}

function setupRoutedRequest() {
  if (!state.plan || typeof state.plan !== "object") return null;
  if (!state.plan.routed_request || typeof state.plan.routed_request !== "object" || Array.isArray(state.plan.routed_request)) {
    state.plan.routed_request = {};
  }
  return state.plan.routed_request;
}

function mirrorSetupRoutedAnswer(id, value) {
  const routed = setupRoutedRequest();
  if (!routed || !id) return;
  if (value === undefined) {
    delete routed[id];
  } else {
    routed[id] = value;
  }
}

function currentSetupSelectedTiers(question = null) {
  const routedDefault = Array.isArray(state.plan?.routed_request?.selected_tiers)
    ? state.plan.routed_request.selected_tiers
    : [];
  const fallback = Array.isArray(question?.default) ? question.default : FAST_SELECTED_TIER_VALUES;
  const current = normalizeSelectedTierValues(
    Array.isArray(state.answers.selected_tiers) && state.answers.selected_tiers.length
      ? state.answers.selected_tiers
      : Array.isArray(state.answers.conservation_tiers) && state.answers.conservation_tiers.length
        ? state.answers.conservation_tiers
        : routedDefault,
    fallback
  );
  state.answers.selected_tiers = current;
  delete state.answers.conservation_tiers;
  mirrorSetupRoutedAnswer("selected_tiers", [...current]);
  return current;
}

function buildFastLaunchPresetFromUi() {
  return buildFastLaunchPreset({
    target_input: String(el.fastTargetInput?.value || "").trim(),
    prompt: String(el.fastPromptInput?.value || "").trim(),
    selected_tiers: readFastSelectedTiers(),
    total_output_sequences: Number.parseInt(String(el.fastTotalOutputInput?.value || "").trim(), 10),
  });
}

async function loadFastTargetFile(file) {
  if (!file || typeof file.text !== "function") return;
  const text = await file.text();
  if (el.fastTargetInput) {
    el.fastTargetInput.value = String(text || "");
  }
  setMessage(t("fast.message.fileLoaded", { name: file.name || "input" }), "ai");
}

function initFastLauncher() {
  if (fastLauncherInitialized) return;
  el.fastSelectedTiers?.querySelectorAll("[data-fast-tier]").forEach((button) => {
    const selected = button.classList.contains("selected");
    button.setAttribute("aria-pressed", selected ? "true" : "false");
    button.addEventListener("click", () => {
      const isSelected = button.classList.contains("selected");
      const selectedCount = el.fastSelectedTiers?.querySelectorAll("[data-fast-tier].selected").length || 0;
      if (isSelected && selectedCount <= 1) return;
      button.classList.toggle("selected", !isSelected);
      button.setAttribute("aria-pressed", isSelected ? "false" : "true");
    });
  });
  el.fastLoadFileBtn?.addEventListener("click", () => {
    el.fastTargetFile?.click();
  });
  el.fastTargetFile?.addEventListener("change", async (event) => {
    const file = event?.target?.files?.[0];
    if (!file) return;
    await loadFastTargetFile(file);
    event.target.value = "";
  });
  el.fastOpenAdvancedBtn?.addEventListener("click", () => {
    const targetInput = String(el.fastTargetInput?.value || "").trim();
    if (!targetInput) {
      setMessage(t("fast.error.targetRequired"), "ai");
      setActiveTab("fast");
      return;
    }
    const preset = buildFastLaunchPresetFromUi();
    applyFastLaunchPresetToState(preset);
    setActiveTab("advanced");
    setMessage(t("fast.message.reviewReady"), "ai");
  });
  el.fastRunBtn?.addEventListener("click", async () => {
    const targetInput = String(el.fastTargetInput?.value || "").trim();
    if (!targetInput) {
      setMessage(t("fast.error.targetRequired"), "ai");
      setActiveTab("fast");
      return;
    }
    const preset = buildFastLaunchPresetFromUi();
    const answers = {
      ...preset.answers,
      target_input: targetInput,
      run_mode: preset.mode || "pipeline"
    };
    await runPipeline(answers);
  });
  fastLauncherInitialized = true;
}

async function loadEvolutionTargetFile(file) {
  if (!file || typeof file.text !== "function") return;
  const text = await file.text();
  if (el.evolutionTargetInput) {
    el.evolutionTargetInput.value = String(text || "");
  }
  setMessage(t("fast.message.fileLoaded", { name: file.name || "input" }), "ai");
}

function initEvolutionLauncher() {
  if (evolutionLauncherInitialized) return;
  el.evolutionLoadFileBtn?.addEventListener("click", () => {
    el.evolutionTargetFile?.click();
  });
  el.evolutionTargetFile?.addEventListener("change", async (event) => {
    const file = event?.target?.files?.[0];
    if (!file) return;
    await loadEvolutionTargetFile(file);
    event.target.value = "";
  });
    el.evolutionRunBtn?.addEventListener("click", async () => {
    const targetInput = String(el.evolutionTargetInput?.value || "").trim();
    if (!targetInput) {
      setMessage(t("evolution.error.targetRequired"), "ai");
      setActiveTab("evolution");
      return;
    }
    
    const answers = {
      run_mode: "pipeline",
      target_input: targetInput,
      evolution_mode: true,
      evolution_pool_size: Number.parseInt(el.evolutionPoolSizeInput?.value || "1000", 10),
      evolution_initial_samples: Number.parseInt(el.evolutionInitialSamplesInput?.value || "30", 10),
      evolution_oracle_samples: Number.parseInt(el.evolutionOracleSamplesInput?.value || "20", 10),
      af2_plddt_cutoff: Number.parseFloat(el.evolutionAf2PlddtCutoffInput?.value || "85"),
      af2_rmsd_cutoff: Number.parseFloat(el.evolutionAf2RmsdCutoffInput?.value || "2.0"),
      relax_score_per_residue_cutoff: Number.parseFloat(el.evolutionRelaxScoreCutoffInput?.value || "0.0"),
      bioemu_target_rmsd_cutoff: Number.parseFloat(el.evolutionBioemuTargetRmsdCutoffInput?.value || "2.0"),
      bioemu_steering_config_text: el.evolutionBioemuSteeringConfigInput?.value || "",
      rfd3_target_rmsd_cutoff: Number.parseFloat(el.evolutionRfd3TargetRmsdCutoffInput?.value || "2.0"),
      fixed_positions_extra: el.evolutionFixedPositionsExtraInput?.value || "",
      start_from: "msa",
      stop_after: "novelty",
      novelty_enabled: true
    };
    
    await runPipeline(answers);
  });
  evolutionLauncherInitialized = true;
}

function initTabs() {
  if (!tabButtons.length) return;
  if (!tabsInitialized) {
    tabButtons.forEach((btn) => {
      btn.addEventListener("click", () => setActiveTab(btn.dataset.tab));
    });
    tabsInitialized = true;
  }
  initHomeLauncher();
  initHomeContext();
  initEvolutionLauncher();
  initFastLauncher();
  const stored = localStorage.getItem(TAB_KEY);
  setActiveTab(stored || "home");
  void syncHomeProjectRoundContext({ preserveSelection: true });
}

function showLogin() {
  syncLoginMode();
  el.loginGate.classList.remove("hidden");
  if (el.appShell) el.appShell.classList.add("hidden");
  if (el.detachedResiduePickerRoot) el.detachedResiduePickerRoot.classList.add("hidden");
  if (el.chatArea) el.chatArea.classList.add("hidden");
  if (el.adminBtn) el.adminBtn.classList.add("hidden");
  if (el.runpodAdminBtn) el.runpodAdminBtn.classList.add("hidden");
  if (el.settingsPanel) el.settingsPanel.classList.add("hidden");
  if (el.adminPanel) el.adminPanel.classList.add("hidden");
  if (el.helpPanel) el.helpPanel.classList.add("hidden");
}

function showChat() {
  el.loginGate.classList.add("hidden");
  syncLoginMode();
  if (detachedResiduePickerToken) {
    if (el.appShell) el.appShell.classList.add("hidden");
    if (el.detachedResiduePickerRoot) el.detachedResiduePickerRoot.classList.remove("hidden");
    renderDetachedResiduePickerWorkspace();
    return;
  }
  if (el.detachedResiduePickerRoot) el.detachedResiduePickerRoot.classList.add("hidden");
  if (el.appShell) el.appShell.classList.remove("hidden");
  if (el.chatArea) el.chatArea.classList.remove("hidden");
  setUserBadge();
  ensureManualPlan();
  initTabs();
}

function updateAdminUI() {
  const isAdmin = isAdminUser();
  const useOidc = oidcEnabled();
  if (isAdmin) {
    if (el.adminBtn) el.adminBtn.classList.toggle("hidden", useOidc);
    if (el.runpodAdminBtn) el.runpodAdminBtn.classList.remove("hidden");
    if (el.adminRunsToggle) el.adminRunsToggle.classList.remove("hidden");
    if (el.showAllRuns) el.showAllRuns.checked = true;
    if (el.tabBtnCath) el.tabBtnCath.classList.remove("hidden");
    if (el.cathOpsPanel) el.cathOpsPanel.classList.remove("hidden");
    if (activeTabId() === "cath") {
      void refreshCathOps({ force: true });
    }
  } else {
    if (el.adminBtn) el.adminBtn.classList.add("hidden");
    if (el.runpodAdminBtn) el.runpodAdminBtn.classList.add("hidden");
    if (el.adminPanel) el.adminPanel.classList.add("hidden");
    if (el.adminRunsToggle) el.adminRunsToggle.classList.add("hidden");
    if (el.tabBtnCath) el.tabBtnCath.classList.add("hidden");
    if (el.showAllRuns) el.showAllRuns.checked = false;
    if (el.cathOpsPanel) el.cathOpsPanel.classList.add("hidden");
    state.cathOverview = null;
    state.cathJobs = [];
    state.cathSelectedJobId = "";
    state.cathSelectedJobLog = "";
    renderCathSubsetGrid();
    renderCathJobsList();
    renderCathJobLog();
    if (activeTabId() === "cath") {
      setActiveTab("home");
    }
  }
  if (useOidc && el.adminPanel) {
    el.adminPanel.classList.add("hidden");
  }
}

