function updateRunLabel() {
  if (!el.runBtn) return;
  const labels = {
    pipeline: "run.label.pipeline",
    workflow: "run.label.workflow",
    rfd3: "run.label.rfd3",
    bioemu: "run.label.bioemu",
    msa: "run.label.msa",
    design: "run.label.design",
    soluprot: "run.label.soluprot",
    af2: "run.label.af2",
    diffdock: "run.label.diffdock",
  };
  const key = labels[state.runMode];
  el.runBtn.textContent = key ? t(key) : "Run";
}

function setRunMode(mode, { render = true } = {}) {
  const normalized = RUN_MODE_OPTIONS.find((opt) => opt.value === mode)?.value || "pipeline";
  state.runMode = normalized;
  state.setupStepIndex = 0;
  if (normalized === "workflow") {
    state.workflowDesigner = createWorkflowDesignerState();
  }
  if (normalized === "diffdock") {
    state.answers.diffdock_use = "use";
  }
  state.plan = buildManualPlan(normalized);
  updateRunLabel();
  syncSetupRunReuseControls();
  if (render) {
    renderQuestions(state.plan.questions || []);
  }
}

function ensureManualPlan() {
  if (state.plan && Array.isArray(state.plan.questions) && state.plan.questions.length > 0) {
    updateRunLabel();
    renderQuestions(state.plan.questions);
    return;
  }
  setRunMode(state.runMode || "pipeline");
}

function resetPlan({ keepMode = true } = {}) {
  state.answers = {};
  state.answerMeta = {};
  state.setupLoadedRequestRunId = "";
  state.chainRanges = null;
  resetSetupResiduePicker();
  const nextMode = keepMode ? state.runMode : "pipeline";
  setRunMode(nextMode);
}

function renderToggleButtons(container, options, currentValues, onToggle) {
  const group = document.createElement("div");
  group.className = "choice-group";
  options.forEach((opt) => {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "choice-btn";
    const selected = Array.isArray(currentValues) && currentValues.includes(opt.value);
    if (selected) btn.classList.add("selected");
    btn.textContent = labelFor(opt);
    btn.addEventListener("click", () => {
      onToggle(opt.value);
      renderFeedbackControls();
    });
    group.appendChild(btn);
  });
  container.innerHTML = "";
  container.appendChild(group);
}

function renderSingleButtons(container, options, currentValue, onSelect) {
  const group = document.createElement("div");
  group.className = "choice-group";
  options.forEach((opt) => {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "choice-btn";
    if (currentValue === opt.value) btn.classList.add("selected");
    btn.textContent = labelFor(opt);
    btn.addEventListener("click", () => {
      onSelect(opt.value);
      renderFeedbackControls();
    });
    group.appendChild(btn);
  });
  container.innerHTML = "";
  container.appendChild(group);
}

function fillSelect(select, options, { includeEmpty = false } = {}) {
  if (!select) return;
  select.innerHTML = "";
  if (includeEmpty) {
    const opt = document.createElement("option");
    opt.value = "";
    opt.textContent = t("common.none");
    select.appendChild(opt);
  }
  options.forEach((item) => {
    const opt = document.createElement("option");
    opt.value = item.value;
    opt.textContent = labelFor(item);
    select.appendChild(opt);
  });
}

function refillSelect(select, options, { includeEmpty = false } = {}) {
  if (!select) return;
  const current = select.value;
  fillSelect(select, options, { includeEmpty });
  if (current !== undefined) {
    select.value = current;
  }
}

function renderFeedbackControls() {
  if (!el.feedbackRating || !el.feedbackReasons) return;
  renderSingleButtons(
    el.feedbackRating,
    [
      { labelKey: "feedback.rating.good", value: "good" },
      { labelKey: "feedback.rating.bad", value: "bad" },
    ],
    state.feedbackRating,
    (value) => {
      state.feedbackRating = value;
    }
  );

  const reasonsForRating =
    FEEDBACK_REASONS_BY_RATING[state.feedbackRating] || FEEDBACK_REASONS_BY_RATING.bad;
  const allowed = new Set(reasonsForRating.map((item) => item.value));
  if (Array.isArray(state.feedbackReasons)) {
    state.feedbackReasons = state.feedbackReasons.filter((reason) => allowed.has(reason));
  }

  renderToggleButtons(el.feedbackReasons, reasonsForRating, state.feedbackReasons, (value) => {
    const next = new Set(state.feedbackReasons);
    if (next.has(value)) {
      next.delete(value);
    } else {
      next.add(value);
    }
    state.feedbackReasons = Array.from(next);
  });
}

function renderReportReviewControls() {
  if (!el.reportReviewRating || !el.reportReviewReasons) return;
  renderSingleButtons(
    el.reportReviewRating,
    [
      { labelKey: "feedback.rating.good", value: "good" },
      { labelKey: "feedback.rating.bad", value: "bad" },
    ],
    state.reportReviewRating,
    (value) => {
      state.reportReviewRating = value;
    }
  );

  const reasonsForRating =
    REPORT_REVIEW_REASONS_BY_RATING[state.reportReviewRating] || REPORT_REVIEW_REASONS_BY_RATING.bad;
  const allowed = new Set(reasonsForRating.map((item) => item.value));
  if (Array.isArray(state.reportReviewReasons)) {
    state.reportReviewReasons = state.reportReviewReasons.filter((reason) => allowed.has(reason));
  }

  renderToggleButtons(el.reportReviewReasons, reasonsForRating, state.reportReviewReasons, (value) => {
    const next = new Set(state.reportReviewReasons);
    if (next.has(value)) {
      next.delete(value);
    } else {
      next.add(value);
    }
    state.reportReviewReasons = Array.from(next);
  });
}

function refreshArtifactSelects() {
  const options = [
    { labelKey: "common.none", value: "" },
    ...state.artifacts.map((item) => ({ label: displayArtifactPath(item.path), value: item.path })),
  ];
  if (el.feedbackArtifact) {
    fillSelect(el.feedbackArtifact, options);
  }
  if (el.experimentArtifact) {
    fillSelect(el.experimentArtifact, options);
  }
  renderArtifactCompareSelects();
}

function initFeedbackUI() {
  renderFeedbackControls();
  renderReportReviewControls();
  fillSelect(el.feedbackStage, FEEDBACK_STAGES, { includeEmpty: false });
  fillSelect(el.experimentAssay, EXPERIMENT_ASSAYS, { includeEmpty: false });
  fillSelect(el.experimentResult, EXPERIMENT_RESULTS, { includeEmpty: false });
  refreshArtifactSelects();

  if (el.feedbackArtifact && el.feedbackStage) {
    el.feedbackArtifact.addEventListener("change", () => {
      const value = el.feedbackArtifact.value;
      if (value) {
        const stage = stageFromPath(value);
        if (stage && el.feedbackStage.value === "") {
          el.feedbackStage.value = stage;
        }
      }
    });
  }
}

function inferRunModeFromRequestPayload(payload) {
  return inferRequestRunMode(payload);
}

function normalizeTierKeyValue(value) {
  const raw = String(value ?? "").trim();
  if (!raw) return "";
  const asNum = Number(raw);
  if (!Number.isFinite(asNum)) return raw;
  if (Math.abs(asNum) <= 1.0) {
    return String(Math.round(asNum * 100));
  }
  return String(Math.round(asNum));
}

function buildProgressContextFromRequestPayload(payload) {
  if (!payload || typeof payload !== "object") return null;
  const rawTiers = Array.isArray(payload.selected_tiers) && payload.selected_tiers.length
    ? payload.selected_tiers
    : Array.isArray(payload.conservation_tiers)
      ? payload.conservation_tiers
      : [0.3, 0.5, 0.7];
  const tierKeys = Array.from(
    new Set(
      rawTiers
        .map((item) => normalizeTierKeyValue(item))
        .filter((item) => String(item || "").trim())
    )
  );
  const stopAfter = String(payload.stop_after || "")
    .trim()
    .toLowerCase();
  const startFrom = normalizePipelineStage(payload.start_from, "msa") || "msa";
  const noveltyEnabled = Boolean(payload.novelty_enabled) || stopAfter === "novelty";
  return {
    tierKeys,
    noveltyEnabled,
    stopAfter,
    startFrom,
    wtCompare: Boolean(payload.wt_compare),
  };
}

function progressContextForRunId(runId, payload = null) {
  const key = String(runId || "").trim();
  const requestContext = payload ? buildProgressContextFromRequestPayload(payload) : null;
  const workflowPlan = key ? workflowPlanForRunId(key) : null;
  if (!workflowPlan?.nodes?.length) return requestContext;
  const existingContext = state.progressContextByRunId?.[key] || null;
  return buildWorkflowProgressContext({
    nodes: workflowPlan.nodes,
    tierKeys: requestContext?.tierKeys || existingContext?.tierKeys,
    wtCompare:
      requestContext && Object.prototype.hasOwnProperty.call(requestContext, "wtCompare")
        ? requestContext.wtCompare
        : existingContext?.wtCompare,
  });
}

async function ensureRunModeForRunId(runId, status) {
  if (!runId) return "pipeline";
  if (state.workflowPlansByRunId && state.workflowPlansByRunId[runId]) {
    const baseProgressContext = progressContextForRunId(runId);
    if (baseProgressContext) {
      state.progressContextByRunId[runId] = baseProgressContext;
    }
    try {
      const req = await apiCall("pipeline.read_artifact", {
        run_id: runId,
        path: "request.json",
        max_bytes: 2_500_000,
      });
      const text = typeof req?.text === "string" ? req.text : "";
      if (text.trim()) {
        const payload = JSON.parse(text);
        const progressContext = progressContextForRunId(runId, payload);
        if (progressContext) state.progressContextByRunId[runId] = progressContext;
      }
    } catch (_err) {
      // Keep workflow mode even if request.json cannot be loaded.
    }
    state.runModeById[runId] = "workflow";
    return "workflow";
  }
  const mapped = state.runModeById[runId];
  const context = state.progressContextByRunId[runId];
  if (mapped && PROGRESS_PLANS[mapped] && (mapped !== "pipeline" || context)) return mapped;

  try {
    const req = await apiCall("pipeline.read_artifact", {
      run_id: runId,
      path: "request.json",
      max_bytes: 2_500_000,
    });
    const text = typeof req?.text === "string" ? req.text : "";
    if (text.trim()) {
      const payload = JSON.parse(text);
      if (payload && typeof payload === "object" && Object.prototype.hasOwnProperty.call(payload, "af2_provider")) {
        const shouldRefreshAf2Labels = setAf2ProviderForRun(runId, payload.af2_provider);
        if (shouldRefreshAf2Labels) {
          refreshAf2ProviderLabels({ rerenderQuestions: true });
        }
      }
      const progressContext = progressContextForRunId(runId, payload);
      if (progressContext) {
        state.progressContextByRunId[runId] = progressContext;
      }
      const inferred = inferRunModeFromRequestPayload(payload);
      if (inferred && PROGRESS_PLANS[inferred]) {
        state.runModeById[runId] = inferred;
        return inferred;
      }
    }
  } catch (err) {
    // Ignore mode inference failures and keep fallback below.
  }

  const rawStage = String(status?.stage || "")
    .trim()
    .toLowerCase();
  if (rawStage === "af2") {
    state.runModeById[runId] = "af2";
    return "af2";
  }
  if (rawStage === "diffdock") {
    state.runModeById[runId] = "diffdock";
    return "diffdock";
  }

  state.runModeById[runId] = "pipeline";
  return "pipeline";
}

function progressModeForStatus(status) {
  const embedded = String(status?._mode || "")
    .trim()
    .toLowerCase();
  if (embedded && PROGRESS_PLANS[embedded]) return embedded;

  const runId = state.currentRunId || "";
  const mapped = runId ? state.runModeById[runId] : "";
  if (mapped && PROGRESS_PLANS[mapped]) return mapped;

  const rawStage = String(status?.stage || "").trim().toLowerCase();
  if (rawStage === "af2") return "af2";
  if (rawStage === "diffdock") return "diffdock";
  return "pipeline";
}

function mapStageToProgressStep(stage, mode, status) {
  const raw = String(stage || "").trim().toLowerCase();
  if (!raw) return null;
  if (raw === "done") return "done";

  if (raw === "evolution") {
    const detail = String(status?.detail || "").toLowerCase();
    if (detail.includes("initializing")) return "evo_init";
    if (detail.includes("stage 1")) return "evo_pool";
    if (detail.includes("stage 2")) return "evo_sampling";
    if (detail.includes("stage 3a")) return "evo_train_eval";
    if (detail.includes("stage 3b")) return "evo_surrogate";
    if (detail.includes("stage 3c")) return "evo_topk_eval";
    return "evo_init";
  }

  if (raw === "mmseqs_msa") return "msa";
  if (raw === "conservation") return "conservation";
  if (raw === "wt_baseline" || raw === "wt_soluprot" || raw === "wt_af2" || raw.startsWith("wt_relax")) return "wt";
  if (raw === "rfd3") return mode === "rfd3" ? "rfd3" : "backbone";
  if (raw === "bioemu") return mode === "bioemu" ? "bioemu" : "backbone";
  if (raw === "af2_target" || raw === "pdb_preprocess" || raw === "query_pdb_check") return "backbone";
  if (raw === "diffdock") return mode === "diffdock" ? "diffdock" : "masking";
  if (raw === "ligand_mask" || raw === "surface_mask" || raw === "mask_consensus") return "masking";
  if (raw === "design" || raw.startsWith("proteinmpnn_")) return "design";
  if (raw === "soluprot" || raw.startsWith("soluprot_")) return "soluprot";
  if (raw === "af2" || raw.startsWith("af2_")) return "af2";
  if (raw === "relax" || raw.startsWith("relax_")) return "relax";
  if (raw === "novelty" || raw.startsWith("novelty_")) return "novelty";
  return null;
}

function parseTierStage(stage) {
  const raw = String(stage || "").trim().toLowerCase();
  const match = raw.match(/^(proteinmpnn|soluprot|af2|relax|novelty)_([0-9]+(?:\.[0-9]+)?)$/);
  if (!match) return null;
  const base = match[1];
  const tierKey = normalizeTierKeyValue(match[2]);
  if (!tierKey) return null;
  if (base === "proteinmpnn") return { step: "design", tierKey };
  if (base === "relax") return { step: "relax", tierKey };
  return { step: base, tierKey };
}

function computePipelineTierAwareProgress(status, runState, offset, cached) {
  const runId = String(state.currentRunId || "");
  if (!runId) return null;
  const ctx = state.progressContextByRunId[runId];
  if (!ctx || !Array.isArray(ctx.tierKeys) || ctx.tierKeys.length === 0) return null;

  const units = progressUnitsForRequest({
    mode: "pipeline",
    startFrom: ctx.startFrom || "msa",
    stopAfter: ctx.stopAfter || "",
    noveltyEnabled: ctx.noveltyEnabled,
    wtCompare: ctx.wtCompare,
    tierKeys: ctx.tierKeys,
  });
  if (!Array.isArray(units) || !units.length) return null;

  const currentStep = mapStageToProgressStep(status?.stage, "pipeline");
  const parsedTierStage = parseTierStage(status?.stage);
  if (!currentStep) return null;
  if (String(currentStep) === "done") {
    return {
      percent: 100,
      label: progressStepLabel("done"),
    };
  }

  const tierSteps = new Set(["design", "soluprot", "af2", "relax", "novelty"]);
  const tierKeys = Array.from(new Set(ctx.tierKeys.map((item) => normalizeTierKeyValue(item)).filter(Boolean)));
  let unitIndex = -1;
  let label = progressStepLabel(currentStep);
  let tierIndex = -1;

  if (!tierSteps.has(currentStep)) {
    unitIndex = units.findIndex((unit) => unit?.step === currentStep && !unit?.tierKey);
  } else {
    let targetTierKey = parsedTierStage?.tierKey || "";
    if (!targetTierKey && cached && Number.isFinite(cached.tierIndex)) {
      const cachedIndex = Math.max(0, Math.min(tierKeys.length - 1, Number(cached.tierIndex)));
      targetTierKey = tierKeys[cachedIndex] || "";
    }
    if (!targetTierKey) {
      targetTierKey = units.find((unit) => unit?.step === currentStep && unit?.tierKey)?.tierKey || tierKeys[0] || "";
    }
    unitIndex = units.findIndex((unit) => unit?.step === currentStep && String(unit?.tierKey || "") === targetTierKey);
    tierIndex = tierKeys.indexOf(targetTierKey);
    if (tierIndex < 0) tierIndex = 0;
    label = `${formatConservationTierLabel(targetTierKey, state.lang || "en")} · ${progressStepLabel(currentStep)}`;
  }
  if (unitIndex < 0) return null;

  let percent = ((unitIndex + offset) / Math.max(1, units.length)) * 100;
  if (TERMINAL_RUN_STATES.has(runState) && runState !== "completed") {
    percent = Math.max(percent, ((unitIndex + 0.75) / Math.max(1, units.length)) * 100);
  }
  percent = Math.max(1, Math.min(99, percent));
  return {
    percent,
    label,
    tierIndex: tierIndex >= 0 ? tierIndex : null,
  };
}

function progressStepLabel(step) {
  if (step === "backbone") return t("monitor.progress.backbone");
  if (step === "wt") return t("monitor.progress.wt");
  if (step === "masking") return t("monitor.progress.masking");
  if (step === "done") return t("monitor.progress.done");
  if (step === "evo_init") return t("monitor.progress.evo_init");
  if (step === "evo_pool") return t("monitor.progress.evo_pool");
  if (step === "evo_sampling") return t("monitor.progress.evo_sampling");
  if (step === "evo_train_eval") return t("monitor.progress.evo_train_eval");
  if (step === "evo_surrogate") return t("monitor.progress.evo_surrogate");
  if (step === "evo_topk_eval") return t("monitor.progress.evo_topk_eval");
  return formatStageLabel(step);
}

function formatStatusStage(stage) {
  const raw = String(stage || "").trim();
  if (!raw) return "-";
  const lower = raw.toLowerCase();

  const tierMatch = lower.match(/^(proteinmpnn|soluprot|af2|relax|novelty)_([0-9]+(?:\.[0-9]+)?)$/);
  if (tierMatch) {
    const key = tierMatch[1];
    const tierLabel = formatConservationTierLabel(tierMatch[2], state.lang || "en");
    if (key === "proteinmpnn") {
      return `${formatStageLabel("design")} · ${tierLabel}`;
    }
    if (key === "soluprot") {
      return `${formatStageLabel("soluprot")} · ${tierLabel}`;
    }
    if (key === "af2") {
      return `${formatStageLabel("af2")} · ${tierLabel}`;
    }
    if (key === "relax") {
      return `${formatStageLabel("relax")} · ${tierLabel}`;
    }
    if (key === "novelty") {
      return `${formatStageLabel("novelty")} · ${tierLabel}`;
    }
  }

  const normalized = formatStageLabel(lower);
  if (normalized && normalized !== lower) return normalized;
  return raw;
}

function parseStatusTimestamp(value) {
  const raw = String(value || "").trim();
  if (!raw) return NaN;
  const normalized = raw.includes("T") ? raw : raw.replace(" ", "T");
  const withZone = /[zZ]|[+\-]\d{2}:\d{2}$/.test(normalized) ? normalized : `${normalized}Z`;
  return Date.parse(withZone);
}

function formatEtaMs(ms) {
  if (!Number.isFinite(ms) || ms <= 0) return "0m";
  const totalSec = Math.max(1, Math.round(ms / 1000));
  if (totalSec < 60) return "<1m";
  const min = Math.floor(totalSec / 60);
  const hr = Math.floor(min / 60);
  if (hr > 0) return `${hr}h ${min % 60}m`;
  return `${min}m`;
}

function estimateRunEta(status, percentRounded) {
  const runId = String(state.currentRunId || "");
  const runState = String(status?.state || "").trim().toLowerCase();
  if (!runId) return "-";
  if (runState === "completed" || runState === "done") return "0m";
  if (runState === "failed" || runState === "cancelled" || runState === "error" || runState === "timed_out") {
    return "failed";
  }
  const updatedTs = parseStatusTimestamp(status?.updated_at);
  if (!Number.isFinite(updatedTs) || !Number.isFinite(percentRounded) || percentRounded <= 0 || percentRounded >= 100) {
    return "-";
  }
  const timing = (state.timingByRunId[runId] = state.timingByRunId[runId] || {});
  if (!Number.isFinite(timing.startedAt)) {
    timing.startedAt = updatedTs;
  }
  const elapsed = Math.max(0, updatedTs - timing.startedAt);
  if (elapsed < 5000) return "-";
  const remaining = (elapsed * (100 - percentRounded)) / Math.max(1, percentRounded);
  return formatEtaMs(remaining);
}

function setStateBadge(node, runState) {
  if (!node) return;
  node.classList.add("state-badge");
  node.dataset.state = String(runState || "").toLowerCase();
}

function updateMonitorErrorCards(status) {
  const runState = String(status?.state || "").toLowerCase();
  const detailText = String(status?.detail || "").trim();
  const shouldShow = runState === "failed" || runState === "error" || /^error[:\s]/i.test(detailText);
  const summary = detailText ? detailText.split("\n")[0].slice(0, 220) : "Error";

  const cards = [
    {
      root: el.runErrorDetails,
      summary: el.runErrorSummary,
      raw: el.runErrorRaw,
    },
    {
      root: el.setupErrorDetails,
      summary: el.setupErrorSummary,
      raw: el.setupErrorRaw,
    },
  ];

  cards.forEach((card) => {
    if (!card.root) return;
    card.root.classList.toggle("hidden", !shouldShow);
    if (shouldShow) {
      if (card.summary) card.summary.textContent = summary || "Error";
      if (card.raw) card.raw.textContent = detailText || summary;
    } else {
      if (card.raw) card.raw.textContent = "";
    }
  });
}

function renderRunProgress(status) {
  if (!el.runProgressFill || !el.runProgressPercent || !el.runProgressLabel || !el.runProgressStages) return;

  const mode = progressModeForStatus(status);
  const runId = String(state.currentRunId || "");
  let steps = PROGRESS_PLANS[mode] || PROGRESS_PLANS.pipeline;
  const ctx = state.progressContextByRunId[runId];
  if ((mode === "pipeline" || mode === "workflow") && ctx) {
    steps = progressStepsForRequest({
      mode,
      startFrom: ctx?.startFrom || "msa",
      stopAfter: ctx?.stopAfter || "",
      noveltyEnabled: ctx?.noveltyEnabled,
      wtCompare: ctx?.wtCompare,
    });
  }
  const runState = String(status?.state || "").trim().toLowerCase();
  const currentStep = mapStageToProgressStep(status?.stage, mode, status);

  const cached = runId ? state.progressByRunId[runId] : null;
  let stepIndex = currentStep ? steps.indexOf(currentStep) : -1;
  if (stepIndex < 0 && cached && cached.mode === mode && Number.isFinite(cached.index)) {
    stepIndex = cached.index;
  }
  if (stepIndex < 0) stepIndex = 0;

  let percent = 0;
  let labelOverride = "";
  let tierIndexForCache = null;
  if (currentStep === "done") {
    percent = 100;
    stepIndex = steps.length - 1;
  } else {
    const base = Math.max(0, stepIndex);
    const offset =
      runState === "running" ? 0.45 : runState === "completed" ? 1.0 : runState === "failed" ? 0.2 : 0.1;
    const tierAware =
      mode === "pipeline" || mode === "workflow"
        ? computePipelineTierAwareProgress(status, runState, offset, cached)
        : null;
    if (tierAware && Number.isFinite(tierAware.percent)) {
      percent = Number(tierAware.percent);
      labelOverride = String(tierAware.label || "");
      if (Number.isFinite(tierAware.tierIndex) && Number(tierAware.tierIndex) >= 0) {
        tierIndexForCache = Number(tierAware.tierIndex);
      }
    } else {
      percent = ((base + offset) / Math.max(1, steps.length)) * 100;
      if (TERMINAL_RUN_STATES.has(runState) && runState !== "completed") {
        percent = Math.max(percent, ((base + 0.75) / Math.max(1, steps.length)) * 100);
      }
      percent = Math.max(1, Math.min(99, percent));
    }
  }

  const rounded = Math.max(0, Math.min(100, Math.round(percent)));
  el.runProgressFill.style.width = `${rounded}%`;
  el.runProgressPercent.textContent = `${rounded}%`;
  el.runProgressLabel.textContent = labelOverride || progressStepLabel(steps[Math.min(stepIndex, steps.length - 1)]);

  el.runProgressStages.innerHTML = steps
    .map((step, index) => {
      let cls = "";
      if (index < stepIndex) cls = "done";
      else if (index === stepIndex) cls = runState === "failed" || runState === "error" ? "failed" : "current";
      return `<span class="progress-stage ${cls}">${escapeHtml(progressStepLabel(step))}</span>`;
    })
    .join("");

  if (runId) {
    const payload = { mode, index: stepIndex, percent: rounded };
    if (tierIndexForCache !== null) payload.tierIndex = tierIndexForCache;
    state.progressByRunId[runId] = payload;
  }
  return rounded;
}

function resetRunProgress() {
  if (el.runDetailValue) el.runDetailValue.textContent = "-";
  if (el.runProgressFill) el.runProgressFill.style.width = "0%";
  if (el.runProgressPercent) el.runProgressPercent.textContent = "0%";
  if (el.runProgressLabel) el.runProgressLabel.textContent = "-";
  if (el.runProgressStages) el.runProgressStages.innerHTML = "";
}

function armRunStatusGracePeriod(runId, durationMs = 4000) {
  const key = String(runId || "").trim();
  if (!key) return;
  state.statusGraceUntilByRunId[key] = Date.now() + Math.max(0, Number(durationMs) || 0);
}

function updateRunInfo(status) {
  if (!status) return;
  const statusRunId = String(status.run_id || state.currentRunId || "").trim();
  const incomingRunState = String(status.state || "").toLowerCase();
  const graceUntil = Number(state.statusGraceUntilByRunId?.[statusRunId] || 0);
  if (statusRunId && incomingRunState && isTerminalRunState(incomingRunState) && graceUntil > Date.now()) {
    return;
  }
  if (statusRunId && (!incomingRunState || !isTerminalRunState(incomingRunState) || graceUntil <= Date.now())) {
    delete state.statusGraceUntilByRunId[statusRunId];
  }
  const rawStage = String(status.stage || "").trim();
  const stageDisplay = formatStatusStage(rawStage);
  el.runStageValue.textContent = stageDisplay || "-";
  el.runStateValue.textContent = status.state || "-";
  el.runUpdatedValue.textContent = status.updated_at || "-";
  if (el.runDetailValue) {
    const detailText = status.detail !== undefined && status.detail !== null ? String(status.detail) : "";
    el.runDetailValue.textContent = detailText.trim() ? detailText : "-";
  }
  const runState = incomingRunState;
  setStateBadge(el.runStateValue, runState);

  state.lastRunStatus = status;
  const percent = renderRunProgress(status);
  const etaText = estimateRunEta(status, percent);

  if (el.setupContextStageValue) el.setupContextStageValue.textContent = stageDisplay || "-";
  if (el.setupContextStateValue) {
    el.setupContextStateValue.textContent = status.state || "-";
    setStateBadge(el.setupContextStateValue, runState);
  }
  if (el.analyzeContextStageValue) el.analyzeContextStageValue.textContent = stageDisplay || "-";
  if (el.analyzeContextStateValue) {
    el.analyzeContextStateValue.textContent = status.state || "-";
    setStateBadge(el.analyzeContextStateValue, runState);
  }

  if (el.setupRunIdValue) el.setupRunIdValue.textContent = state.currentRunId || "-";
  if (el.setupRunStageValue) el.setupRunStageValue.textContent = stageDisplay || "-";
  if (el.setupRunStateValue) {
    el.setupRunStateValue.textContent = status.state || "-";
    setStateBadge(el.setupRunStateValue, runState);
  }
  if (el.setupRunUpdatedValue) el.setupRunUpdatedValue.textContent = status.updated_at || "-";
  if (el.setupRunEtaValue) el.setupRunEtaValue.textContent = etaText;

  updateMonitorErrorCards(status);
  state.currentRunState = String(status.state || "").toLowerCase();
  const completed = state.currentRunState === "completed" || state.currentRunState === "done";
  if (statusRunId && completed && state.autoAnalyzePendingByRunId[statusRunId]) {
    const workflowPlan = workflowPlanForRunId(statusRunId);
    const workflowStop = normalizePipelineStage(state.progressContextByRunId?.[statusRunId]?.stopAfter, "");
    const checkpointTarget = normalizePipelineStage(workflowPlan?.nextCheckpointStage || "", "");
    const waitingCheckpoint =
      workflowPlan &&
      workflowPlan.checkpointEnabled &&
      checkpointTarget &&
      workflowStop === checkpointTarget &&
      normalizePipelineStage(workflowPlan.finalStopAfter, "") !== workflowStop;
    state.autoAnalyzePendingByRunId[statusRunId] = false;
    if (!waitingCheckpoint) {
      setActiveTab("analyze");
    }
  }
  if (statusRunId && (state.currentRunState === "failed" || state.currentRunState === "cancelled")) {
    state.autoAnalyzePendingByRunId[statusRunId] = false;
  }
  if (statusRunId && isTerminalRunState(state.currentRunState)) {
    delete state.statusGraceUntilByRunId[statusRunId];
  }
  updateInlineStatus(status);
  updateRunEligibility(state.plan?.questions || []);
  updateMonitorActionButtons();
  renderWorkflowReviewPanel(status);
  renderCopilotContext();
  syncWorkflowStudioSessionFromStatus(status);
  renderHomeContextSelectors();
}

function updateInlineStatus(status, runId = state.currentRunId) {
  if (!el.runInlineStatus) return;
  if (!runId) {
    el.runInlineStatus.textContent = t("setup.runStatus.empty");
    el.runInlineStatus.dataset.state = "";
    return;
  }
  const stage = status?.stage || "-";
  const stateText = status?.state || "-";
  const updated = status?.updated_at || "-";
  el.runInlineStatus.textContent = t("setup.runStatus.line", {
    id: runId,
    stage,
    state: stateText,
    updated,
  });
  el.runInlineStatus.dataset.state = String(stateText || "").toLowerCase();
}

function setCurrentRunId(runId) {
  state.currentRunId = runId;
  state.currentRunState = "";
  state.lastRunStatus = null;
  state.lastStatusKey = "";
  state.feedbackCount = 0;
  state.experimentCount = 0;
  state.artifacts = [];
  state.artifactMetaByPath = {};
  state.artifactComparison = null;
  state.artifactComparisonRunId = "";
  state.monitorNeedsReport = false;
  state.monitorCompleteness = null;
  state.analyzeArtifactPath = "";
  state.studioArtifactPath = "";
  state.artifactCompareLeftPath = "";
  state.artifactCompareRightPath = "";
  state.runCompareResult = null;
  state.hitListResult = null;
  state.hitListRows = [];
  if (runId && !state.timingByRunId[runId]) state.timingByRunId[runId] = {};
  el.runIdValue.textContent = runId || "-";
  el.runIdValue.title = runId || "";
  el.runStageValue.textContent = "-";
  el.runStateValue.textContent = "-";
  el.runUpdatedValue.textContent = "-";
  if (el.setupContextStageValue) el.setupContextStageValue.textContent = "-";
  if (el.setupContextStateValue) {
    el.setupContextStateValue.textContent = "-";
    setStateBadge(el.setupContextStateValue, "");
  }
  if (el.analyzeContextStageValue) el.analyzeContextStageValue.textContent = "-";
  if (el.analyzeContextStateValue) {
    el.analyzeContextStateValue.textContent = "-";
    setStateBadge(el.analyzeContextStateValue, "");
  }
  const studioSessionId = workflowStudioSessionIdForRun(runId);
  if (studioSessionId) {
    setCurrentWorkflowStudioSessionId(studioSessionId);
  }
  if (el.setupRunIdValue) el.setupRunIdValue.textContent = runId || "-";
  if (el.setupRunStageValue) el.setupRunStageValue.textContent = "-";
  if (el.setupRunStateValue) {
    el.setupRunStateValue.textContent = "-";
    setStateBadge(el.setupRunStateValue, "");
  }
  if (el.setupRunUpdatedValue) el.setupRunUpdatedValue.textContent = "-";
  if (el.setupRunEtaValue) el.setupRunEtaValue.textContent = "-";
  updateRunLabel();
  updateMonitorErrorCards(null);
  updateAnalyzeSummary();
  resetRunProgress();
  updateInlineStatus(null, runId);
  updateRunEligibility(state.plan?.questions || []);
  updateMonitorActionButtons();
  renderAllArtifactViews(state.artifacts);
  refreshArtifactSelects();
  renderArtifactComparisonSummary(null);
  renderMonitorCompleteness(null, null);
  renderRunCompareSummary(null);
  renderHitList();
  populateRunCompareBaselineOptions();
  updateHitCutoffLabel();
  setHitWeightInputValues();
  setFilePreviewPlaceholder("monitor");
  setFilePreviewPlaceholder("studio");
  setFilePreviewPlaceholder("analyze", "analyze.files.placeholder");
  setComparePreviewPlaceholder("artifacts.preview.placeholder");
  updateMonitorReportActions();
  renderWorkflowReviewPanel(null);
  renderCopilotContext();
  if (state.runs) renderRuns(state.runs);
  refreshAgentPanel();
  refreshFeedback();
  refreshExperiments();
  loadReport();
  renderWorkflowStudio();
  renderHomeContextSelectors();
}

function ensureAutoPoll() {
  if (!el.autoPoll.checked) {
    stopPolling();
    return;
  }
  if (state.pollTimer) return;
  state.pollTimer = window.setInterval(() => {
    if (activeTabId() === "cath" && isAdminUser()) {
      void refreshCathOps();
      return;
    }
    void pollCurrentRun({ includeArtifacts: "auto" });
  }, 5000);
  if (activeTabId() === "cath" && isAdminUser()) {
    void refreshCathOps({ force: true });
    return;
  }
  void pollCurrentRun({ includeArtifacts: "auto" });
}

function stopPolling() {
  if (state.pollTimer) {
    window.clearInterval(state.pollTimer);
    state.pollTimer = null;
  }
}

function artifactRefreshStatusKeyForRun(runId = state.currentRunId) {
  const key = String(runId || "").trim();
  if (!key) return "";
  const status =
    state.lastRunStatus &&
    typeof state.lastRunStatus === "object" &&
    String(state.lastRunStatus.run_id || "").trim() === key
      ? state.lastRunStatus
      : null;
  const stage = String(status?.stage || "-").trim() || "-";
  const runState = String(status?.state || state.currentRunState || "-").trim() || "-";
  const updated = String(status?.updated_at || "-").trim() || "-";
  return `${key}|${stage}|${runState}|${updated}`;
}

function markArtifactsRefreshed(runId = state.currentRunId) {
  const key = String(runId || "").trim();
  if (!key) return;
  state.artifactRefreshAtByRunId[key] = Date.now();
  state.artifactRefreshStatusKeyByRunId[key] = artifactRefreshStatusKeyForRun(key);
}

function isTerminalRunState(stateText = currentRunStateText()) {
  const normalized = String(stateText || "")
    .trim()
    .toLowerCase();
  return ["completed", "done", "failed", "error", "cancelled", "canceled", "stopped"].includes(normalized);
}

function shouldAutoRefreshArtifacts(runId = state.currentRunId) {
  const key = String(runId || "").trim();
  if (!key) return false;
  if (!["monitor", "studio"].includes(activeTabId())) return false;
  if (!Array.isArray(state.artifacts) || state.artifacts.length === 0) return true;
  const currentStatusKey = artifactRefreshStatusKeyForRun(key);
  const previousStatusKey = String(state.artifactRefreshStatusKeyByRunId?.[key] || "");
  if (currentStatusKey && currentStatusKey !== previousStatusKey) return true;
  const lastRefreshAt = Number(state.artifactRefreshAtByRunId?.[key] || 0);
  if (!isTerminalRunState() && Date.now() - lastRefreshAt >= 15000) return true;
  return false;
}

async function pollCurrentRun({ includeArtifacts = "auto" } = {}) {
  const studioRunId =
    activeTabId() === "studio" ? String(workflowStudioActionRunId(workflowStudioSessionForId()) || "").trim() : "";
  const runId = String(studioRunId || state.currentRunId || "").trim();
  if (!runId) {
    if (activeTabId() === "cath" && isAdminUser()) {
      await refreshCathOps();
    }
    return;
  }
  if (studioRunId && studioRunId !== String(state.currentRunId || "").trim()) {
    setCurrentRunId(studioRunId);
  }
  if (state.pollCyclePromise) return state.pollCyclePromise;
  state.pollCyclePromise = (async () => {
    await pollStatus(runId);
    await refreshAgentPanel();
    if (activeTabId() === "cath" && isAdminUser()) {
      await refreshCathOps();
    }
    const shouldRefresh =
      includeArtifacts === true || (includeArtifacts === "auto" && shouldAutoRefreshArtifacts(runId));
    if (shouldRefresh) {
      await refreshArtifacts({ runId });
    }
  })()
    .catch((err) => {
      setMessage(t("status.error", { error: err.message }), "ai");
    })
    .finally(() => {
      state.pollCyclePromise = null;
    });
  return state.pollCyclePromise;
}

function authHeaders() {
  return state.token ? { Authorization: `Bearer ${state.token}` } : {};
}

async function apiCall(name, args) {
  const res = await fetch(`${state.apiBase}/tools/call`, {
    method: "POST",
    credentials: "include",
    headers: { "Content-Type": "application/json", ...authHeaders() },
    body: JSON.stringify({ name, arguments: args || {} }),
  });
  const payload = await res.json().catch(() => null);
  if (!res.ok) {
    const msg = payload && typeof payload.error === "string" ? payload.error : `HTTP ${res.status}`;
    throw new Error(msg);
  }
  if (!payload || typeof payload !== "object") {
    throw new Error(t("error.api"));
  }
  if (!payload.ok) {
    throw new Error(payload.error || t("error.api"));
  }
  return payload.result;
}

async function authLogin() {
  if (state.authBootstrapPending) {
    el.loginError.textContent = t("login.loading");
    return;
  }
  if (oidcEnabled()) {
    el.loginError.textContent = "";
    try {
      await startOidcLogin();
    } catch (err) {
      el.loginError.textContent = err.message || t("auth.ssoUnavailable");
    }
    return;
  }
  const username = el.loginUsername.value.trim();
  const password = el.loginPassword.value.trim();
  el.loginError.textContent = "";
  if (!username || !password) {
    el.loginError.textContent = t("auth.required");
    return;
  }
  try {
    const res = await fetch(`${state.apiBase}/auth/login`, {
      method: "POST",
      credentials: "include",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ username, password }),
    });
    if (!res.ok) {
      throw new Error(`HTTP ${res.status}`);
    }
    const payload = await res.json();
    if (!payload.ok) {
      throw new Error(payload.error || t("auth.loginFailed"));
    }
    state.token = payload.token;
    state.user = payload.user;
    saveToken(payload.token);
    saveUser(payload.user);
    reloadWorkflowStudioSessionsForUser(state.user);
    showChat();
    updateAdminUI();
    refreshRuns();
  } catch (err) {
    el.loginError.textContent = err.message;
  }
}

async function loadSession() {
  if (!state.token && !oidcEnabled()) {
    showLogin();
    return;
  }
  let failureStatus = 0;
  let failureMessage = "";
  try {
    const res = await fetch(`${state.apiBase}/auth/me`, {
      credentials: "include",
      headers: { ...authHeaders() },
    });
    const payload = await res.json().catch(() => null);
    if (!res.ok) {
      failureStatus = res.status;
      failureMessage = payload && typeof payload.error === "string" ? payload.error : `HTTP ${res.status}`;
      throw new Error(failureMessage);
    }
    if (!payload.ok) {
      failureMessage = payload.error || t("auth.sessionInvalid");
      throw new Error(failureMessage);
    }
    state.user = payload.user;
    saveUser(payload.user);
    reloadWorkflowStudioSessionsForUser(state.user);
    showChat();
    updateAdminUI();
    refreshRuns();
  } catch (err) {
    if (shouldClearStoredSession({ status: failureStatus, error: failureMessage || err?.message })) {
      clearSession();
      showLogin();
      return;
    }
    const cachedUser = state.user || loadUser();
    if (cachedUser) {
      state.user = cachedUser;
      reloadWorkflowStudioSessionsForUser(state.user);
      showChat();
      updateAdminUI();
      return;
    }
    showLogin();
  }
}

function resetInputs() {
  resetPlan({ keepMode: true });
  setMessage(t("run.reset"), "ai");
}

const PROTEIN_RESNAMES = new Set([
  "ALA",
  "ARG",
  "ASN",
  "ASP",
  "CYS",
  "GLN",
  "GLU",
  "GLY",
  "HIS",
  "ILE",
  "LEU",
  "LYS",
  "MET",
  "PHE",
  "PRO",
  "SER",
  "THR",
  "TRP",
  "TYR",
  "VAL",
  "ASX",
  "GLX",
  "XLE",
  "UNK",
  "MSE",
  "SEC",
  "PYL",
  "SEP",
  "TPO",
  "PTR",
  "HYP",
  "HID",
  "HIE",
  "HIP",
  "CYX",
]);

function normalizeChainId(chainId) {
  const clean = String(chainId || "").trim();
  return clean || "_";
}

function denormalizeChainId(chainId) {
  return String(chainId || "") === "_" ? "" : String(chainId || "");
}

function isProteinAtomLine(line) {
  if (!line.startsWith("ATOM") && !line.startsWith("HETATM")) return false;
  const resname = line.slice(17, 20).trim().toUpperCase();
  return PROTEIN_RESNAMES.has(resname);
}

function parsePdbChainRanges(pdbText) {
  const ranges = {};
  const lines = String(pdbText || "").split(/\r?\n/);
  for (const line of lines) {
    if (!isProteinAtomLine(line)) continue;
    const chainId = normalizeChainId(line[21] || "");
    const resSeq = parseInt(line.slice(22, 26).trim(), 10);
    if (!Number.isFinite(resSeq)) continue;
    const entry = ranges[chainId] || { min: resSeq, max: resSeq, minPos: null, maxPos: null };
    entry.min = Math.min(entry.min, resSeq);
    entry.max = Math.max(entry.max, resSeq);
    if (resSeq > 0) {
      entry.minPos = entry.minPos === null ? resSeq : Math.min(entry.minPos, resSeq);
      entry.maxPos = entry.maxPos === null ? resSeq : Math.max(entry.maxPos, resSeq);
    }
    ranges[chainId] = entry;
  }
  const normalized = {};
  Object.entries(ranges).forEach(([chainId, entry]) => {
    if (entry.minPos !== null && entry.maxPos !== null) {
      normalized[chainId] = { min: entry.minPos, max: entry.maxPos };
    }
  });
  return Object.keys(normalized).length ? normalized : null;
}

function parsePdbResidueOrderByChain(pdbText) {
  const orderByChain = {};
  const seenByChain = {};
  const lines = String(pdbText || "").split(/\r?\n/);
  for (const line of lines) {
    if (!isProteinAtomLine(line)) continue;
    const chainId = normalizeChainId(line[21] || "");
    const resSeq = parseInt(line.slice(22, 26).trim(), 10);
    if (!Number.isFinite(resSeq) || resSeq <= 0) continue;
    if (!seenByChain[chainId]) seenByChain[chainId] = new Set();
    const seen = seenByChain[chainId];
    if (seen.has(resSeq)) continue;
    seen.add(resSeq);
    if (!orderByChain[chainId]) orderByChain[chainId] = [];
    orderByChain[chainId].push(resSeq);
  }
  return orderByChain;
}

function normalizeResidueSelectionMap(raw) {
  const out = {};
  if (!raw || typeof raw !== "object") return out;
  Object.entries(raw).forEach(([chain, values]) => {
    const nums = (Array.isArray(values) ? values : [values])
      .map((v) => Number.parseInt(v, 10))
      .filter((v) => Number.isFinite(v) && v > 0);
    if (nums.length) {
      out[normalizeChainId(chain)] = Array.from(new Set(nums)).sort((a, b) => a - b);
    }
  });
  return out;
}

function countSelectedResidues(selectionMap) {
  return Object.values(selectionMap || {}).reduce(
    (acc, list) => acc + (Array.isArray(list) ? list.length : 0),
    0
  );
}

function selectionSummaryText(selectionMap) {
  const parts = [];
  Object.entries(selectionMap || {})
    .sort(([a], [b]) => a.localeCompare(b))
    .forEach(([chain, values]) => {
      if (!Array.isArray(values) || values.length === 0) return;
      const preview = values.slice(0, 8).join(",");
      const suffix = values.length > 8 ? `,+${values.length - 8}` : "";
      parts.push(`${chain}:${preview}${suffix}`);
    });
  return parts.join("; ");
}

function filterSelectionByResidueOrder(selectionMap, orderByChain) {
  const normalized = normalizeResidueSelectionMap(selectionMap);
  const filtered = {};
  Object.entries(normalized).forEach(([chain, values]) => {
    const allowed = new Set((orderByChain && orderByChain[chain]) || []);
    const kept = values.filter((v) => allowed.has(v));
    if (kept.length) filtered[chain] = kept;
  });
  return filtered;
}

function residuePickerPresetSelectionsById(presetDescriptors = residuePickerPresetDescriptors()) {
  const out = {};
  (Array.isArray(presetDescriptors) ? presetDescriptors : []).forEach((preset) => {
    const presetId = String(preset?.id || "").trim();
    if (!presetId) return;
    out[presetId] = normalizeResidueSelectionMap(preset.selection || {});
  });
  return out;
}

function normalizeResiduePickerActivePresetIds(activePresetIds = [], presetSelectionsById = {}) {
  const seen = new Set();
  const out = [];
  (Array.isArray(activePresetIds) ? activePresetIds : []).forEach((presetId) => {
    const normalizedId = String(presetId || "").trim();
    if (!normalizedId || seen.has(normalizedId)) return;
    if (!countSelectedResidues(presetSelectionsById?.[normalizedId] || {})) return;
    seen.add(normalizedId);
    out.push(normalizedId);
  });
  return out;
}

function syncSetupResiduePickerSelectionState({
  selectionFallback = {},
  manualSelection,
  excludedSelection,
  activePresetIds,
  presetSelectionsById = residuePickerPresetSelectionsById(),
  allowFallback = false,
} = {}) {
  const residueOrderByChain = state.setupResiduePicker.residueOrderByChain || {};
  const fallbackSelection = filterSelectionByResidueOrder(selectionFallback, residueOrderByChain);
  const rawManualSelection = manualSelection ?? state.setupResiduePicker.manualSelection;
  const rawExcludedSelection = excludedSelection ?? state.setupResiduePicker.excludedSelection;
  const rawActivePresetIds = activePresetIds ?? state.setupResiduePicker.activePresetIds;
  const resolved = resolveResiduePickerSelectionState({
    selectionFallback: fallbackSelection,
    manualSelection: filterSelectionByResidueOrder(rawManualSelection, residueOrderByChain),
    excludedSelection: filterSelectionByResidueOrder(rawExcludedSelection, residueOrderByChain),
    activePresetIds: normalizeResiduePickerActivePresetIds(rawActivePresetIds, presetSelectionsById),
    presetSelectionsById,
    allowFallback,
  });
  const nextSelection = filterSelectionByResidueOrder(resolved.selection, residueOrderByChain);
  state.setupResiduePicker.manualSelection = resolved.manualSelection;
  state.setupResiduePicker.excludedSelection = resolved.excludedSelection;
  state.setupResiduePicker.activePresetIds = resolved.activePresetIds;
  state.setupResiduePicker.selection = nextSelection;
  return nextSelection;
}

function resetSetupResiduePicker() {
  state.setupResiduePicker = createSetupResiduePickerState();
}

function clearSetupResiduePickerSelectionState() {
  state.setupResiduePicker = clearResiduePickerSelectionState(state.setupResiduePicker);
  return state.setupResiduePicker;
}

function recomputeSetupResiduePickerSpatialPresets(pdbText = state.setupResiduePicker.pdbText || "") {
  const text = String(pdbText || "").trim();
  if (!text) {
    state.setupResiduePicker.spatialPresets = { surface: {}, core: {}, interface: {}, residues: [] };
    return state.setupResiduePicker.spatialPresets;
  }
  const surfaceAreaCutoff = normalizeSurfaceAreaCutoff(
    state.setupResiduePicker.surfaceAreaCutoff,
    DEFAULT_SURFACE_AREA_CUTOFF
  );
  state.setupResiduePicker.surfaceAreaCutoff = surfaceAreaCutoff;
  state.setupResiduePicker.spatialPresets = deriveResidueSpatialPresets(text, {
    surfaceAreaCutoff,
  });
  return state.setupResiduePicker.spatialPresets;
}

function setSetupResiduePickerStructure(pdbText, { sourceLabel = "", sourceKey = "" } = {}) {
  const text = String(pdbText || "").trim();
  if (!text) return false;
  const residueOrderByChain = parsePdbResidueOrderByChain(text);
  if (!Object.keys(residueOrderByChain).length) return false;
  const sequenceByChain = parsePdbSequenceByChain(text);
  const sequencePaletteByChain = {};
  Object.entries(sequenceByChain).forEach(([chain, sequence]) => {
    sequencePaletteByChain[chain] = sequenceResiduePalette(sequence);
  });
  const previousCutoff = normalizeSurfaceAreaCutoff(
    state.setupResiduePicker.surfaceAreaCutoff,
    DEFAULT_SURFACE_AREA_CUTOFF
  );
  const spatialPresets = deriveResidueSpatialPresets(text, {
    surfaceAreaCutoff: previousCutoff,
  });
  const nextSelection = filterSelectionByResidueOrder(state.setupResiduePicker.selection, residueOrderByChain);
  const nextManualSelection = filterSelectionByResidueOrder(state.setupResiduePicker.manualSelection, residueOrderByChain);
  const nextExcludedSelection = filterSelectionByResidueOrder(state.setupResiduePicker.excludedSelection, residueOrderByChain);
  state.setupResiduePicker = {
    pdbText: text,
    sourceLabel,
    sourceKey,
    selection: nextSelection,
    manualSelection: nextManualSelection,
    excludedSelection: nextExcludedSelection,
    activePresetIds: Array.isArray(state.setupResiduePicker.activePresetIds)
      ? state.setupResiduePicker.activePresetIds.map((presetId) => String(presetId || "").trim()).filter(Boolean)
      : [],
    residueOrderByChain,
    sequenceByChain,
    sequencePaletteByChain,
    spatialPresets,
    surfaceAreaCutoff: previousCutoff,
    structureColorMode: state.setupResiduePicker.structureColorMode || "secondary",
    conservationPreview:
      String(sourceKey || "").startsWith("run_target:") ? state.setupResiduePicker.conservationPreview || null : null,
    notice: "",
    runningAf2: false,
  };
  syncSetupResiduePickerSelectionState({ selectionFallback: nextSelection, allowFallback: true });
  return true;
}

function normalizeFixedPositionsValue(raw) {
  if (typeof raw === "string") {
    const out = parseFixedPositionsExtra(raw);
    if (out.error) return {};
    return normalizeFixedPositionsExtraDraft(out.value);
  }
  return normalizeFixedPositionsExtraDraft(raw);
}

function mergeFixedPositionsMap(baseMap, addMap) {
  return mergeFixedPositionsExtraDraft(baseMap, addMap);
}

function setupWorkflowNodesForRfd3() {
  return state.runMode === "workflow" ? normalizeWorkflowNodesForState(state.workflowDesigner?.nodes) : [];
}

function setupRfd3InputOverrideVisible() {
  return state.answerMeta?.rfd3_input_pdb?.overrideVisible === true;
}

function setSetupRfd3InputOverrideVisible(visible) {
  const nextVisible = visible === true;
  const meta = { ...(state.answerMeta.rfd3_input_pdb || {}) };
  if (nextVisible) {
    meta.overrideVisible = true;
  } else {
    delete meta.overrideVisible;
  }
  if (Object.keys(meta).length) {
    state.answerMeta.rfd3_input_pdb = meta;
  } else {
    delete state.answerMeta.rfd3_input_pdb;
  }
}

function setupRunUsesRfd3Stage(answers = state.answers) {
  return runUsesRfd3Stage({
    mode: state.runMode,
    answers,
    nodes: setupWorkflowNodesForRfd3(),
  });
}

function setupRunEnablesRfd3Stage(answers = state.answers) {
  return rfd3EnabledForContext({
    mode: state.runMode,
    answers,
    nodes: setupWorkflowNodesForRfd3(),
  });
}

function shouldShowSetupRfd3InputField(answers = state.answers) {
  return shouldShowRfd3InputPdbField({
    mode: state.runMode,
    answers,
    nodes: setupWorkflowNodesForRfd3(),
    overrideVisible: setupRfd3InputOverrideVisible(),
  });
}

const RFD3_MODE_OPTIONS = Object.freeze([
  { labelKey: "choice.rfd3Mode.localDiversify", value: "local_diversify" },
  { labelKey: "choice.rfd3Mode.legacyContig", value: "legacy_contig" },
  { labelKey: "choice.rfd3Mode.binder", value: "binder" },
  { labelKey: "choice.rfd3Mode.enzyme", value: "enzyme" },
  { labelKey: "choice.rfd3Mode.advanced", value: "advanced" },
]);

const SETUP_RFD3_MODE_DETAIL_IDS = new Set([
  "rfd3_mode",
  "rfd3_partial_t",
  "rfd3_contig",
  "rfd3_hotspots",
  "rfd3_infer_ori_strategy",
  "rfd3_is_non_loopy",
  "rfd3_unindex",
  "rfd3_length",
  "rfd3_select_fixed_atoms",
  "rfd3_inputs_text",
]);

function rfd3ModeI18nSuffix(mode) {
  const normalized = normalizeRfd3Mode(mode);
  if (normalized === "local_diversify") return "localDiversify";
  if (normalized === "legacy_contig") return "legacyContig";
  return normalized || "localDiversify";
}

function rfd3ModeDescriptionKey(mode) {
  return `question.rfd3Mode.mode.${rfd3ModeI18nSuffix(mode)}`;
}

function setupRfd3ModeDetailIds(mode) {
  return Array.from(SETUP_RFD3_MODE_DETAIL_IDS);
}

function rfd3ModeUsesContig(mode) {
  const normalized = normalizeRfd3Mode(mode);
  return (
    normalized === "legacy_contig" ||
    normalized === "binder" ||
    normalized === "local_diversify" ||
    normalized === "enzyme"
  );
}

function rfd3ModeUsesBinderFields(mode) {
  return normalizeRfd3Mode(mode) === "binder";
}

function rfd3ModeUsesEnzymeFields(mode) {
  return normalizeRfd3Mode(mode) === "enzyme";
}

function rfd3ModeUsesUnindexFields(mode) {
  const normalized = normalizeRfd3Mode(mode);
  return normalized === "enzyme" || normalized === "local_diversify";
}

function rfd3ModeUsesFixedAtomFields(mode) {
  const normalized = normalizeRfd3Mode(mode);
  return normalized === "enzyme" || normalized === "local_diversify";
}

function rfd3ModeUsesPartialT(mode) {
  return ["local_diversify", "legacy_contig", "binder", "enzyme"].includes(normalizeRfd3Mode(mode));
}

function rfd3ModeUsesAdvancedInputs(mode) {
  return normalizeRfd3Mode(mode) === "advanced";
}

function effectiveSetupRfd3Mode(answers = state.answers) {
  const merged = {
    ...(answers || {}),
    rfd3_input_pdb:
      effectiveRfd3InputPdb({
        mode: state.runMode,
        answers,
        nodes: setupWorkflowNodesForRfd3(),
      }) || answers?.rfd3_input_pdb,
  };
  return effectiveRfd3Mode(merged) || "local_diversify";
}

function questionVisibleForCurrentState(question, normalizedQuestions = []) {
  const id = String(question?.id || "").trim();
  if (!id) return false;

  const answers = state.answers || {};
  const mode = state.runMode || "pipeline";
  const setupNodes = setupWorkflowNodesForRfd3();
  const rfd3InScope =
    runUsesRfd3Stage({
      mode,
      answers,
      nodes: setupNodes,
    }) || shouldShowSetupRfd3InputField(answers);
  const rfd3Enabled =
    rfd3EnabledForContext({
      mode,
      answers,
      nodes: setupNodes,
    }) || shouldShowSetupRfd3InputField(answers);
  const bioemuRelevant =
    mode === "pipeline" ||
    mode === "workflow" ||
    mode === "bioemu" ||
    mode === "design" ||
    mode === "soluprot" ||
    answers.bioemu_use === true ||
    answers.stop_after === "bioemu";
  if (
    id === "evolution_pool_size" ||
    id === "evolution_initial_samples" ||
    id === "evolution_oracle_samples" ||
    id === "evolution_rounds" ||
    id === "evolution_samples_per_round"
  ) {
    return answers.evolution_mode === true;
  }
  if (id === "rfd3_use") {
    return rfd3InScope && mode !== "rfd3";
  }
  if (id === "rfd3_input_pdb") {
    return rfd3Enabled && shouldShowSetupRfd3InputField(answers);
  }
  if (id === "backbone_filter_use_dssp") {
    return rfd3Enabled || bioemuRelevant;
  }
  if (id === "rfd3_max_return_designs") {
    return rfd3Enabled;
  }
  if (id === "rfd3_target_rmsd_cutoff") {
    return rfd3Enabled;
  }
  if (id === "rfd3_contig") {
    return rfd3Enabled;
  }
  if (id === "rfd3_hotspots" || id === "rfd3_infer_ori_strategy" || id === "rfd3_is_non_loopy") {
    return rfd3Enabled;
  }
  if (id === "rfd3_unindex" || id === "rfd3_length" || id === "rfd3_select_fixed_atoms") {
    return rfd3Enabled;
  }
  if (id === "rfd3_partial_t") {
    return rfd3Enabled;
  }
  if (id === "rfd3_inputs_text") {
    return rfd3Enabled;
  }
  if (
    id === "bioemu_filter_samples" ||
    id === "bioemu_steering_config_text" ||
    id === "bioemu_num_samples" ||
    id === "bioemu_max_return_structures" ||
    id === "bioemu_target_rmsd_cutoff"
  ) {
    return bioemuRelevant;
  }
  return true;
}

function workflowStudioRfd3InputOverrideVisible(session) {
  return session?.ui_state?.rfd3_input_override_visible === true;
}

function setWorkflowStudioRfd3InputOverrideVisible(sessionId, visible) {
  const current = workflowStudioSessionForId(sessionId);
  if (!current) return;
  if (!current.ui_state || typeof current.ui_state !== "object" || Array.isArray(current.ui_state)) {
    current.ui_state = {};
  }
  if (visible === true) {
    current.ui_state.rfd3_input_override_visible = true;
  } else {
    delete current.ui_state.rfd3_input_override_visible;
  }
  current.updated_at = new Date().toISOString();
  upsertWorkflowStudioSession(current);
}

function selectedResiduesToQueryPositions(selectionMap, residueOrderByChain) {
  const out = {};
  Object.entries(normalizeResidueSelectionMap(selectionMap)).forEach(([chain, values]) => {
    const order = Array.isArray(residueOrderByChain?.[chain]) ? residueOrderByChain[chain] : [];
    if (!order.length) return;
    const orderIndex = new Map(order.map((resi, idx) => [resi, idx + 1]));
    const mapped = values
      .map((resi) => orderIndex.get(resi))
      .filter((idx) => Number.isFinite(idx) && idx > 0);
    if (mapped.length) {
      out[chain] = Array.from(new Set(mapped)).sort((a, b) => a - b);
    }
  });
  return out;
}

function getTargetInputPdbTextFromAnswers(answers = state.answers) {
  return targetInputPdbText(answers);
}

function getTargetInputFastaTextFromAnswers(answers = state.answers) {
  const explicit = String(answers?.target_fasta || "").trim();
  if (explicit) return explicit;
  const text = String(answers?.target_input || "").trim();
  if (!text) return "";
  return detectTargetKey(text) === "target_fasta" ? text : "";
}

function getRfd3InputPdbTextFromAnswers(answers = state.answers) {
  return explicitRfd3InputPdbText(answers);
}

function getEffectiveRfd3InputPdbTextFromAnswers(
  answers = state.answers,
  { mode = state.runMode, nodes = setupWorkflowNodesForRfd3() } = {}
) {
  return effectiveRfd3InputPdb({
    mode,
    answers,
    nodes,
  });
}

function getTargetInputPdbText() {
  return getTargetInputPdbTextFromAnswers(state.answers);
}

function getTargetInputFastaText() {
  return getTargetInputFastaTextFromAnswers(state.answers);
}

function getRfd3InputPdbText() {
  return getRfd3InputPdbTextFromAnswers(state.answers);
}

function applyTargetInputTextToState(text, { fileName = "" } = {}) {
  const trimmed = String(text || "").trim();
  state.answers.target_input = trimmed;
  state.answers.target_fasta = "";
  state.answers.target_pdb = "";
  state.answerMeta = state.answerMeta && typeof state.answerMeta === "object" ? state.answerMeta : {};
  state.answerMeta.target_pdb = {};
  let resolvedKey = "";
  if (trimmed) {
    resolvedKey = detectTargetKey(trimmed) || "target_pdb";
    state.answers[resolvedKey] = trimmed;
    if (resolvedKey === "target_pdb" && fileName) {
      state.answerMeta.target_pdb = { fileName: String(fileName || "").trim() };
    }
  }
  const studioSession = workflowStudioSessionForId(state.currentWorkflowStudioSessionId);
  if (studioSession) {
    studioSession.base_answers = studioSession.base_answers || {};
    studioSession.base_answers.target_input = trimmed;
    studioSession.base_answers.target_fasta = "";
    studioSession.base_answers.target_pdb = "";
    if (trimmed && resolvedKey) {
      studioSession.base_answers[resolvedKey] = trimmed;
    }
  }
}

function buildWorkflowDesignerCard({
  onLaunch = null,
  rerender = null,
  secondaryAction = null,
  extraClass = "",
  allowTargetInputEdit = false,
} = {}) {
  const stageChoices = PIPELINE_STAGE_ORDER.map((stage) => ({
    stage,
    label:
      stage === "novelty"
        ? t("stop.full")
        : stage === "af2"
          ? t("stage.af2")
          : t(`stage.${stage}`),
    desc: t(`setup.workflow.stageDesc.${stage}`),
  }));
  const stageChoiceMap = new Map(stageChoices.map((item) => [item.stage, item]));
  const stageLabelFor = (stage) => stageChoiceMap.get(stage)?.label || formatStageLabel(stage);
  const stageDescFor = (stage) => stageChoiceMap.get(stage)?.desc || t("setup.workflow.stageGuideHint");
  const rerenderFn = typeof rerender === "function" ? rerender : () => {};
  const showTargetInputEditor = Boolean(allowTargetInputEdit);
  const applyNodeSet = (nextSet) => {
    const ordered = PIPELINE_STAGE_ORDER.filter((stage) => nextSet.has(stage));
    if (!ordered.length) return;
    state.workflowDesigner.nodes = ordered;
    const normalizedCheckpoints = normalizeWorkflowCheckpointList(state.workflowDesigner.checkpointStages, ordered);
    state.workflowDesigner.checkpointStages = normalizedCheckpoints;
    if (!normalizedCheckpoints.length) {
      state.workflowDesigner.checkpointEnabled = false;
    }
    state.workflowDesigner.flowPulse = Number(state.workflowDesigner.flowPulse || 0) + 1;
    rerenderFn();
  };

  const card = document.createElement("div");
  card.className = `question-card workflow-designer ${extraClass}`.trim();

  const title = document.createElement("div");
  title.className = "question-title";
  title.textContent = t("setup.workflow.title");

  const help = document.createElement("div");
  help.className = "question-help";
  help.textContent = t("setup.workflow.help");

  const layout = document.createElement("div");
  layout.className = "workflow-designer-layout";

  const mainCol = document.createElement("div");
  mainCol.className = "workflow-designer-main";

  const sideCol = document.createElement("div");
  sideCol.className = "workflow-designer-side";

  const hasTargetInputValue = () =>
    Boolean(
      String(state.answers.target_input || "").trim() ||
        String(getTargetInputPdbText() || "").trim() ||
        String(getTargetInputFastaText() || "").trim()
    );

  if (showTargetInputEditor) {
    const targetInputBlock = document.createElement("section");
    targetInputBlock.className = "workflow-block workflow-target-input-block";
    const targetInputTitle = document.createElement("div");
    targetInputTitle.className = "workflow-section-label";
    targetInputTitle.textContent = t("question.targetInput.label");
    const targetInputHelp = document.createElement("div");
    targetInputHelp.className = "workflow-block-help";
    targetInputHelp.textContent = t("question.targetInput.help");
    const workflowDesignerTargetInput = document.createElement("textarea");
    workflowDesignerTargetInput.className = "workflow-target-input";
    workflowDesignerTargetInput.rows = 8;
    workflowDesignerTargetInput.placeholder = t("fast.input.placeholder");
    workflowDesignerTargetInput.value = String(
      state.answers.target_input || getTargetInputPdbText() || getTargetInputFastaText() || ""
    );
    const targetInputActions = document.createElement("div");
    targetInputActions.className = "workflow-designer-actions";
    const targetInputLoadBtn = document.createElement("button");
    targetInputLoadBtn.type = "button";
    targetInputLoadBtn.className = "ghost";
    targetInputLoadBtn.textContent = t("fast.action.loadFile");
    const targetInputFile = document.createElement("input");
    targetInputFile.type = "file";
    targetInputFile.accept = ".pdb,.ent,.fa,.fasta,.txt,.seq";
    targetInputFile.className = "hidden";
    targetInputActions.appendChild(targetInputLoadBtn);
    targetInputActions.appendChild(targetInputFile);
    targetInputBlock.appendChild(targetInputTitle);
    targetInputBlock.appendChild(targetInputHelp);
    targetInputBlock.appendChild(workflowDesignerTargetInput);
    targetInputBlock.appendChild(targetInputActions);
    mainCol.appendChild(targetInputBlock);
  }

  const guideBlock = document.createElement("section");
  guideBlock.className = "workflow-block";
  const guideTitle = document.createElement("div");
  guideTitle.className = "workflow-section-label";
  guideTitle.textContent = t("setup.workflow.stageGuide");
  const guideHint = document.createElement("div");
  guideHint.className = "workflow-block-help";
  guideHint.textContent = t("setup.workflow.stageGuideHint");
  const guideLabel = document.createElement("div");
  guideLabel.className = "workflow-stage-guide-label";
  const guideDesc = document.createElement("div");
  guideDesc.className = "workflow-stage-guide-desc";
  guideBlock.appendChild(guideTitle);
  guideBlock.appendChild(guideHint);
  guideBlock.appendChild(guideLabel);
  guideBlock.appendChild(guideDesc);

  const updateGuide = (stage) => {
    const item = stageChoiceMap.get(stage) || stageChoices[0] || null;
    if (!item) {
      guideLabel.textContent = t("setup.workflow.stageGuideHint");
      guideDesc.textContent = "";
      return;
    }
    guideLabel.textContent = `${t("setup.workflow.stageGuideLabel")}: ${item.label}`;
    guideDesc.textContent = stageDescFor(item.stage);
  };

  const paletteBlock = document.createElement("section");
  paletteBlock.className = "workflow-block";
  const paletteTitle = document.createElement("div");
  paletteTitle.className = "workflow-section-label";
  paletteTitle.textContent = t("setup.workflow.palette");
  const paletteHelp = document.createElement("div");
  paletteHelp.className = "workflow-block-help";
  paletteHelp.textContent = t("setup.workflow.paletteHelp");
  paletteBlock.appendChild(paletteTitle);
  paletteBlock.appendChild(paletteHelp);

  const palette = document.createElement("div");
  palette.className = "choice-group workflow-palette";
  const selected = new Set(normalizeWorkflowNodesForState(state.workflowDesigner.nodes));
  stageChoices.forEach((item) => {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "choice-btn workflow-palette-btn";
    if (selected.has(item.stage)) btn.classList.add("selected");
    btn.textContent = item.label;
    btn.title = stageDescFor(item.stage);
    btn.addEventListener("mouseenter", () => updateGuide(item.stage));
    btn.addEventListener("focus", () => updateGuide(item.stage));
    btn.addEventListener("click", () => {
      const nextSet = new Set(selected);
      if (nextSet.has(item.stage)) {
        nextSet.delete(item.stage);
      } else {
        nextSet.add(item.stage);
      }
      applyNodeSet(nextSet);
    });
    palette.appendChild(btn);
  });
  paletteBlock.appendChild(palette);

  const canvasBlock = document.createElement("section");
  canvasBlock.className = "workflow-block";
  const canvasTitle = document.createElement("div");
  canvasTitle.className = "workflow-section-label";
  canvasTitle.textContent = t("setup.workflow.canvas");
  const canvasHelp = document.createElement("div");
  canvasHelp.className = "workflow-block-help";
  canvasHelp.textContent = t("setup.workflow.canvasHelp");
  canvasBlock.appendChild(canvasTitle);
  canvasBlock.appendChild(canvasHelp);

  const canvas = document.createElement("div");
  canvas.className = "workflow-canvas";
  const nodes = normalizeWorkflowNodesForState(state.workflowDesigner.nodes);
  if (!nodes.length) {
    canvas.innerHTML = `<div class="placeholder">${escapeHtml(t("setup.workflow.empty"))}</div>`;
  } else {
    nodes.forEach((stage, idx) => {
      const node = document.createElement("div");
      node.className = "workflow-node";
      node.style.animationDelay = `${Math.min(idx, 8) * 60}ms`;
      node.dataset.stage = stage;
      const isFinal = idx === nodes.length - 1;
      if (isFinal) node.classList.add("final-node");
      const stageLabel = stageLabelFor(stage);
      node.title = stageDescFor(stage);
      node.innerHTML = `
        <span class="workflow-node-title">${escapeHtml(stageLabel)}</span>
        <span class="workflow-node-badges">
          ${isFinal ? `<span class="workflow-node-badge final">${escapeHtml(t("setup.workflow.badge.final"))}</span>` : ""}
        </span>
      `;
      node.addEventListener("mouseenter", () => updateGuide(stage));
      const removeBtn = document.createElement("button");
      removeBtn.type = "button";
      removeBtn.className = "workflow-node-remove";
      removeBtn.textContent = "x";
      removeBtn.title = t("setup.workflow.removeNode");
      removeBtn.addEventListener("click", (event) => {
        event.stopPropagation();
        const nextSet = new Set(nodes);
        nextSet.delete(stage);
        applyNodeSet(nextSet);
      });
      node.appendChild(removeBtn);
      canvas.appendChild(node);
      if (idx < nodes.length - 1) {
        const edge = document.createElement("span");
        edge.className = "workflow-edge";
        edge.textContent = "->";
        canvas.appendChild(edge);
      }
    });
  }
  canvasBlock.appendChild(canvas);

  const hint = document.createElement("div");
  hint.className = "workflow-block-help";
  hint.textContent = t("setup.workflow.nodeHint");
  const orderHint = document.createElement("div");
  orderHint.className = "workflow-block-help";
  orderHint.textContent = t("setup.workflow.orderLocked");
  canvasBlock.appendChild(hint);
  canvasBlock.appendChild(orderHint);

  const controlsBlock = document.createElement("section");
  controlsBlock.className = "workflow-block";
  const controlsTitle = document.createElement("div");
  controlsTitle.className = "workflow-section-label";
  controlsTitle.textContent = t("setup.workflow.controls");
  controlsBlock.appendChild(controlsTitle);
  const controlsHint = document.createElement("div");
  controlsHint.className = "workflow-block-help";
  controlsHint.textContent = t("setup.workflow.controlsHint");
  controlsBlock.appendChild(controlsHint);

  const launchTitle = document.createElement("div");
  launchTitle.className = "workflow-section-label";
  launchTitle.textContent = t("setup.workflow.launchTitle");
  const launchHint = document.createElement("div");
  launchHint.className = "workflow-block-help";
  launchHint.textContent = t("setup.workflow.launchHint");
  const launchActions = document.createElement("div");
  launchActions.className = "workflow-designer-actions";
  const launchBtn = document.createElement("button");
  launchBtn.id = "workflowDesignerLaunchBtn";
  launchBtn.type = "button";
  launchBtn.className = "primary";
  launchBtn.textContent = t("setup.workflow.launchAction");
  const syncWorkflowDesignerLaunchEligibility = () => {
    launchBtn.disabled = !nodes.length || !hasTargetInputValue() || Boolean(state.runSubmitting);
  };
  syncWorkflowDesignerLaunchEligibility();
  launchBtn.addEventListener("click", async () => {
    if (launchBtn.disabled || typeof onLaunch !== "function") return;
    await onLaunch();
  });
  if (showTargetInputEditor) {
    const workflowDesignerTargetInput = mainCol.querySelector(".workflow-target-input");
    const targetInputFile = mainCol.querySelector('input[type="file"].hidden');
    const targetInputLoadBtn = mainCol.querySelector(".workflow-target-input-block .ghost");
    if (workflowDesignerTargetInput instanceof HTMLTextAreaElement) {
      workflowDesignerTargetInput.addEventListener("input", () => {
        applyTargetInputTextToState(workflowDesignerTargetInput.value);
        syncWorkflowDesignerLaunchEligibility();
      });
    }
    if (targetInputLoadBtn instanceof HTMLButtonElement && targetInputFile instanceof HTMLInputElement) {
      targetInputLoadBtn.addEventListener("click", () => {
        targetInputFile.click();
      });
      targetInputFile.addEventListener("change", async (event) => {
        const file = event?.target?.files?.[0];
        if (!file || typeof file.text !== "function") return;
        const text = await file.text();
        if (workflowDesignerTargetInput instanceof HTMLTextAreaElement) {
          workflowDesignerTargetInput.value = String(text || "");
        }
        applyTargetInputTextToState(text, { fileName: file.name || "input" });
        syncWorkflowDesignerLaunchEligibility();
        setMessage(t("fast.message.fileLoaded", { name: file.name || "input" }), "ai");
        event.target.value = "";
      });
    }
  }
  launchActions.appendChild(launchBtn);
  if (secondaryAction && typeof secondaryAction.onClick === "function") {
    const secondaryBtn = document.createElement("button");
    secondaryBtn.type = "button";
    secondaryBtn.className = "ghost";
    secondaryBtn.textContent = secondaryAction.label || t("common.close");
    secondaryBtn.addEventListener("click", () => secondaryAction.onClick());
    launchActions.appendChild(secondaryBtn);
  }
  controlsBlock.appendChild(launchTitle);
  controlsBlock.appendChild(launchHint);
  controlsBlock.appendChild(launchActions);

  const summaryBlock = document.createElement("section");
  summaryBlock.className = "workflow-block";
  const summaryTitle = document.createElement("div");
  summaryTitle.className = "workflow-section-label";
  summaryTitle.textContent = t("setup.workflow.summaryTitle");
  const summary = document.createElement("div");
  summary.className = "question-summary";
  summary.textContent = t("setup.workflow.summaryStudio", {
    stages: nodes.map((stage) => formatStageLabel(stage)).join(" -> "),
  });
  const checkpointSummary = document.createElement("div");
  checkpointSummary.className = "question-summary";
  checkpointSummary.textContent = t("setup.workflow.summaryStudioHint");
  const af2RelaxHint = document.createElement("div");
  af2RelaxHint.className = "workflow-block-help";
  af2RelaxHint.textContent = t("setup.workflow.af2RelaxHint");
  summaryBlock.appendChild(summaryTitle);
  summaryBlock.appendChild(summary);
  summaryBlock.appendChild(checkpointSummary);
  if (nodes.includes("af2")) {
    summaryBlock.appendChild(af2RelaxHint);
  }

  mainCol.appendChild(paletteBlock);
  mainCol.appendChild(canvasBlock);
  sideCol.appendChild(guideBlock);
  sideCol.appendChild(controlsBlock);
  sideCol.appendChild(summaryBlock);

  layout.appendChild(mainCol);
  layout.appendChild(sideCol);

  card.appendChild(title);
  card.appendChild(help);
  card.appendChild(layout);
  updateGuide(nodes[0] || stageChoices[0]?.stage || "");
  return card;
}

async function loadResiduePickerConservationPreview(runId = "") {
  const key = String(runId || "").trim();
  if (!key) {
    state.setupResiduePicker.conservationPreview = null;
    return null;
  }
  try {
    const result = await apiCall("pipeline.read_artifact", {
      run_id: key,
      path: "conservation.json",
      max_bytes: 500000,
    });
    const payload = JSON.parse(String(result?.text || "{}"));
    const fixed = payload?.fixed_positions_by_tier && typeof payload.fixed_positions_by_tier === "object"
      ? payload.fixed_positions_by_tier
      : {};
    const tiers = {};
    Object.entries(fixed).forEach(([tier, values]) => {
      if (!Array.isArray(values)) return;
      const numeric = values
        .map((value) => Number.parseInt(value, 10))
        .filter((value) => Number.isFinite(value) && value > 0);
      const tierNum = Number(tier);
      const tierKey = Number.isFinite(tierNum)
        ? String(tierNum > 1 ? Math.round(tierNum) : Math.round(tierNum * 100))
        : String(tier || "");
      if (numeric.length && tierKey) tiers[tierKey] = numeric;
    });
    state.setupResiduePicker.conservationPreview = { tiers };
  } catch (_err) {
    state.setupResiduePicker.conservationPreview = null;
  }
  return state.setupResiduePicker.conservationPreview;
}

async function predictResiduePickerTargetStructure({ fastaText = "", af2Provider = "colabfold" } = {}) {
  const normalizedFasta = String(fastaText || "").trim();
  if (!normalizedFasta) {
    throw new Error(t("setup.residuePicker.runAf2NeedsFasta"));
  }
  const prefix = state.user?.run_prefix || buildUserPrefix({ name: state.user?.username || "user" });
  const runId = createRunId(`${prefix}_picker_af2`);
  const result = await apiCall("pipeline.af2_predict", {
    run_id: runId,
    target_fasta: normalizedFasta,
    af2_provider: normalizeAf2Provider(af2Provider || "colabfold"),
  });
  const outRunId = String(result?.run_id || runId);
  const candidates = [];
  const summaryAf2 = result?.summary?.af2;
  if (summaryAf2 && typeof summaryAf2 === "object") {
    Object.keys(summaryAf2).forEach((seqId) => {
      const clean = String(seqId || "").trim();
      if (!clean) return;
      candidates.push(`af2/${clean}/ranked_0.pdb`);
    });
  }
  try {
    const listed = await apiCall("pipeline.list_artifacts", {
      run_id: outRunId,
      max_depth: 5,
      limit: 300,
    });
    const listedPaths = Array.isArray(listed?.artifacts)
      ? listed.artifacts
          .map((item) => String(item?.path || ""))
          .filter((path) => /\/ranked_0\.pdb$/i.test(path))
          .sort()
      : [];
    listedPaths.forEach((path) => candidates.push(path));
  } catch {
    // best-effort candidate discovery
  }
  candidates.push("af2/target/ranked_0.pdb");
  candidates.push("af2/sequence/ranked_0.pdb");

  const tried = new Set();
  let selectedPath = "";
  let selectedPdb = "";
  for (const path of candidates) {
    const normalizedPath = String(path || "").trim();
    if (!normalizedPath || tried.has(normalizedPath)) continue;
    tried.add(normalizedPath);
    try {
      const artifact = await apiCall("pipeline.read_artifact", {
        run_id: outRunId,
        path: normalizedPath,
        max_bytes: 2_000_000,
      });
      const text = String(artifact?.text || "").trim();
      if (!text) continue;
      selectedPath = normalizedPath;
      selectedPdb = text;
      break;
    } catch {
      continue;
    }
  }

  if (!selectedPdb) {
    throw new Error(t("setup.residuePicker.runAf2NoResult"));
  }

  const sourceLabel = `${outRunId}:${selectedPath}`;
  const loaded = setSetupResiduePickerStructure(selectedPdb, {
    sourceLabel,
    sourceKey: `af2_picker:${outRunId}`,
  });
  await refreshRuns();
  return { outRunId, selectedPath, selectedPdb, sourceLabel, loaded };
}

function residuePickerPresetSelectionForTier(tierKey) {
  const preview = state.setupResiduePicker.conservationPreview;
  const tiers = preview && typeof preview.tiers === "object" ? preview.tiers : null;
  const chainIds = Object.keys(state.setupResiduePicker.residueOrderByChain || {});
  if (!tiers || !Array.isArray(tiers[tierKey]) || chainIds.length !== 1) return {};
  const chainId = chainIds[0];
  const order = Array.isArray(state.setupResiduePicker.residueOrderByChain?.[chainId])
    ? state.setupResiduePicker.residueOrderByChain[chainId]
    : [];
  const residues = tiers[tierKey]
    .map((position) => order[Number(position) - 1])
    .filter((resi) => Number.isFinite(resi) && resi > 0);
  return residues.length ? { [chainId]: Array.from(new Set(residues)).sort((a, b) => a - b) } : {};
}

function residuePickerPresetDescriptors() {
  const isKo = (state.lang || "en") === "ko";
  const spatial = state.setupResiduePicker.spatialPresets || { surface: {}, core: {}, interface: {} };
  const base = [
    {
      id: "surface",
      label: isKo ? "Surface" : "Surface",
      selection: spatial.surface || {},
      emptyReason: isKo ? "surface 잔기가 없습니다." : "No surface residues available.",
    },
    {
      id: "core",
      label: isKo ? "Core" : "Core",
      selection: spatial.core || {},
      emptyReason: isKo ? "core 잔기가 없습니다." : "No core residues available.",
    },
    {
      id: "interface",
      label: isKo ? "Interface" : "Interface",
      selection: spatial.interface || {},
      emptyReason: isKo ? "interface 잔기가 없습니다." : "No interface residues available.",
    },
  ];
  const conserved = availableConservedTierPresetKeys(state.setupResiduePicker.conservationPreview, [0.3, 0.5, 0.7]).map(
    (tierKey) => {
      const tier = Number(tierKey);
      const availability = conservedTierPresetState(state.setupResiduePicker.conservationPreview, tier / 100, state.lang || "en");
      const selection = residuePickerPresetSelectionForTier(tierKey);
      const chainCount = Object.keys(state.setupResiduePicker.residueOrderByChain || {}).length;
      return {
        id: `conserved_${tierKey}`,
        label: `Conserved ${tierKey}`,
        selection,
        disabled: !availability.enabled,
        emptyReason:
          availability.reason ||
          (chainCount !== 1
            ? (state.lang || "en") === "ko"
              ? "Conserved preset은 단일 체인 구조에서만 바로 선택할 수 있습니다."
              : "Conserved presets are currently available only for single-chain residue picking."
            : (state.lang || "en") === "ko"
              ? "선택할 conserved 잔기가 없습니다."
              : "No conserved residues are available for this tier."),
      };
    }
  );
  return [...base, ...conserved].map((item) => {
    const selection = item.selection && typeof item.selection === "object" ? item.selection : {};
    const count = countSelectedResidues(selection);
    return {
      ...item,
      count,
      disabled: Boolean(item.disabled) || !count,
      title: Boolean(item.disabled) || !count ? item.emptyReason : "",
    };
  });
}

function applyResiduePickerBaseStyle(viewer, colorMode = "secondary") {
  if (!viewer) return;
  const mode = String(colorMode || "secondary").trim().toLowerCase();
  if (mode === "chain") {
    viewer.setStyle({}, { cartoon: { colorscheme: "chain" } });
    return;
  }
  if (mode === "spectrum") {
    viewer.setStyle({}, { cartoon: { color: "spectrum" } });
    return;
  }
  viewer.setStyle({}, { cartoon: { colorscheme: "ssPyMol" } });
}

function buildResiduePickerLauncherCard({ onOpenDetached, onResetSelection, sourceLabel = "", runId = "" } = {}) {
  const card = document.createElement("div");
  card.className = "question-card residue-picker-launcher";

  const title = document.createElement("div");
  title.className = "question-title";
  title.textContent = t("setup.residuePicker.title");

  const help = document.createElement("div");
  help.className = "question-help";
  help.textContent = t("setup.residuePicker.launcherHelp");

  const conservedNote = document.createElement("div");
  conservedNote.className = "question-summary";
  conservedNote.textContent = t("setup.residuePicker.launcherConserved");

  const source = document.createElement("div");
  source.className = "question-summary";
  const normalizedSource = String(sourceLabel || "").trim();
  const normalizedRunId = String(runId || "").trim();
  source.textContent = normalizedSource
    ? t("setup.residuePicker.source", { source: normalizedSource })
    : normalizedRunId
      ? t("setup.residuePicker.source", { source: normalizedRunId })
      : t("setup.residuePicker.source", { source: t("setup.residuePicker.source.none") });

  const actionRow = document.createElement("div");
  actionRow.className = "setup-residue-picker-controls";

  const openBtn = document.createElement("button");
  openBtn.type = "button";
  openBtn.className = "primary";
  openBtn.textContent = t("setup.residuePicker.openDetached");
  openBtn.addEventListener("click", () => {
    if (typeof onOpenDetached === "function") {
      onOpenDetached();
    }
  });
  actionRow.appendChild(openBtn);

  const resetBtn = document.createElement("button");
  resetBtn.type = "button";
  resetBtn.className = "ghost";
  resetBtn.textContent = t("setup.residuePicker.clearSelection");
  resetBtn.addEventListener("click", () => {
    if (typeof onResetSelection === "function") {
      onResetSelection();
    }
  });
  actionRow.appendChild(resetBtn);

  card.appendChild(title);
  card.appendChild(help);
  card.appendChild(source);
  card.appendChild(conservedNote);
  card.appendChild(actionRow);
  return card;
}

function buildResiduePickerCard({
  targetPdbText = "",
  targetFastaText = "",
  rfd3PdbText = "",
  selectedRunId = "",
  pickerProvider = "colabfold",
  detached = false,
  applyButtonLabel = "",
  rerender,
  onOpenDetached,
  onPredictLoaded,
  onApplySelection,
  onApplyCompleted,
} = {}) {
  const card = document.createElement("div");
  card.className = "question-card setup-residue-picker";
  if (detached) {
    card.classList.add("detached-picker-card");
  }

  const title = document.createElement("div");
  title.className = "question-title";
  title.textContent = t("setup.residuePicker.title");

  const help = document.createElement("div");
  help.className = "question-help";
  help.textContent = t("setup.residuePicker.help");

  const head = document.createElement("div");
  head.className = "setup-residue-picker-head";
  const headCopy = document.createElement("div");
  headCopy.className = "setup-residue-picker-head-copy";
  headCopy.appendChild(title);
  headCopy.appendChild(help);
  head.appendChild(headCopy);
  const headActions = document.createElement("div");
  headActions.className = "setup-residue-picker-controls";
  const clearSelectionState = ({ syncParent = false, refresh = true } = {}) => {
    clearSetupResiduePickerSelectionState();
    if (detached) {
      const request = state.detachedResiduePicker.request;
      if (request && typeof request === "object") {
        request.snapshot = buildResiduePickerStateSnapshot();
        try {
          sessionStorage.setItem(
            residuePickerDetachedRequestStorageKey(request.token),
            JSON.stringify(buildDetachedResiduePickerStoragePayload(request))
          );
        } catch (_err) {
          // ignore snapshot refresh failures inside popup
        }
      }
    }
    if (syncParent && detached) {
      dispatchDetachedResiduePickerReset(state.detachedResiduePicker.request);
    }
    if (refresh) refreshCard();
  };
  if (!detached && typeof onOpenDetached === "function") {
    const openDetachedBtn = document.createElement("button");
    openDetachedBtn.type = "button";
    openDetachedBtn.className = "ghost";
    openDetachedBtn.textContent = t("setup.residuePicker.openDetached");
    openDetachedBtn.addEventListener("click", () => {
      onOpenDetached();
    });
    headActions.appendChild(openDetachedBtn);
  }
  if (detached) {
    const clearTopBtn = document.createElement("button");
    clearTopBtn.type = "button";
    clearTopBtn.className = "ghost";
    clearTopBtn.textContent = t("setup.residuePicker.clearSelection");
    clearTopBtn.addEventListener("click", () => {
      clearSelectionState({ syncParent: true, refresh: true });
    });
    headActions.appendChild(clearTopBtn);
  }
  if (headActions.childElementCount) {
    head.appendChild(headActions);
  }

  const source = document.createElement("div");
  source.className = "question-summary";
  source.textContent = t("setup.residuePicker.source", {
    source: state.setupResiduePicker.sourceLabel || t("setup.residuePicker.source.none"),
  });

  const controls = document.createElement("div");
  controls.className = "setup-residue-picker-controls";

  const loadTargetBtn = document.createElement("button");
  loadTargetBtn.type = "button";
  loadTargetBtn.className = "ghost";
  loadTargetBtn.textContent = t("setup.residuePicker.loadTargetInput");

  const loadRfd3Btn = document.createElement("button");
  loadRfd3Btn.type = "button";
  loadRfd3Btn.className = "ghost";
  loadRfd3Btn.textContent = t("setup.residuePicker.loadRfd3Input");

  const loadRunBtn = document.createElement("button");
  loadRunBtn.type = "button";
  loadRunBtn.className = "ghost";
  loadRunBtn.textContent = t("setup.residuePicker.loadRunTarget");

  const runAf2Btn = document.createElement("button");
  runAf2Btn.type = "button";
  runAf2Btn.className = "ghost";
  runAf2Btn.textContent = t("setup.residuePicker.runAf2", af2ProviderTemplateParams(pickerProvider));

  const controlState = residuePickerControlState({
    targetPdbText,
    targetFastaText,
    rfd3PdbText,
    selectedRunId,
    busy: Boolean(state.setupResiduePicker.runningAf2),
  });
  loadTargetBtn.disabled = !controlState.canLoadTarget;
  loadRfd3Btn.disabled = !controlState.canLoadRfd3;
  loadRunBtn.disabled = !controlState.canLoadRun;
  runAf2Btn.disabled = !controlState.canRunAf2;

  const refreshCard = () => {
    if (typeof rerender === "function") rerender();
  };

  const loadStructureFromText = (pdbText, sourceLabelText, sourceKey) => {
    const text = String(pdbText || "").trim();
    if (!text) {
      state.setupResiduePicker.notice = t("setup.residuePicker.noPdb");
      refreshCard();
      return;
    }
    const loaded = setSetupResiduePickerStructure(text, { sourceLabel: sourceLabelText, sourceKey });
    state.setupResiduePicker.notice = loaded ? "" : t("setup.residuePicker.noPdb");
    refreshCard();
  };

  loadTargetBtn.addEventListener("click", () => {
    loadStructureFromText(targetPdbText, t("setup.residuePicker.loadTargetInput"), "target_input");
  });
  loadRfd3Btn.addEventListener("click", () => {
    loadStructureFromText(rfd3PdbText, t("setup.residuePicker.loadRfd3Input"), "rfd3_input_pdb");
  });
  loadRunBtn.addEventListener("click", async () => {
    if (!selectedRunId) {
      state.setupResiduePicker.notice = t("setup.residuePicker.noRun");
      refreshCard();
      return;
    }
    try {
      await loadResiduePickerConservationPreview(selectedRunId);
      const result = await apiCall("pipeline.read_artifact", {
        run_id: selectedRunId,
        path: "target.pdb",
        max_bytes: 2_000_000,
      });
      const text = String(result?.text || "").trim();
      if (!text) {
        state.setupResiduePicker.notice = t("setup.residuePicker.noPdb");
        refreshCard();
        return;
      }
      const label = `${selectedRunId}:target.pdb`;
      const loaded = setSetupResiduePickerStructure(text, {
        sourceLabel: label,
        sourceKey: `run_target:${selectedRunId}`,
      });
      state.setupResiduePicker.notice = loaded ? "" : t("setup.residuePicker.noPdb");
    } catch (err) {
      state.setupResiduePicker.notice = t("setup.residuePicker.loadFailed", { error: err.message });
    }
    refreshCard();
  });
  runAf2Btn.addEventListener("click", async () => {
    if (!String(targetFastaText || "").trim()) {
      state.setupResiduePicker.notice = t("setup.residuePicker.runAf2NeedsFasta");
      refreshCard();
      return;
    }
    state.setupResiduePicker.runningAf2 = true;
    state.setupResiduePicker.notice = t("setup.residuePicker.runAf2Running", af2ProviderTemplateParams(pickerProvider));
    refreshCard();
    try {
      const result = await predictResiduePickerTargetStructure({
        fastaText: targetFastaText,
        af2Provider: pickerProvider,
      });
      if (typeof onPredictLoaded === "function") {
        onPredictLoaded(result);
      }
      state.setupResiduePicker.notice = result.loaded
        ? t("setup.residuePicker.runAf2Loaded", { run: result.outRunId, path: result.selectedPath })
        : t("setup.residuePicker.noPdb");
    } catch (err) {
      state.setupResiduePicker.notice = t("setup.residuePicker.runAf2Failed", { error: err.message });
    } finally {
      state.setupResiduePicker.runningAf2 = false;
      refreshCard();
    }
  });

  controls.appendChild(runAf2Btn);
  controls.appendChild(loadTargetBtn);
  controls.appendChild(loadRfd3Btn);
  controls.appendChild(loadRunBtn);

  const modeRow = document.createElement("div");
  modeRow.className = "setup-residue-picker-mode-row";
  [
    {
      id: "secondary",
      label: (state.lang || "en") === "ko" ? "2차구조" : "Secondary",
    },
    {
      id: "spectrum",
      label: (state.lang || "en") === "ko" ? "N→C" : "N→C",
    },
    {
      id: "chain",
      label: (state.lang || "en") === "ko" ? "Chain" : "Chain",
    },
  ].forEach((mode) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = `ghost mode-chip${state.setupResiduePicker.structureColorMode === mode.id ? " selected" : ""}`;
    button.textContent = mode.label;
    button.addEventListener("click", () => {
      state.setupResiduePicker.structureColorMode = mode.id;
      refreshCard();
    });
    modeRow.appendChild(button);
  });

  const cutoffRow = document.createElement("div");
  cutoffRow.className = "setup-residue-picker-threshold";
  const cutoffLabel = document.createElement("label");
  cutoffLabel.className = "setup-residue-picker-threshold-label";
  cutoffLabel.textContent = t("setup.residuePicker.surfaceCutoffLabel");
  const cutoffInput = document.createElement("input");
  cutoffInput.type = "number";
  cutoffInput.min = "0";
  cutoffInput.step = "0.1";
  cutoffInput.value = String(
    normalizeSurfaceAreaCutoff(state.setupResiduePicker.surfaceAreaCutoff, DEFAULT_SURFACE_AREA_CUTOFF)
  );
  cutoffInput.addEventListener("change", () => {
    state.setupResiduePicker.surfaceAreaCutoff = normalizeSurfaceAreaCutoff(
      cutoffInput.value,
      DEFAULT_SURFACE_AREA_CUTOFF
    );
    recomputeSetupResiduePickerSpatialPresets();
    refreshCard();
  });
  const cutoffHelp = document.createElement("div");
  cutoffHelp.className = "setup-residue-picker-threshold-help";
  cutoffHelp.textContent = t("setup.residuePicker.surfaceCutoffHelp");
  cutoffRow.appendChild(cutoffLabel);
  cutoffRow.appendChild(cutoffInput);
  cutoffRow.appendChild(cutoffHelp);

  const presetRow = document.createElement("div");
  presetRow.className = "setup-residue-picker-preset-row";
  const presetDescriptors = residuePickerPresetDescriptors();
  const presetSelectionsById = residuePickerPresetSelectionsById(presetDescriptors);
  syncSetupResiduePickerSelectionState({
    selectionFallback: state.setupResiduePicker.selection,
    presetSelectionsById,
    allowFallback: true,
  });
  const presetButtons = [];
  presetDescriptors.forEach((preset) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "ghost preset-chip";
    button.disabled = Boolean(preset.disabled);
    button.title = preset.title || "";
    button.textContent = `${preset.label}${preset.count ? ` (${preset.count})` : ""}`;
    button.addEventListener("click", () => {
      const activePresetIds = new Set(
        normalizeResiduePickerActivePresetIds(state.setupResiduePicker.activePresetIds, presetSelectionsById)
      );
      if (activePresetIds.has(preset.id)) {
        activePresetIds.delete(preset.id);
      } else {
        activePresetIds.add(preset.id);
      }
      syncSetupResiduePickerSelectionState({
        selectionFallback: state.setupResiduePicker.selection,
        activePresetIds: Array.from(activePresetIds),
        presetSelectionsById,
      });
      syncSelectionViews({ clearNotice: true });
    });
    presetButtons.push({ button, preset });
    presetRow.appendChild(button);
  });

  const workspace = document.createElement("div");
  workspace.className = "setup-residue-picker-workspace";

  const sequencePane = document.createElement("div");
  sequencePane.className = "setup-residue-picker-sequence";
  const sequenceTitle = document.createElement("div");
  sequenceTitle.className = "status-subtitle";
  sequenceTitle.textContent = (state.lang || "en") === "ko" ? "서열 선택" : "Sequence Selection";
  sequencePane.appendChild(sequenceTitle);

  const sequenceBody = document.createElement("div");
  sequenceBody.className = "setup-residue-picker-sequence-body";
  sequencePane.appendChild(sequenceBody);

  const viewerPane = document.createElement("div");
  viewerPane.className = "setup-residue-picker-view";
  const viewerTitle = document.createElement("div");
  viewerTitle.className = "status-subtitle";
  viewerTitle.textContent = (state.lang || "en") === "ko" ? "구조 보기" : "Structure View";
  viewerPane.appendChild(viewerTitle);

  const selectionText = document.createElement("div");
  selectionText.className = "question-summary";

  const notice = document.createElement("div");
  notice.className = "question-summary setup-residue-picker-notice";
  notice.textContent = state.setupResiduePicker.notice || "";

  let redrawViewer = () => {};
  let syncSequenceSelection = () => {};
  let syncPresetSelection = () => {};

  const setNotice = (text = "") => {
    state.setupResiduePicker.notice = String(text || "");
    notice.textContent = state.setupResiduePicker.notice;
  };

  const selectionMapHasResidue = (selectionMap, chain, residue) =>
    Array.isArray(selectionMap?.[chain]) && selectionMap[chain].includes(residue);

  const updateSelectionResidue = (selectionMap, chain, residue, selected) => {
    const next = normalizeResidueSelectionMap(selectionMap);
    const chainId = normalizeChainId(chain || "");
    if (!chainId || !Number.isFinite(residue) || residue <= 0) return next;
    const chainSet = new Set(next[chainId] || []);
    if (selected) {
      chainSet.add(residue);
    } else {
      chainSet.delete(residue);
    }
    if (chainSet.size) {
      next[chainId] = Array.from(chainSet).sort((left, right) => left - right);
    } else {
      delete next[chainId];
    }
    return next;
  };

  const updateSelectionSummary = () => {
    const normalized = normalizeResidueSelectionMap(state.setupResiduePicker.selection);
    state.setupResiduePicker.selection = normalized;
    const summary = selectionSummaryText(normalized);
    selectionText.textContent = summary
      ? t("setup.residuePicker.selection.summary", { summary })
      : t("setup.residuePicker.selection.none");
  };

  const syncSelectionViews = ({ clearNotice = false } = {}) => {
    if (clearNotice) {
      setNotice("");
    } else {
      notice.textContent = state.setupResiduePicker.notice || "";
    }
    updateSelectionSummary();
    syncPresetSelection();
    syncSequenceSelection();
    redrawViewer();
  };

  const toggleSelection = (chain, resi) => {
    const chainId = normalizeChainId(chain || "");
    const residue = Number.parseInt(resi, 10);
    if (!Number.isFinite(residue) || residue <= 0) return;
    const currentSelection = normalizeResidueSelectionMap(state.setupResiduePicker.selection);
    const manualSelection = normalizeResidueSelectionMap(state.setupResiduePicker.manualSelection || {});
    const excludedSelection = normalizeResidueSelectionMap(state.setupResiduePicker.excludedSelection || {});
    const activePresetIds = normalizeResiduePickerActivePresetIds(
      state.setupResiduePicker.activePresetIds,
      presetSelectionsById
    );
    const presetSelected = activePresetIds.some((presetId) =>
      selectionMapHasResidue(presetSelectionsById[presetId], chainId, residue)
    );
    const currentlySelected = selectionMapHasResidue(currentSelection, chainId, residue);
    let nextManualSelection = manualSelection;
    let nextExcludedSelection = excludedSelection;
    if (currentlySelected) {
      nextManualSelection = updateSelectionResidue(nextManualSelection, chainId, residue, false);
      if (presetSelected) {
        nextExcludedSelection = updateSelectionResidue(nextExcludedSelection, chainId, residue, true);
      }
    } else {
      if (presetSelected) {
        nextExcludedSelection = updateSelectionResidue(nextExcludedSelection, chainId, residue, false);
      } else {
        nextExcludedSelection = updateSelectionResidue(nextExcludedSelection, chainId, residue, false);
        nextManualSelection = updateSelectionResidue(nextManualSelection, chainId, residue, true);
      }
    }
    syncSetupResiduePickerSelectionState({
      selectionFallback: currentSelection,
      manualSelection: nextManualSelection,
      excludedSelection: nextExcludedSelection,
      activePresetIds,
      presetSelectionsById,
    });
    syncSelectionViews({ clearNotice: true });
  };

  updateSelectionSummary();

  const sequenceTracks = buildSequenceSelectionTracks(
    state.setupResiduePicker.sequenceByChain || {},
    state.setupResiduePicker.residueOrderByChain || {},
    { lineLength: 24, labelEvery: 2 }
  );
  if (!sequenceTracks.length) {
    const empty = document.createElement("div");
    empty.className = "placeholder";
    empty.textContent = t("setup.residuePicker.viewerPlaceholder");
    sequenceBody.appendChild(empty);
  } else {
    sequenceTracks.forEach((track) => {
      const chainBlock = document.createElement("div");
      chainBlock.className = "sequence-track-block";
      const chainHeader = document.createElement("div");
      chainHeader.className = "sequence-track-header";
      chainHeader.textContent = `Chain ${track.chain} · ${track.rows.reduce((count, row) => count + row.cells.length, 0)} aa`;
      chainBlock.appendChild(chainHeader);

      (Array.isArray(track.rows) ? track.rows : []).forEach((row) => {
        const rowWrap = document.createElement("div");
        rowWrap.className = "sequence-track-row";

        const residueGrid = document.createElement("div");
        residueGrid.className = "sequence-track-grid";
        residueGrid.style.gridTemplateColumns = `repeat(${row.cells.length}, minmax(20px, 1fr))`;

        row.cells.forEach((cell) => {
          const residueButton = document.createElement("button");
          residueButton.type = "button";
          residueButton.className = "sequence-track-residue";
          residueButton.dataset.chain = track.chain;
          residueButton.dataset.resi = String(cell.resi);
          residueButton.title = `${track.chain}:${cell.resi} ${cell.aa} · ${cell.label}`;
          residueButton.style.setProperty("--residue-color", String(cell.color || aminoAcidPropertyInfo(cell.aa).color));

          const residueLetter = document.createElement("span");
          residueLetter.className = "sequence-track-aa";
          residueLetter.textContent = String(cell.aa || "X");

          const residueBar = document.createElement("span");
          residueBar.className = "sequence-track-bar";

          residueButton.appendChild(residueLetter);
          residueButton.appendChild(residueBar);
          residueButton.addEventListener("click", () => toggleSelection(track.chain, cell.resi));
          residueGrid.appendChild(residueButton);
        });

        const labelGrid = document.createElement("div");
        labelGrid.className = "sequence-track-labels";
        labelGrid.style.gridTemplateColumns = `repeat(${row.cells.length}, minmax(20px, 1fr))`;
        row.labels.forEach((label) => {
          const value = String(label?.value || "").trim();
          const slot = Number(label?.slot);
          if (!value || !Number.isFinite(slot)) return;
          const labelEl = document.createElement("span");
          labelEl.className = `sequence-track-label${label.edge ? " edge" : ""}`;
          labelEl.style.gridColumn = String(slot + 1);
          labelEl.textContent = value;
          labelGrid.appendChild(labelEl);
        });

        rowWrap.appendChild(residueGrid);
        rowWrap.appendChild(labelGrid);
        chainBlock.appendChild(rowWrap);
      });

      sequenceBody.appendChild(chainBlock);
    });
  }

  syncSequenceSelection = () => {
    const selection = normalizeResidueSelectionMap(state.setupResiduePicker.selection);
    Array.from(sequenceBody.querySelectorAll(".sequence-track-residue")).forEach((node) => {
      if (!(node instanceof HTMLElement)) return;
      const chain = normalizeChainId(node.dataset.chain || "");
      const resi = Number.parseInt(node.dataset.resi || "", 10);
      const selected = Number.isFinite(resi) && Array.isArray(selection[chain]) && selection[chain].includes(resi);
      node.classList.toggle("selected", Boolean(selected));
    });
  };
  syncPresetSelection = () => {
    const activePresetIds = new Set(
      normalizeResiduePickerActivePresetIds(state.setupResiduePicker.activePresetIds, presetSelectionsById)
    );
    presetButtons.forEach(({ button, preset }) => {
      if (!(button instanceof HTMLElement)) return;
      button.classList.toggle("selected", activePresetIds.has(preset.id));
    });
  };
  syncPresetSelection();
  syncSequenceSelection();

  if (!state.setupResiduePicker.pdbText) {
    const placeholder = document.createElement("div");
    placeholder.className = "placeholder";
    placeholder.textContent = t("setup.residuePicker.viewerPlaceholder");
    viewerPane.appendChild(placeholder);
  } else if (!window.$3Dmol) {
    const placeholder = document.createElement("div");
    placeholder.className = "placeholder";
    placeholder.textContent = t("setup.residuePicker.viewerUnavailable");
    viewerPane.appendChild(placeholder);
  } else {
    const viewerEl = document.createElement("div");
    viewerEl.className = "viewer3d setup-residue-picker-viewer";
    viewerPane.appendChild(viewerEl);

    const viewer = window.$3Dmol.createViewer(viewerEl, { backgroundColor: "white" });
    viewer.addModel(state.setupResiduePicker.pdbText, "pdb");
    const residueSetByChain = {};
    const surfaceSelection = normalizeResidueSelectionMap(state.setupResiduePicker.spatialPresets?.surface || {});
    const coreSelection = normalizeResidueSelectionMap(state.setupResiduePicker.spatialPresets?.core || {});
    const interfaceSelection = normalizeResidueSelectionMap(state.setupResiduePicker.spatialPresets?.interface || {});
    const residueAnnotationByKey = new Map();
    Object.entries(state.setupResiduePicker.residueOrderByChain || {}).forEach(([chain, values]) => {
      residueSetByChain[chain] = new Set(values);
    });
    (Array.isArray(state.setupResiduePicker.spatialPresets?.residues)
      ? state.setupResiduePicker.spatialPresets.residues
      : []
    ).forEach((entry) => {
      const chain = normalizeChainId(entry?.chain || "");
      const resi = Number.parseInt(entry?.resi, 10);
      const key = residueAnnotationKey(chain, resi);
      if (!key) return;
      const exposureClass = selectionMapHasResidue(coreSelection, chain, resi)
        ? "core"
        : selectionMapHasResidue(surfaceSelection, chain, resi)
          ? "surface"
          : "";
      residueAnnotationByKey.set(key, {
        exposureClass,
        interfaceHit: selectionMapHasResidue(interfaceSelection, chain, resi) || Boolean(entry?.interface),
      });
    });
    const pickerLegend = createViewerLegendCard(
      buildResiduePickerViewerLegendLines({
        colorMode: state.setupResiduePicker.structureColorMode,
        lang: state.lang || "en",
      })
    );
    if (pickerLegend) {
      viewerPane.appendChild(pickerLegend);
    }

    redrawViewer = () => {
      applyResiduePickerBaseStyle(viewer, state.setupResiduePicker.structureColorMode);
      Object.entries(normalizeResidueSelectionMap(state.setupResiduePicker.selection)).forEach(([chain, values]) => {
        values.forEach((resi) => {
          const selector = { resi };
          const chainId = denormalizeChainId(chain);
          if (chainId) selector.chain = chainId;
          viewer.setStyle(selector, {
            cartoon: { color: "#d9480f" },
            stick: { radius: 0.2, color: "#d9480f" },
          });
        });
      });
      viewer.render();
    };

    installViewerHoverLabels(viewer, (atom) => {
      const chain = normalizeChainId(atom?.chain || "");
      const resi = Number.parseInt(atom?.resi, 10);
      if (!Number.isFinite(resi) || resi <= 0) return "";
      const allowed = residueSetByChain[chain];
      if (!allowed || !allowed.has(resi)) return "";
      const annotation = residueAnnotationByKey.get(residueAnnotationKey(chain, resi)) || {};
      return buildResiduePickerHoverText({
        chain,
        resi,
        resn: atom?.resn || "",
        selected: selectionMapHasResidue(normalizeResidueSelectionMap(state.setupResiduePicker.selection), chain, resi),
        exposureClass: annotation.exposureClass || "",
        interfaceHit: Boolean(annotation.interfaceHit),
        lang: state.lang || "en",
      });
    });

    viewer.setClickable({}, true, (atom) => {
      const chain = normalizeChainId(atom?.chain || "");
      const resi = Number.parseInt(atom?.resi, 10);
      if (!Number.isFinite(resi) || resi <= 0) return;
      const allowed = residueSetByChain[chain];
      if (!allowed || !allowed.has(resi)) return;
      toggleSelection(chain, resi);
    });

    viewer.zoomTo();
    redrawViewer();
  }

  workspace.appendChild(viewerPane);
  workspace.appendChild(sequencePane);

  const actionRow = document.createElement("div");
  actionRow.className = "setup-residue-picker-controls";

  const applyBtn = document.createElement("button");
  applyBtn.type = "button";
  applyBtn.className = "primary";
  applyBtn.textContent = applyButtonLabel || t("setup.residuePicker.apply");
  applyBtn.addEventListener("click", () => {
    const mappedSelection = selectedResiduesToQueryPositions(
      state.setupResiduePicker.selection,
      state.setupResiduePicker.residueOrderByChain
    );
    const selectedCount = countSelectedResidues(mappedSelection);
    if (typeof onApplySelection === "function") {
      const delivered = onApplySelection(mappedSelection, selectedCount);
      if (delivered === false) {
        setNotice(t("setup.residuePicker.applyFailed"));
        return;
      }
    }
    setNotice(
      selectedCount ? t("setup.residuePicker.applied", { count: selectedCount }) : t("setup.residuePicker.cleared")
    );
    syncSelectionViews();
    if (typeof onApplyCompleted === "function") {
      onApplyCompleted({ mappedSelection, selectedCount });
    }
  });

  const clearSelectionBtn = document.createElement("button");
  clearSelectionBtn.type = "button";
  clearSelectionBtn.className = "ghost";
  clearSelectionBtn.textContent = t("setup.residuePicker.clearSelection");
  clearSelectionBtn.addEventListener("click", () => {
    clearSelectionState({ syncParent: detached, refresh: false });
    syncSelectionViews({ clearNotice: true });
  });

  actionRow.appendChild(applyBtn);
  if (!detached) {
    actionRow.appendChild(clearSelectionBtn);
  }

  const note = document.createElement("div");
  note.className = "question-summary";
  note.textContent = t("setup.residuePicker.note");

  card.appendChild(head);
  card.appendChild(source);
  card.appendChild(controls);
  card.appendChild(modeRow);
  card.appendChild(cutoffRow);
  card.appendChild(presetRow);
  card.appendChild(workspace);
  card.appendChild(selectionText);
  card.appendChild(actionRow);
  card.appendChild(note);
  card.appendChild(notice);
  return card;
}

function refreshChainRangesFromAnswers() {
  const rfd3Text = setupRunUsesRfd3Stage() ? getEffectiveRfd3InputPdbTextFromAnswers() : "";
  if (rfd3Text) {
    updateChainRangesFromText(rfd3Text);
    return;
  }
  const targetPdbText = getTargetInputPdbText();
  if (targetPdbText) {
    updateChainRangesFromText(targetPdbText);
    return;
  }
  state.chainRanges = null;
}

function updateChainRangesFromText(text) {
  const ranges = parsePdbChainRanges(text);
  state.chainRanges = ranges;
}

function clearStructureBoundRfd3Answers() {
  state.answers.rfd3_contig = "";
  state.answers.rfd3_unindex = "";
  state.answers.rfd3_select_fixed_atoms = "";
}

function isAnswerMissing(value) {
  if (Array.isArray(value)) return value.length === 0;
  if (value === null || value === undefined) return true;
  return String(value).trim() === "";
}

function normalizeQuestion(q) {
  if (!q || !q.id) return q;
  const aliasId = QUESTION_ID_ALIASES[q.id];
  const base = aliasId ? { ...q, id: aliasId } : q;
  if (aliasId) {
    delete base.labelKey;
    delete base.questionKey;
    delete base.label;
    delete base.question;
  }
  const preset = QUESTION_PRESETS[base.id];
  if (!preset) return base;
  const merged = { ...preset, ...base };
  if (merged.required === undefined) merged.required = Boolean(preset.required);
  return merged;
}

function formatAnswerValue(value) {
  if (value === null || value === undefined) return "";
  if (Array.isArray(value)) return value.join(", ");
  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch {
      return String(value);
    }
  }
  return String(value);
}

function splitAnswerList(raw) {
  return String(raw || "")
    .split(/[,\s]+/)
    .map((item) => item.trim())
    .filter((item) => item.length > 0);
}

function parseFixedPositionsExtra(raw) {
  const text = String(raw || "").trim();
  if (!text) return { value: "", error: "" };
  if (text.startsWith("{") || text.startsWith("[")) {
    try {
      const parsed = JSON.parse(text);
      if (typeof parsed === "object") {
        return { value: parsed, error: "" };
      }
      return { value: "", error: "fixed_positions_extra must be JSON object/list." };
    } catch (err) {
      return { value: "", error: "fixed_positions_extra JSON parse failed." };
    }
  }

  if (text.includes(":")) {
    const out = {};
    const segments = text.split(/[;\n]+/).map((seg) => seg.trim()).filter(Boolean);
    segments.forEach((seg) => {
      if (!seg.includes(":")) return;
      const parts = seg.split(":");
      const chain = (parts.shift() || "").trim();
      if (!chain) return;
      const nums = splitAnswerList(parts.join(":"))
        .map((v) => Number.parseInt(v, 10))
        .filter((v) => Number.isFinite(v) && v > 0);
      if (nums.length) out[chain] = nums;
    });
    if (Object.keys(out).length) return { value: out, error: "" };
    return { value: "", error: "fixed_positions_extra chain list is empty." };
  }

  const nums = splitAnswerList(text)
    .map((v) => Number.parseInt(v, 10))
    .filter((v) => Number.isFinite(v) && v > 0);
  if (nums.length) return { value: nums, error: "" };
  return { value: "", error: "fixed_positions_extra expects numbers or JSON." };
}

function parseAnswerValue(id, raw) {
  const text = String(raw ?? "").trim();
  if (!text) return { value: "", error: "" };

  if (ANSWER_JSON_KEYS.has(id)) {
    if (id === "fixed_positions_extra") {
      return parseFixedPositionsExtra(text);
    }
    try {
      const parsed = JSON.parse(text);
      if (typeof parsed === "object") return { value: parsed, error: "" };
      return { value: "", error: `${id} must be a JSON object.` };
    } catch (err) {
      return { value: "", error: `${id} JSON parse failed.` };
    }
  }

  if (ANSWER_BOOL_KEYS.has(id)) {
    const v = text.toLowerCase();
    if (["1", "true", "yes", "y", "on"].includes(v)) return { value: true, error: "" };
    if (["0", "false", "no", "n", "off"].includes(v)) return { value: false, error: "" };
    return { value: "", error: `${id} expects true/false.` };
  }

  if (ANSWER_INT_KEYS.has(id)) {
    const n = Number.parseInt(text, 10);
    if (Number.isFinite(n)) return { value: n, error: "" };
    return { value: "", error: `${id} expects an integer.` };
  }

  if (ANSWER_FLOAT_KEYS.has(id)) {
    const n = Number.parseFloat(text);
    if (!Number.isFinite(n)) return { value: "", error: `${id} expects a number.` };
    if (id === "af2_plddt_cutoff" && (n < 0 || n > 100)) {
      return { value: "", error: "af2_plddt_cutoff must be between 0 and 100." };
    }
    if (id === "af2_rmsd_cutoff" && n <= 0) {
      return { value: "", error: "af2_rmsd_cutoff must be greater than 0." };
    }
    return { value: n, error: "" };
  }

  if (ANSWER_FLOAT_LIST_KEYS.has(id)) {
    let items = [];
    if (text.startsWith("[")) {
      try {
        const parsed = JSON.parse(text);
        if (Array.isArray(parsed)) {
          items = parsed.map((v) => Number.parseFloat(v)).filter((v) => Number.isFinite(v));
        }
      } catch (err) {
        return { value: "", error: `${id} JSON parse failed.` };
      }
    } else {
      items = splitAnswerList(text)
        .map((v) => Number.parseFloat(v))
        .filter((v) => Number.isFinite(v));
    }
    if (items.length) return { value: items, error: "" };
    return { value: "", error: `${id} expects a list of numbers.` };
  }

  if (ANSWER_LIST_KEYS.has(id)) {
    let items = [];
    if (text.startsWith("[")) {
      try {
        const parsed = JSON.parse(text);
        if (Array.isArray(parsed)) {
          items = parsed.map((v) => String(v)).filter((v) => v.length > 0);
        }
      } catch (err) {
        return { value: "", error: `${id} JSON parse failed.` };
      }
    } else {
      items = splitAnswerList(text);
    }
    if (items.length) return { value: items, error: "" };
    return { value: "", error: `${id} expects a list.` };
  }

  return { value: text, error: "" };
}

function renderChoiceButtons(container, options, currentValue, onSelect, { multi = false, rerender = true } = {}) {
  const group = document.createElement("div");
  group.className = "choice-group";
  const buttons = [];
  options.forEach((opt) => {
    const btn = document.createElement("button");
    btn.type = "button";
    btn.className = "choice-btn";
    const isSelected = multi
      ? Array.isArray(currentValue) && currentValue.includes(opt.value)
      : currentValue === opt.value;
    if (isSelected) btn.classList.add("selected");
    btn.textContent = labelFor(opt);
    btn.addEventListener("click", () => {
      onSelect(opt.value);
      if (!rerender) {
        if (multi) {
          btn.classList.toggle("selected");
        } else {
          buttons.forEach((node) => node.classList.remove("selected"));
          btn.classList.add("selected");
        }
        return;
      }
      renderQuestions(state.plan?.questions || []);
    });
    group.appendChild(btn);
    buttons.push(btn);
  });
  container.appendChild(group);
}

function renderSetupReviewCard(normalizedQuestions = []) {
  const confirmQuestion = normalizedQuestions.find((q) => q?.id === "confirm_run");
  if (state.answers.confirm_run === undefined) {
    state.answers.confirm_run = confirmQuestion?.default !== undefined ? Boolean(confirmQuestion.default) : true;
  }

  const card = document.createElement("div");
  card.className = "question-card setup-review-card";

  const title = document.createElement("div");
  title.className = "question-title";
  title.textContent = t("setup.review.title");

  const grid = document.createElement("div");
  grid.className = "setup-review-grid";

  const appendItem = (labelKey, value, { muted = false } = {}) => {
    const item = document.createElement("div");
    item.className = "setup-review-item";
    if (muted) item.classList.add("muted");

    const label = document.createElement("div");
    label.className = "setup-review-label";
    label.textContent = t(labelKey);

    const text = document.createElement("div");
    text.className = "setup-review-value";
    text.textContent = String(value || t("setup.review.none"));

    item.appendChild(label);
    item.appendChild(text);
    grid.appendChild(item);
  };

  const modeOption = RUN_MODE_OPTIONS.find((item) => item.value === state.runMode);
  const startStage = normalizePipelineStage(state.answers.start_from || "msa", "msa");
  const stopStage = normalizePipelineStage(state.answers.stop_after || "novelty", "novelty");
  const stopLabel = stopStage === "novelty" ? t("stop.full") : formatStageLabel(stopStage);
  const hasTargetInput = Boolean(
    String(state.answers.target_input || state.answers.target_pdb || state.answers.target_fasta || "").trim()
  );
  const tierQuestion = normalizedQuestions.find((q) => q?.id === "selected_tiers");
  const selectedTiers = currentSetupSelectedTiers(tierQuestion);
  const rfd3Active = setupRunEnablesRfd3Stage();
  const bioemuActive = state.answers.bioemu_use === true || ["bioemu", "design", "soluprot", "af2", "novelty"].includes(stopStage);
  const relaxActive = state.answers.relax_enabled === true;

  appendItem("setup.review.mode", modeOption?.labelKey ? t(modeOption.labelKey) : state.runMode);
  appendItem("setup.review.stages", `${formatStageLabel(startStage)} -> ${stopLabel}`);
  appendItem("setup.review.input", hasTargetInput ? t("setup.review.inputReady") : t("setup.review.inputMissing"), {
    muted: !hasTargetInput,
  });
  appendItem("setup.review.rfd3", rfd3Active ? t("common.enabled") : t("common.disabled"));
  appendItem("setup.review.bioemu", bioemuActive ? t("common.enabled") : t("common.disabled"));
  appendItem("setup.review.af2", af2ProviderName(state.answers.af2_provider || "colabfold", state.lang || "en"));
  appendItem("setup.review.relax", relaxActive ? t("common.enabled") : t("common.disabled"));
  appendItem(
    "setup.review.tiers",
    selectedTiers.length
      ? selectedTiers.map((value) => formatConservationTierValue(value)).join(", ")
      : t("setup.review.none")
  );

  card.appendChild(title);
  card.appendChild(grid);
  return card;
}

function renderQuestions(questions) {
  const inputStack = el.questionInputStack || el.questionStack;
  const configStack = el.questionConfigStack || el.questionStack;
  if (configStack) {
    configStack.classList.toggle("workflow-layout", state.runMode === "workflow");
  }
  const stacks = new Set([el.questionStack, el.questionInputStack, el.questionConfigStack].filter(Boolean));
  stacks.forEach((node) => {
    node.innerHTML = "";
  });
  const appendInputCard = (card) => {
    if (inputStack) inputStack.appendChild(card);
  };
  const appendConfigCard = (card) => {
    if (configStack) configStack.appendChild(card);
  };

  if (!questions.length) {
    if (el.setupStepper) el.setupStepper.classList.add("hidden");
    el.runBtn.disabled = false;
    el.runHint.textContent = t("hint.none");
    return;
  }

  const normalizedQuestions = (questions || [])
    .map((q) => normalizeQuestion(q))
    .filter(Boolean);
  if (!normalizedQuestions.some((q) => q.id === "compare_rmsd_scope")) {
    normalizedQuestions.push(normalizeQuestion({ id: "compare_rmsd_scope" }));
  }
  const filteredVisibleQuestions = normalizedQuestions.filter((q) => questionVisibleForCurrentState(q));
  const visibleQuestions = renderSetupWizard(filteredVisibleQuestions);
  const setupWizardActive = setupWizardEnabled(filteredVisibleQuestions);
  const setupWizardStepId = setupWizardActive ? activeSetupWizardStepId() : "";
  if (state.runMode === "pipeline") {
    if (!normalizePipelineStage(state.answers.start_from, "")) {
      state.answers.start_from = "msa";
    }
    syncStartStopStages();
  }

  if (setupWizardStepId === "review") {
    appendConfigCard(renderSetupReviewCard(normalizedQuestions));
    updateRunEligibility(normalizedQuestions);
    return;
  }

  const fileQuestionIds = new Set([
    "target_input",
    "target_pdb",
    "target_fasta",
    "rfd3_input_pdb",
    "diffdock_ligand",
  ]);

  const choiceQuestionIds = new Set([
    "run_mode",
    "start_from",
    "stop_after",
    "rfd3_use",
    "backbone_filter_use_dssp",
    "selected_tiers",
    "design_chains",
    "rfd3_contig",
    "pdb_strip_nonpositive_resseq",
    "wt_compare",
    "mask_consensus_apply",
    "ligand_mask_use_original_target",
    "bioemu_use",
    "bioemu_filter_samples",
    "novelty_enabled",
    "relax_enabled",
    "af2_provider",
    "confirm_run",
  "evolution_mode",
]);

  const isFileQuestion = (q) => q && fileQuestionIds.has(q.id);
  const isChoiceQuestion = (q) => q && choiceQuestionIds.has(q.id);
  const fileQuestions = [];
  const choiceQuestions = [];
  const textQuestions = [];

  visibleQuestions.forEach((q) => {
    if (isFileQuestion(q)) {
      fileQuestions.push(q);
    } else if (isChoiceQuestion(q)) {
      choiceQuestions.push(q);
    } else {
      textQuestions.push(q);
    }
  });

  const compactChoiceQuestionIds = new Set([
    "novelty_enabled",
    "rfd3_use",
    "backbone_filter_use_dssp",
    "bioemu_use",
    "bioemu_filter_samples",
    "relax_enabled",
    "af2_provider",
    "selected_tiers",
    "design_chains",
    "pdb_strip_nonpositive_resseq",
    "wt_compare",
    "mask_consensus_apply",
  ]);

  const buildQuestionCardClass = (q, extraClasses = []) => {
    const classes = ["question-card"];
    const rawId = String(q?.id || "").trim();
    if (rawId) {
      const safeId = rawId.replace(/[^a-z0-9_-]+/gi, "-");
      if (safeId) classes.push(`question-${safeId}`);
    }
    if (q?.required) classes.push("required");
    if (Array.isArray(extraClasses)) {
      extraClasses.forEach((name) => {
        if (name) classes.push(name);
      });
    }
    return classes.join(" ");
  };

  function renderSetupRfd3ModeDetailsCard(card, normalizedQuestions) {
    const fieldIds = setupRfd3ModeDetailIds();
    if (!fieldIds.length) return;
    const resolvedRfd3Defaults = resolveRfd3Defaults({
      mode: state.runMode,
      answers: state.answers,
      nodes: setupWorkflowNodesForRfd3(),
    });
    if (
      isAnswerMissing(state.answers.rfd3_contig) &&
      resolvedRfd3Defaults.inferredContig
    ) {
      state.answers.rfd3_contig = resolvedRfd3Defaults.inferredContig;
    }
    if (
      isAnswerMissing(state.answers.rfd3_unindex) &&
      resolvedRfd3Defaults.inferredUnindex
    ) {
      state.answers.rfd3_unindex = resolvedRfd3Defaults.inferredUnindex;
    }
    if (
      isAnswerMissing(state.answers.rfd3_select_fixed_atoms) &&
      resolvedRfd3Defaults.inferredSelectFixedAtoms
    ) {
      state.answers.rfd3_select_fixed_atoms = resolvedRfd3Defaults.inferredSelectFixedAtoms;
    }
    if (
      isAnswerMissing(state.answers.rfd3_partial_t) &&
      resolvedRfd3Defaults.rfd3Mode === "local_diversify"
    ) {
      state.answers.rfd3_partial_t = QUESTION_PRESETS.rfd3_partial_t?.default ?? 5.0;
    }

    const grid = document.createElement("div");
    grid.className = "parameter-board-grid option-board-grid";

    const createField = (question) => {
      const field = document.createElement("div");
      field.className = "parameter-field option-field expert-option";

      const label = document.createElement("div");
      label.className = "parameter-label";
      label.textContent = question.labelKey ? t(question.labelKey) : question.label || question.id || "input";

      const desc = document.createElement("div");
      desc.className = "parameter-help";
      desc.textContent = question.questionKey ? t(question.questionKey) : question.question || "";

      field.appendChild(label);
      field.appendChild(desc);
      return field;
    };

    const appendParsedInput = (field, question) => {
      const multiline = Boolean(question.multiline) || ANSWER_TEXTAREA_KEYS.has(question.id);
      const inputWrap = document.createElement("div");
      inputWrap.className = "input-row";
      const input = multiline ? document.createElement("textarea") : document.createElement("input");
      if (!multiline) {
        input.type = ANSWER_INT_KEYS.has(question.id) || ANSWER_FLOAT_KEYS.has(question.id) ? "number" : "text";
        if (ANSWER_FLOAT_KEYS.has(question.id)) input.step = "0.01";
        if (ANSWER_INT_KEYS.has(question.id)) input.step = "1";
      } else {
        input.rows = 3;
      }
      if (question.placeholder) input.placeholder = question.placeholder;
      if (state.answers[question.id] === undefined && question.default !== undefined) {
        state.answers[question.id] = question.default;
      }
      input.value = formatAnswerValue(state.answers[question.id]);

      const errorEl = document.createElement("div");
      errorEl.className = "question-error";
      const existingError = (state.answerMeta[question.id] || {}).error;
      if (existingError) {
        errorEl.textContent = existingError;
        errorEl.style.display = "block";
      } else {
        errorEl.style.display = "none";
      }

      input.addEventListener("input", () => {
        const parsed = parseAnswerValue(question.id, input.value);
        if (parsed.error) {
          state.answers[question.id] = "";
          state.answerMeta[question.id] = { ...state.answerMeta[question.id], error: parsed.error, raw: input.value };
          errorEl.textContent = parsed.error;
          errorEl.style.display = "block";
        } else {
          state.answers[question.id] = parsed.value;
          state.answerMeta[question.id] = { ...state.answerMeta[question.id], error: "", raw: input.value };
          errorEl.textContent = "";
          errorEl.style.display = "none";
        }
        updateRunEligibility(normalizedQuestions);
      });

      inputWrap.appendChild(input);
      field.appendChild(inputWrap);
      field.appendChild(errorEl);
    };

    fieldIds.forEach((fieldId) => {
      const question = normalizedQuestions.find((item) => item.id === fieldId) || normalizeQuestion({ id: fieldId }) || { id: fieldId };
      const field = createField(question);

      if (fieldId === "rfd3_mode") {
        const explicitMode = normalizeRfd3Mode(state.answers.rfd3_mode);
        const effectiveMode = explicitMode || effectiveSetupRfd3Mode(state.answers);
        const select = document.createElement("select");
        const autoOption = document.createElement("option");
        autoOption.value = "";
        autoOption.textContent = t("feedback.stage.auto");
        if (!explicitMode) autoOption.selected = true;
        select.appendChild(autoOption);
        RFD3_MODE_OPTIONS.forEach((item) => {
          const option = document.createElement("option");
          option.value = item.value;
          option.textContent = t(item.labelKey);
          if (explicitMode === item.value) option.selected = true;
          select.appendChild(option);
        });
        select.addEventListener("change", () => {
          const nextMode = normalizeRfd3Mode(select.value);
          if (nextMode) {
            state.answers.rfd3_mode = nextMode;
          } else {
            delete state.answers.rfd3_mode;
          }
          updateRunEligibility(normalizedQuestions);
          renderQuestions(state.plan?.questions || []);
        });
        field.appendChild(select);
        const note = document.createElement("div");
        note.className = "choice-note";
        const prefix = explicitMode ? "" : `${t("feedback.stage.auto")}: `;
        note.textContent = `${prefix}${t(rfd3ModeDescriptionKey(effectiveMode))}`;
        field.appendChild(note);
      } else if (fieldId === "rfd3_contig") {
        const { options: contigs, currentValue } = resolveRfd3ContigChoices({
          mode: state.runMode,
          answers: state.answers,
          nodes: setupWorkflowNodesForRfd3(),
          chainRanges: state.chainRanges || {},
          routedContig: state.plan?.routed_request?.rfd3_contig,
        });
        const current = String(currentValue || "").trim();
        if (current) {
          state.answers.rfd3_contig = current;
        }
        if (contigs.length) {
          const select = document.createElement("select");
          const noneOption = document.createElement("option");
          noneOption.value = "";
          noneOption.textContent = t("choice.contigNone");
          select.appendChild(noneOption);
          contigs.forEach((item) => {
            const option = document.createElement("option");
            option.value = item.value;
            option.textContent = item.label;
            if (current === item.value) option.selected = true;
            select.appendChild(option);
          });
          select.addEventListener("change", () => {
            state.answers.rfd3_contig = select.value;
            updateRunEligibility(normalizedQuestions);
          });
          field.appendChild(select);
          const note = document.createElement("div");
          note.className = "choice-note";
          note.textContent = t("choice.contigPositiveOnly");
          field.appendChild(note);
        } else {
          appendParsedInput(field, question);
          const note = document.createElement("div");
          note.className = "choice-note";
          note.textContent = t("choice.contigNote");
          field.appendChild(note);
        }
      } else if (fieldId === "rfd3_is_non_loopy") {
        let current = state.answers.rfd3_is_non_loopy;
        if (typeof current !== "boolean") {
          const routedDefault = state.plan?.routed_request?.rfd3_is_non_loopy;
          current = typeof routedDefault === "boolean" ? routedDefault : Boolean(question.default);
          state.answers.rfd3_is_non_loopy = current;
        }
        renderChoiceButtons(
          field,
          [
            { labelKey: "common.enabled", value: true },
            { labelKey: "common.disabled", value: false },
          ],
          current,
          (value) => {
            state.answers.rfd3_is_non_loopy = value;
            updateRunEligibility(normalizedQuestions);
          },
          { rerender: false }
        );
      } else {
        appendParsedInput(field, question);
      }

      grid.appendChild(field);
    });

    card.appendChild(grid);
  }

  choiceQuestions.forEach((q) => {
    if (compactChoiceQuestionIds.has(q.id) || SETUP_RFD3_MODE_DETAIL_IDS.has(q.id) || q.id === "evolution_mode") return;
    const card = document.createElement("div");
    card.className = buildQuestionCardClass(q, q.id === "run_mode" ? ["run-mode-card"] : []);

    const title = document.createElement("div");
    title.className = "question-title";
    title.textContent = q.labelKey ? t(q.labelKey) : q.label || q.id || "input";

    const help = document.createElement("div");
    help.className = "question-help";
    help.textContent = q.questionKey ? t(q.questionKey) : q.question || "";

    card.appendChild(title);
    card.appendChild(help);

    if (q.id === "run_mode") {
      const current = state.runMode || q.default || "pipeline";
      renderChoiceButtons(card, RUN_MODE_OPTIONS, current, (value) => {
        setRunMode(value, { render: false });
        updateRunEligibility(normalizedQuestions);
      });
      const detail = document.createElement("div");
      detail.className = "question-summary";
      detail.textContent = t("question.runMode.detail");
      card.appendChild(detail);
      const modeGuide = document.createElement("div");
      modeGuide.className = "mode-guide";
      const modeGuideTitle = document.createElement("div");
      modeGuideTitle.className = "mode-guide-title";
      modeGuideTitle.textContent = t("setup.modeGuide.title");
      modeGuide.appendChild(modeGuideTitle);
      const selectedOpt =
        RUN_MODE_OPTIONS.find((opt) => String(opt.value || "").trim() === current) || RUN_MODE_OPTIONS[0];
      if (selectedOpt) {
        const mode = String(selectedOpt.value || "").trim();
        const item = document.createElement("div");
        item.className = "mode-guide-item selected";
        const label = document.createElement("div");
        label.className = "mode-guide-label";
        label.textContent = labelFor(selectedOpt);
        const desc = document.createElement("div");
        desc.className = "mode-guide-desc";
        desc.textContent = t(`setup.modeGuide.${mode}`);
        item.appendChild(label);
        item.appendChild(desc);
        modeGuide.appendChild(item);
      }
      card.appendChild(modeGuide);
    }

    if (q.id === "start_from") {
      const routedDefault = state.plan?.routed_request?.start_from;
      const current = normalizePipelineStage(
        state.answers.start_from || routedDefault || q.default || "msa",
        "msa"
      );
      state.answers.start_from = current;
      renderChoiceButtons(
        card,
        [
          { labelKey: "stage.msa", value: "msa" },
          { labelKey: "stage.rfd3", value: "rfd3" },
          { labelKey: "stage.bioemu", value: "bioemu" },
          { labelKey: "stage.design", value: "design" },
          { labelKey: "stage.soluprot", value: "soluprot" },
          { labelKey: "stage.af2", value: "af2" },
          { labelKey: "stop.full", value: "novelty" },
        ],
        current,
        (value) => {
          state.answers.start_from = normalizePipelineStage(value, "msa");
          syncStartStopStages();
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "stop_after") {
      const routedDefault = state.plan?.routed_request?.stop_after;
      const current = normalizePipelineStage(
        state.answers.stop_after || routedDefault || q.default || "novelty",
        "novelty"
      );
      state.answers.stop_after = current;
      renderChoiceButtons(
        card,
        [
          { labelKey: "stage.msa", value: "msa" },
          { labelKey: "stage.rfd3", value: "rfd3" },
          { labelKey: "stage.bioemu", value: "bioemu" },
          { labelKey: "stage.design", value: "design" },
          { labelKey: "stage.soluprot", value: "soluprot" },
          { labelKey: "stage.af2", value: "af2" },
          { labelKey: "stop.full", value: "novelty" },
        ],
        current,
        (value) => {
          const selectedStop = normalizePipelineStage(value, "novelty");
          state.answers.stop_after = selectedStop;
          syncStartStopStages();
          if (selectedStop === "bioemu") {
            state.answers.bioemu_use = true;
          }
          state.answers.novelty_enabled = selectedStop === "novelty";
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "af2_provider") {
      const routedDefault = state.plan?.routed_request?.af2_provider;
      const current = String(state.answers.af2_provider || routedDefault || q.default || "colabfold")
        .trim()
        .toLowerCase();
      state.answers.af2_provider = normalizeAf2Provider(current);
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.af2Provider.colabfold", value: "colabfold" },
          { labelKey: "choice.af2Provider.af2", value: "af2" },
        ],
        state.answers.af2_provider,
        (value) => {
          state.answers.af2_provider = normalizeAf2Provider(value);
          refreshAf2ProviderLabels({ rerenderQuestions: true });
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "rfd3_use") {
      let current = state.answers.rfd3_use;
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.rfd3_use;
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else {
          current = q.default !== undefined ? Boolean(q.default) : false;
        }
        state.answers.rfd3_use = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.rfd3Use.on", value: true },
          { labelKey: "choice.rfd3Use.off", value: false },
        ],
        current,
        (value) => {
          state.answers.rfd3_use = value;
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "design_chains") {
      const chains = state.chainRanges ? Object.keys(state.chainRanges) : [];
      let current = Array.isArray(state.answers.design_chains) ? state.answers.design_chains : [];
      const routedDefault = state.plan?.routed_request?.design_chains;
      if (!current.length && Array.isArray(routedDefault) && routedDefault.length) {
        current = routedDefault;
        state.answers.design_chains = current;
      }
      const group = document.createElement("div");
      group.className = "choice-group";

      const allBtn = document.createElement("button");
      allBtn.type = "button";
      allBtn.className = "choice-btn" + (current.length === 0 ? " selected" : "");
      allBtn.textContent = t("choice.allChains");
      allBtn.addEventListener("click", () => {
        state.answers.design_chains = [];
        updateRunEligibility(normalizedQuestions);
        renderQuestions(state.plan?.questions || []);
      });
      group.appendChild(allBtn);

      chains.forEach((chain) => {
        const btn = document.createElement("button");
        btn.type = "button";
        btn.className = "choice-btn" + (current.includes(chain) ? " selected" : "");
        btn.textContent = chain;
        btn.addEventListener("click", () => {
          const next = new Set(current);
          if (next.has(chain)) {
            next.delete(chain);
          } else {
            next.add(chain);
          }
          state.answers.design_chains = Array.from(next);
          updateRunEligibility(normalizedQuestions);
          renderQuestions(state.plan?.questions || []);
        });
        group.appendChild(btn);
      });

      card.appendChild(group);

      if (chains.length) {
        const note = document.createElement("div");
        note.className = "choice-note";
        note.textContent = t("choice.chainDefaultNote");
        card.appendChild(note);
      } else {
        const note = document.createElement("div");
        note.className = "choice-note";
        note.textContent = t("choice.chainNote");
        card.appendChild(note);
      }
    }

    if (q.id === "pdb_strip_nonpositive_resseq") {
      let current = state.answers.pdb_strip_nonpositive_resseq;
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.pdb_strip_nonpositive_resseq;
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else {
          current = q.default !== undefined ? Boolean(q.default) : true;
        }
        state.answers.pdb_strip_nonpositive_resseq = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.stripNonpositive.on", value: true },
          { labelKey: "choice.stripNonpositive.off", value: false },
        ],
        current,
        (value) => {
          state.answers.pdb_strip_nonpositive_resseq = value;
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "wt_compare") {
      let current = state.answers.wt_compare;
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.wt_compare;
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else {
          current = q.default !== undefined ? Boolean(q.default) : true;
        }
        state.answers.wt_compare = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.wtCompare.on", value: true },
          { labelKey: "choice.wtCompare.off", value: false },
        ],
        current,
        (value) => {
          state.answers.wt_compare = value;
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "mask_consensus_apply") {
      let current = state.answers.mask_consensus_apply;
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.mask_consensus_apply;
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else {
          current = q.default !== undefined ? Boolean(q.default) : true;
        }
        state.answers.mask_consensus_apply = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.maskConsensusApply.on", value: true },
          { labelKey: "choice.maskConsensusApply.off", value: false },
        ],
        current,
        (value) => {
          state.answers.mask_consensus_apply = value;
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "ligand_mask_use_original_target") {
      let current = state.answers.ligand_mask_use_original_target;
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.ligand_mask_use_original_target;
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else {
          current = q.default !== undefined ? Boolean(q.default) : true;
        }
        state.answers.ligand_mask_use_original_target = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.ligandMaskOriginal.on", value: true },
          { labelKey: "choice.ligandMaskOriginal.off", value: false },
        ],
        current,
        (value) => {
          state.answers.ligand_mask_use_original_target = value;
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "bioemu_use") {
      let current = state.answers.bioemu_use;
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.bioemu_use;
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else {
          current = q.default !== undefined ? Boolean(q.default) : false;
        }
        state.answers.bioemu_use = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.bioemuUse.on", value: true },
          { labelKey: "choice.bioemuUse.off", value: false },
        ],
        current,
        (value) => {
          state.answers.bioemu_use = value;
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "novelty_enabled") {
      let current = state.answers.novelty_enabled;
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.novelty_enabled;
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else {
          current = q.default !== undefined ? Boolean(q.default) : false;
        }
        state.answers.novelty_enabled = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.novelty.on", value: true },
          { labelKey: "choice.novelty.off", value: false },
        ],
        current,
        (value) => {
          state.answers.novelty_enabled = value;
          if (value) {
            state.answers.stop_after = "novelty";
          } else if (String(state.answers.stop_after || "").trim().toLowerCase() === "novelty") {
            state.answers.stop_after = "af2";
          }
          syncStartStopStages();
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "relax_enabled") {
      let current = state.answers.relax_enabled;
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.relax_enabled;
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else {
          current = q.default !== undefined ? Boolean(q.default) : false;
        }
        state.answers.relax_enabled = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.relax.on", value: true },
          { labelKey: "choice.relax.off", value: false },
        ],
        current,
        (value) => {
          state.answers.relax_enabled = value;
          updateRunEligibility(normalizedQuestions);
          renderQuestions(state.plan?.questions || []);
        }
      );
    }

    if (q.id === "confirm_run") {
      let current = state.answers.confirm_run;
      if (typeof current !== "boolean") {
        current = q.default !== undefined ? Boolean(q.default) : true;
        state.answers.confirm_run = current;
      }
      renderChoiceButtons(
        card,
        [
          { labelKey: "choice.confirmRun.no", value: false },
          { labelKey: "choice.confirmRun.yes", value: true },
        ],
        current,
        (value) => {
          state.answers.confirm_run = value;
          updateRunEligibility(normalizedQuestions);
        }
      );
    }

    if (q.id === "rfd3_contig") {
      const rfd3Active = setupRunEnablesRfd3Stage(state.answers) || shouldShowSetupRfd3InputField();
      const currentMode = effectiveSetupRfd3Mode(state.answers);
      const { options: contigs, currentValue } = resolveRfd3ContigChoices({
        mode: state.runMode,
        answers: state.answers,
        nodes: setupWorkflowNodesForRfd3(),
        chainRanges: state.chainRanges || {},
        routedContig: state.plan?.routed_request?.rfd3_contig,
      });
      if (contigs.length) {
        let current = String(state.answers.rfd3_contig || "").trim();
        if (!current && rfd3Active && rfd3ModeUsesContig(currentMode)) {
          current = String(currentValue || "").trim();
          if (current) {
            state.answers.rfd3_contig = current;
          }
        }
        const options = [{ labelKey: "choice.contigNone", value: "" }, ...contigs];
        renderChoiceButtons(card, options, current || "", (value) => {
          state.answers.rfd3_contig = value;
          updateRunEligibility(normalizedQuestions);
        });
        const note = document.createElement("div");
        note.className = "choice-note";
        note.textContent = t("choice.contigPositiveOnly");
        card.appendChild(note);
      } else {
        const note = document.createElement("div");
        note.className = "choice-note";
        note.textContent = t("choice.contigNote");
        card.appendChild(note);
      }
    }

    appendConfigCard(card);
  });

  const appendCompactOptionBoard = () => {
    const optionQuestions = choiceQuestions.filter((q) => compactChoiceQuestionIds.has(q.id));
    if (!optionQuestions.length) return;
    const questionById = new Map(optionQuestions.map((q) => [q.id, q]));

    const ensureBooleanAnswer = (q, fallback = false) => {
      if (!q) return fallback;
      let current = state.answers[q.id];
      if (typeof current !== "boolean") {
        const routedDefault = state.plan?.routed_request?.[q.id];
        if (typeof routedDefault === "boolean") {
          current = routedDefault;
        } else if (q.default !== undefined) {
          current = Boolean(q.default);
        } else {
          current = fallback;
        }
        state.answers[q.id] = current;
        mirrorSetupRoutedAnswer(q.id, current);
      }
      return Boolean(current);
    };

    const card = document.createElement("div");
    card.className = "question-card parameter-board option-board";

    const optionBoardTitleKey =
      setupWizardStepId === "workflow"
        ? "setup.workflowBoard.title"
        : setupWizardStepId === "criteria"
          ? "setup.criteria.title"
          : "setup.options.title";
    const optionBoardHelpKey =
      setupWizardStepId === "workflow"
        ? "setup.workflowBoard.help"
        : setupWizardStepId === "criteria"
          ? "setup.criteria.help"
          : "setup.options.help";

    const title = document.createElement("div");
    title.className = "question-title";
    title.textContent = t(optionBoardTitleKey);

    const help = document.createElement("div");
    help.className = "question-help";
    help.textContent = t(optionBoardHelpKey);

    const grid = document.createElement("div");
    grid.className = "parameter-board-grid option-board-grid";

    const appendOptionField = (q, buildControls) => {
      if (!q) return;
      const field = document.createElement("div");
      field.className = "parameter-field option-field" + (q.required ? " required" : "");

      const label = document.createElement("div");
      label.className = "parameter-label";
      label.textContent = q.labelKey ? t(q.labelKey) : q.label || q.id || "option";

      const desc = document.createElement("div");
      desc.className = "parameter-help";
      desc.textContent = q.questionKey ? t(q.questionKey) : q.question || "";

      field.appendChild(label);
      field.appendChild(desc);
      buildControls(field, q);
      grid.appendChild(field);
    };

    const renderBooleanField = ({
      id,
      fallback,
      onLabelKey,
      offLabelKey,
      onLabel,
      offLabel,
      onChange,
      rerender = false,
    }) => {
      const q = questionById.get(id);
      if (!q) return;
      const current = ensureBooleanAnswer(q, fallback);
      appendOptionField(q, (field) => {
        renderChoiceButtons(
          field,
          [
            onLabelKey ? { labelKey: onLabelKey, value: true } : { label: onLabel || "On", value: true },
            offLabelKey ? { labelKey: offLabelKey, value: false } : { label: offLabel || "Off", value: false },
          ],
          current,
          (value) => {
            state.answers[id] = value;
            mirrorSetupRoutedAnswer(id, value);
            if (onChange) onChange(value);
            updateRunEligibility(normalizedQuestions);
          },
          { rerender }
        );
      });
    };

    renderBooleanField({
      id: "novelty_enabled",
      fallback: true,
      onLabelKey: "choice.novelty.on",
      offLabelKey: "choice.novelty.off",
      onChange: (value) => {
        if (value) {
          state.answers.stop_after = "novelty";
        } else if (String(state.answers.stop_after || "").trim().toLowerCase() === "novelty") {
          state.answers.stop_after = "af2";
        }
        syncStartStopStages();
      },
      rerender: false,
    });

    renderBooleanField({
      id: "rfd3_use",
      fallback: false,
      onLabelKey: "choice.rfd3Use.on",
      offLabelKey: "choice.rfd3Use.off",
      rerender: false,
    });

    renderBooleanField({
      id: "bioemu_use",
      fallback: false,
      onLabelKey: "choice.bioemuUse.on",
      offLabelKey: "choice.bioemuUse.off",
      rerender: false,
    });

    renderBooleanField({
      id: "relax_enabled",
      fallback: true,
      onLabelKey: "choice.relax.on",
      offLabelKey: "choice.relax.off",
      rerender: false,
    });


    renderBooleanField({
      id: "bioemu_filter_samples",
      fallback: true,
      onLabel: "Enabled",
      offLabel: "Disabled",
      rerender: false,
    });

    const af2Question = questionById.get("af2_provider");
    if (af2Question) {
      const routedDefault = state.plan?.routed_request?.af2_provider;
      const current = String(state.answers.af2_provider || routedDefault || af2Question.default || "colabfold")
        .trim()
        .toLowerCase();
      state.answers.af2_provider = normalizeAf2Provider(current);
      appendOptionField(af2Question, (field) => {
        renderChoiceButtons(
          field,
          [
            { labelKey: "choice.af2Provider.colabfold", value: "colabfold" },
            { labelKey: "choice.af2Provider.af2", value: "af2" },
          ],
          state.answers.af2_provider,
          (value) => {
            state.answers.af2_provider = normalizeAf2Provider(value);
            refreshAf2ProviderLabels({ rerenderQuestions: true });
            updateRunEligibility(normalizedQuestions);
          },
          { rerender: false }
        );
      });
    }

    const designChainsQuestion = questionById.get("design_chains");
    if (designChainsQuestion) {
      appendOptionField(designChainsQuestion, (field) => {
        const chains = state.chainRanges ? Object.keys(state.chainRanges) : [];
        let current = Array.isArray(state.answers.design_chains) ? state.answers.design_chains : [];
        const routedDefault = state.plan?.routed_request?.design_chains;
        if (!current.length && Array.isArray(routedDefault) && routedDefault.length) {
          current = routedDefault;
          state.answers.design_chains = current;
        }

        const group = document.createElement("div");
        group.className = "choice-group";

        const allBtn = document.createElement("button");
        allBtn.type = "button";
        allBtn.className = "choice-btn" + (current.length === 0 ? " selected" : "");
        allBtn.textContent = t("choice.allChains");
        allBtn.addEventListener("click", () => {
          state.answers.design_chains = [];
          updateRunEligibility(normalizedQuestions);
          renderQuestions(state.plan?.questions || []);
        });
        group.appendChild(allBtn);

        chains.forEach((chain) => {
          const btn = document.createElement("button");
          btn.type = "button";
          btn.className = "choice-btn" + (current.includes(chain) ? " selected" : "");
          btn.textContent = chain;
          btn.addEventListener("click", () => {
            const next = new Set(current);
            if (next.has(chain)) {
              next.delete(chain);
            } else {
              next.add(chain);
            }
            state.answers.design_chains = Array.from(next);
            updateRunEligibility(normalizedQuestions);
            renderQuestions(state.plan?.questions || []);
          });
          group.appendChild(btn);
        });
        field.appendChild(group);

        const note = document.createElement("div");
        note.className = "choice-note";
        note.textContent = chains.length ? t("choice.chainDefaultNote") : t("choice.chainNote");
        field.appendChild(note);
      });
    }

    const selectedTiersQuestion = questionById.get("selected_tiers");
    if (selectedTiersQuestion) {
      appendOptionField(selectedTiersQuestion, (field) => {
        const current = currentSetupSelectedTiers(selectedTiersQuestion);
        renderChoiceButtons(
          field,
          FAST_SELECTED_TIER_VALUES.map((value) => ({
            label: formatConservationTierValue(value),
            value,
          })),
          current,
          (value) => {
            const normalizedValue = normalizeConservationTier(value);
            if (normalizedValue === null) return;
            const next = new Set(current.map((item) => String(item)));
            const key = String(normalizedValue);
            if (next.has(key)) {
              if (next.size <= 1) return;
              next.delete(key);
            } else {
              next.add(key);
            }
            state.answers.selected_tiers = Array.from(next)
              .map((item) => Number.parseFloat(item))
              .filter((item) => Number.isFinite(item))
              .sort((left, right) => left - right);
            mirrorSetupRoutedAnswer("selected_tiers", [...state.answers.selected_tiers]);
            updateRunEligibility(normalizedQuestions);
          },
          { multi: true }
        );
      });
    }

    renderBooleanField({
      id: "pdb_strip_nonpositive_resseq",
      fallback: true,
      onLabelKey: "choice.stripNonpositive.on",
      offLabelKey: "choice.stripNonpositive.off",
      rerender: false,
    });

    renderBooleanField({
      id: "wt_compare",
      fallback: false,
      onLabelKey: "choice.wtCompare.on",
      offLabelKey: "choice.wtCompare.off",
      rerender: false,
    });

    renderBooleanField({
      id: "mask_consensus_apply",
      fallback: false,
      onLabelKey: "choice.maskConsensusApply.on",
      offLabelKey: "choice.maskConsensusApply.off",
      rerender: false,
    });

    card.appendChild(title);
    card.appendChild(help);
    card.appendChild(grid);
    appendConfigCard(card);
  };

  const appendEvolutionBoard = () => {
    const evolutionIds = ["evolution_mode", "evolution_pool_size", "evolution_initial_samples", "evolution_oracle_samples", "evolution_rounds", "evolution_samples_per_round"];
    const evolutionQuestions = normalizedQuestions.filter((q) => evolutionIds.includes(q.id));
    if (!evolutionQuestions.length) return;

    const card = document.createElement("div");
    card.className = "question-card parameter-board evolution-board";

    const title = document.createElement("div");
    title.className = "question-title";
    title.textContent = t("setup.evolution.title");

    const help = document.createElement("div");
    help.className = "question-help";
    help.textContent = t("setup.evolution.help");

    const grid = document.createElement("div");
    grid.className = "parameter-board-grid option-board-grid";

    const modeQuestion = evolutionQuestions.find(q => q.id === "evolution_mode");
    if (modeQuestion) {
      const field = document.createElement("div");
      field.className = "parameter-field option-field";
      const label = document.createElement("div");
      label.className = "parameter-label";
      label.textContent = t(modeQuestion.labelKey);
      const desc = document.createElement("div");
      desc.className = "parameter-help";
      desc.textContent = t(modeQuestion.questionKey);
      field.appendChild(label);
      field.appendChild(desc);

      let current = state.answers.evolution_mode;
      if (typeof current !== "boolean") {
        current = Boolean(modeQuestion.default);
        state.answers.evolution_mode = current;
      }

      renderChoiceButtons(field, [
        { label: "On", value: true },
        { label: "Off", value: false }
      ], current, (value) => {
        state.answers.evolution_mode = value;
        updateRunEligibility(normalizedQuestions);
        renderQuestions(state.plan?.questions || []);
      }, { rerender: false });
      grid.appendChild(field);
    }

    if (state.answers.evolution_mode === true) {
      evolutionQuestions.filter(q => q.id !== "evolution_mode").forEach(q => {
        const field = document.createElement("div");
        field.className = "parameter-field option-field";
        const label = document.createElement("div");
        label.className = "parameter-label";
        label.textContent = t(q.labelKey);
        const desc = document.createElement("div");
        desc.className = "parameter-help";
        desc.textContent = t(q.questionKey);
        field.appendChild(label);
        field.appendChild(desc);

        const inputWrap = document.createElement("div");
        inputWrap.className = "input-row";
        const input = document.createElement("input");
        input.type = "number";
        input.step = "1";
        if (state.answers[q.id] === undefined) {
          state.answers[q.id] = q.default;
        }
        input.value = state.answers[q.id];
        input.addEventListener("input", () => {
          state.answers[q.id] = parseInt(input.value, 10) || 0;
          updateRunEligibility(normalizedQuestions);
        });
        inputWrap.appendChild(input);
        field.appendChild(inputWrap);
        grid.appendChild(field);
      });
    }

    card.appendChild(title);
    card.appendChild(help);
    card.appendChild(grid);
    appendConfigCard(card);
  };

  appendCompactOptionBoard();
  appendEvolutionBoard();

  const bioemuCountQuestionIds = new Set(["bioemu_max_return_structures", "bioemu_num_samples"]);
  const rfd3CountQuestionIds = new Set(["rfd3_max_return_designs"]);
  const compactParameterQuestionIds = new Set([
    "compare_rmsd_scope",
    "bioemu_max_return_structures",
    "bioemu_num_samples",
    "rfd3_max_return_designs",
    "num_seq_per_tier",
    "af2_max_candidates_per_tier",
    "af2_plddt_cutoff",
    "af2_rmsd_cutoff",
    "relax_score_per_residue_cutoff",
  ]);
  const compactParameterPriority = {
    compare_rmsd_scope: 5,
    bioemu_max_return_structures: 10,
    bioemu_num_samples: 20,
    rfd3_max_return_designs: 30,
    num_seq_per_tier: 40,
    af2_max_candidates_per_tier: 50,
    af2_plddt_cutoff: 60,
    af2_rmsd_cutoff: 70,
    evolution_pool_size: 79,
    evolution_initial_samples: 80,
    evolution_oracle_samples: 81,
    evolution_rounds: 82,
    evolution_samples_per_round: 83,
  };
  const bioemuCountRelevant =
    state.runMode === "pipeline" ||
    state.runMode === "workflow" ||
    state.runMode === "bioemu" ||
    state.runMode === "design" ||
    state.runMode === "soluprot" ||
    state.answers.bioemu_use === true ||
    state.answers.stop_after === "bioemu";
  const rfd3CountRelevant =
    state.runMode === "rfd3" ||
    state.answers.stop_after === "rfd3" ||
    setupRunEnablesRfd3Stage() ||
    shouldShowSetupRfd3InputField();

  const compactQuestions = textQuestions
    .filter((q) => compactParameterQuestionIds.has(q.id))
    .filter((q) => q.id !== "relax_score_per_residue_cutoff" || state.answers.relax_enabled === true)
    .filter((q) => !["evolution_pool_size", "evolution_initial_samples", "evolution_oracle_samples", "evolution_rounds", "evolution_samples_per_round"].includes(q.id) || state.answers.evolution_mode === true)
    .sort((left, right) => {
      const leftPriority = compactParameterPriority[left.id] ?? Number.MAX_SAFE_INTEGER;
      const rightPriority = compactParameterPriority[right.id] ?? Number.MAX_SAFE_INTEGER;
      if (leftPriority !== rightPriority) return leftPriority - rightPriority;
      return String(left.id || "").localeCompare(String(right.id || ""));
    });

  const advancedConstraintQuestionIds = new Set([
    "bioemu_target_rmsd_cutoff",
    "bioemu_steering_config_text",
    "rfd3_target_rmsd_cutoff",
    "fixed_positions_extra",
  ]);
  const advancedConstraintPriority = {
    bioemu_target_rmsd_cutoff: 10,
    bioemu_steering_config_text: 20,
    rfd3_target_rmsd_cutoff: 30,
    fixed_positions_extra: 40,
  };
  const advancedConstraintQuestions = textQuestions
    .filter((q) => advancedConstraintQuestionIds.has(q.id))
    .sort((left, right) => {
      const leftPriority = advancedConstraintPriority[left.id] ?? Number.MAX_SAFE_INTEGER;
      const rightPriority = advancedConstraintPriority[right.id] ?? Number.MAX_SAFE_INTEGER;
      if (leftPriority !== rightPriority) return leftPriority - rightPriority;
      return String(left.id || "").localeCompare(String(right.id || ""));
    });

  const appendCompactParameterBoard = (questionsForBoard) => {
    if (!questionsForBoard.length) return;
    const card = document.createElement("div");
    card.className = "question-card parameter-board";

    const parameterBoardTitleKey =
      setupWizardStepId === "criteria" ? "setup.criteria.parameters.title" : "setup.parameters.title";
    const parameterBoardHelpKey =
      setupWizardStepId === "criteria" ? "setup.criteria.parameters.help" : "setup.parameters.help";

    const title = document.createElement("div");
    title.className = "question-title";
    title.textContent = t(parameterBoardTitleKey);

    const help = document.createElement("div");
    help.className = "question-help";
    help.textContent = t(parameterBoardHelpKey);

    const grid = document.createElement("div");
    grid.className = "parameter-board-grid";

    questionsForBoard.forEach((q) => {
      const field = document.createElement("label");
      field.className = "parameter-field" + (q.required ? " required" : "");
      const inactive =
        (bioemuCountQuestionIds.has(q.id) && !bioemuCountRelevant) ||
        (rfd3CountQuestionIds.has(q.id) && !rfd3CountRelevant);
      if (inactive) field.classList.add("inactive");

      const fieldLabel = document.createElement("span");
      fieldLabel.className = "parameter-label";
      fieldLabel.textContent = q.labelKey ? t(q.labelKey) : q.label || q.id || "input";

      const fieldHelp = document.createElement("span");
      fieldHelp.className = "parameter-help";
      fieldHelp.textContent = q.questionKey ? t(q.questionKey) : q.question || "";

      if (state.answers[q.id] === undefined && q.default !== undefined) {
        state.answers[q.id] = q.default;
      }

      let input = null;
      if (q.id === "compare_rmsd_scope") {
        state.answers[q.id] = normalizeCompareRmsdScope(state.answers[q.id] || q.default);
        input = document.createElement("select");
        [
          { labelKey: "choice.compareRmsdScope.off", value: "off" },
          { labelKey: "choice.compareRmsdScope.input", value: "input" },
          { labelKey: "choice.compareRmsdScope.backbone", value: "backbone" },
          { labelKey: "choice.compareRmsdScope.both", value: "both" },
        ].forEach((optionDef) => {
          const option = document.createElement("option");
          option.value = optionDef.value;
          option.textContent = t(optionDef.labelKey);
          if (state.answers[q.id] === optionDef.value) option.selected = true;
          input.appendChild(option);
        });
      } else {
        input = document.createElement("input");
        input.type = ANSWER_INT_KEYS.has(q.id) || ANSWER_FLOAT_KEYS.has(q.id) ? "number" : "text";
        if (ANSWER_FLOAT_KEYS.has(q.id)) input.step = "0.01";
        if (ANSWER_INT_KEYS.has(q.id)) input.step = "1";
        if (q.id === "af2_plddt_cutoff") {
          input.min = "0";
          input.max = "100";
          input.step = "0.1";
        } else if (q.id === "af2_rmsd_cutoff") {
          input.min = "0.01";
          input.step = "0.01";
        }
        if (q.placeholder) {
          input.placeholder = q.placeholder;
        }
        input.value = formatAnswerValue(state.answers[q.id]);
      }
      input.disabled = inactive;

      const errorEl = document.createElement("span");
      errorEl.className = "parameter-error";
      const existingError = (state.answerMeta[q.id] || {}).error;
      if (existingError) {
        errorEl.textContent = existingError;
      } else {
        errorEl.textContent = "";
      }

      input.addEventListener("input", () => {
        if (q.id === "compare_rmsd_scope") {
          state.answers[q.id] = normalizeCompareRmsdScope(input.value || q.default);
          state.answerMeta[q.id] = { ...state.answerMeta[q.id], error: "", raw: input.value };
          errorEl.textContent = "";
          updateRunEligibility(normalizedQuestions);
          return;
        }
        const parsed = parseAnswerValue(q.id, input.value);
        if (parsed.error) {
          state.answers[q.id] = "";
          state.answerMeta[q.id] = { ...state.answerMeta[q.id], error: parsed.error, raw: input.value };
          errorEl.textContent = parsed.error;
        } else {
          state.answers[q.id] = parsed.value;
          state.answerMeta[q.id] = { ...state.answerMeta[q.id], error: "", raw: input.value };
          errorEl.textContent = "";
        }
        updateRunEligibility(normalizedQuestions);
      });

      field.appendChild(fieldLabel);
      field.appendChild(fieldHelp);
      field.appendChild(input);
      if (inactive) {
        const inactiveHint = document.createElement("span");
        inactiveHint.className = "parameter-help inactive";
        inactiveHint.textContent = t("setup.parameters.inactive");
        field.appendChild(inactiveHint);
      }
      field.appendChild(errorEl);
      grid.appendChild(field);
    });

    card.appendChild(title);
    card.appendChild(help);
    card.appendChild(grid);
    appendConfigCard(card);
  };

  appendCompactParameterBoard(compactQuestions);

  const appendAdvancedConstraintBoard = () => {
    if (!advancedConstraintQuestions.length) return;
    const card = document.createElement("div");
    card.className = "question-card parameter-board option-board";

    const title = document.createElement("div");
    title.className = "question-title";
    title.textContent = t("setup.constraints.title");

    const help = document.createElement("div");
    help.className = "question-help";
    help.textContent = t("setup.constraints.help");

    const grid = document.createElement("div");
    grid.className = "parameter-board-grid option-board-grid";

    advancedConstraintQuestions.forEach((q) => {
      const field = document.createElement("div");
      field.className = "parameter-field option-field expert-option" + (q.required ? " required" : "");

      const label = document.createElement("div");
      label.className = "parameter-label";
      label.textContent = q.labelKey ? t(q.labelKey) : q.label || q.id || "input";

      const desc = document.createElement("div");
      desc.className = "parameter-help";
      desc.textContent = q.questionKey ? t(q.questionKey) : q.question || "";

      const inputWrap = document.createElement("div");
      inputWrap.className = "input-row";

      const multiline = Boolean(q.multiline) || ANSWER_TEXTAREA_KEYS.has(q.id);
      const input = multiline ? document.createElement("textarea") : document.createElement("input");
      if (!multiline) {
        input.type = ANSWER_INT_KEYS.has(q.id) || ANSWER_FLOAT_KEYS.has(q.id) ? "number" : "text";
        if (ANSWER_FLOAT_KEYS.has(q.id)) input.step = "0.01";
        if (ANSWER_INT_KEYS.has(q.id)) input.step = "1";
      } else {
        input.rows = 3;
      }
      if (q.placeholder) {
        input.placeholder = q.placeholder;
      }
      if (state.answers[q.id] === undefined && q.default !== undefined) {
        state.answers[q.id] = q.default;
      }
      input.value = formatAnswerValue(state.answers[q.id]);

      const errorEl = document.createElement("div");
      errorEl.className = "question-error";
      const existingError = (state.answerMeta[q.id] || {}).error;
      if (existingError) {
        errorEl.textContent = existingError;
        errorEl.style.display = "block";
      } else {
        errorEl.style.display = "none";
      }

      input.addEventListener("input", () => {
        const parsed = parseAnswerValue(q.id, input.value);
        if (parsed.error) {
          state.answers[q.id] = "";
          state.answerMeta[q.id] = { ...state.answerMeta[q.id], error: parsed.error, raw: input.value };
          errorEl.textContent = parsed.error;
          errorEl.style.display = "block";
        } else {
          state.answers[q.id] = parsed.value;
          state.answerMeta[q.id] = { ...state.answerMeta[q.id], error: "", raw: input.value };
          errorEl.textContent = "";
          errorEl.style.display = "none";
        }
        updateRunEligibility(normalizedQuestions);
      });

      inputWrap.appendChild(input);
      field.appendChild(label);
      field.appendChild(desc);
      field.appendChild(inputWrap);
      field.appendChild(errorEl);
      grid.appendChild(field);
    });

    card.appendChild(title);
    card.appendChild(help);
    card.appendChild(grid);
    appendConfigCard(card);
  };

  appendAdvancedConstraintBoard();

  const appendRfd3DetailBoard = () => {
    if (setupWizardActive && setupWizardStepId !== "expert") return;
    const rfd3DetailRelevant =
      state.runMode === "rfd3" || setupRunEnablesRfd3Stage() || shouldShowSetupRfd3InputField();
    if (!rfd3DetailRelevant) return;
    const card = document.createElement("div");
    card.className = "question-card parameter-board option-board";

    const title = document.createElement("div");
    title.className = "question-title";
    title.textContent = t("setup.rfd3.detail.title");

    const help = document.createElement("div");
    help.className = "question-help";
    help.textContent = t("setup.rfd3.detail.help");

    card.appendChild(title);
    card.appendChild(help);
    renderSetupRfd3ModeDetailsCard(card, normalizedQuestions);
    appendConfigCard(card);
  };

  appendRfd3DetailBoard();

  function appendWorkflowDesignerCard() {
    if (state.runMode !== "workflow") return;
    appendConfigCard(
      buildWorkflowDesignerCard({
        onLaunch: async () => {
          await runPipeline();
        },
        rerender: () => {
          renderQuestions(state.plan?.questions || []);
        },
      })
    );
  }

  appendWorkflowDesignerCard();

  function appendTextQuestionCard(q) {
    const card = document.createElement("div");
    card.className = buildQuestionCardClass(q);

    const title = document.createElement("div");
    title.className = "question-title";
    title.textContent = q.labelKey ? t(q.labelKey) : q.label || q.id || "input";

    const help = document.createElement("div");
    help.className = "question-help";
    help.textContent = q.questionKey ? t(q.questionKey) : q.question || "";

    const inputWrap = document.createElement("div");
    inputWrap.className = "input-row";
    const multiline = Boolean(q.multiline) || ANSWER_TEXTAREA_KEYS.has(q.id);

    const input = multiline ? document.createElement("textarea") : document.createElement("input");
    if (!multiline) {
      input.type = ANSWER_INT_KEYS.has(q.id) || ANSWER_FLOAT_KEYS.has(q.id) ? "number" : "text";
      if (ANSWER_FLOAT_KEYS.has(q.id)) input.step = "0.01";
      if (ANSWER_INT_KEYS.has(q.id)) input.step = "1";
      if (q.id === "af2_plddt_cutoff") {
        input.min = "0";
        input.max = "100";
        input.step = "0.1";
      } else if (q.id === "af2_rmsd_cutoff") {
        input.min = "0.01";
        input.step = "0.01";
      }
    }
    if (multiline) {
      input.rows = 3;
    }
    if (q.placeholder) {
      input.placeholder = q.placeholder;
    }

    if (state.answers[q.id] === undefined && q.default !== undefined) {
      state.answers[q.id] = q.default;
    }
    input.value = formatAnswerValue(state.answers[q.id]);

    const errorEl = document.createElement("div");
    errorEl.className = "question-error";
    const existingError = (state.answerMeta[q.id] || {}).error;
    if (existingError) {
      errorEl.textContent = existingError;
      errorEl.style.display = "block";
    } else {
      errorEl.style.display = "none";
    }

    input.addEventListener("input", () => {
      const parsed = parseAnswerValue(q.id, input.value);
      if (parsed.error) {
        state.answers[q.id] = "";
        state.answerMeta[q.id] = { ...state.answerMeta[q.id], error: parsed.error, raw: input.value };
        errorEl.textContent = parsed.error;
        errorEl.style.display = "block";
      } else {
        state.answers[q.id] = parsed.value;
        state.answerMeta[q.id] = { ...state.answerMeta[q.id], error: "", raw: input.value };
        errorEl.textContent = "";
        errorEl.style.display = "none";
      }
      updateRunEligibility(normalizedQuestions);
    });

    inputWrap.appendChild(input);
    card.appendChild(title);
    card.appendChild(help);
    card.appendChild(inputWrap);
    card.appendChild(errorEl);
    appendConfigCard(card);
    return card;
  }

  const hiddenTextQuestionIds = new Set([
    ...compactQuestions.map((q) => q.id),
    ...advancedConstraintQuestions.map((q) => q.id),
  ]);
  textQuestions.forEach((q) => {
    if (hiddenTextQuestionIds.has(q.id) || SETUP_RFD3_MODE_DETAIL_IDS.has(q.id)) return;
    appendTextQuestionCard(q);
  });

  const setupTargetPdbText = getTargetInputPdbText();
  const setupRfd3Active = setupRunUsesRfd3Stage();
  const showSetupRfd3InputItem = shouldShowSetupRfd3InputField();
  const visibleFileQuestions = fileQuestions.filter(
    (q) => q.id !== "rfd3_input_pdb" || showSetupRfd3InputItem
  );

  if (visibleFileQuestions.length) {
    const card = document.createElement("div");
    card.className = "question-card attachments";

    const title = document.createElement("div");
    title.className = "question-title";
    title.textContent = t("attachment.title");

    const help = document.createElement("div");
    help.className = "question-help";
    help.textContent = t("attachment.help");

    const list = document.createElement("div");
    list.className = "attachment-list";

    if (state.runMode !== "rfd3" && setupTargetPdbText && (setupRfd3Active || showSetupRfd3InputItem)) {
      const notice = document.createElement("div");
      notice.className = "question-summary";
      notice.textContent = showSetupRfd3InputItem
        ? t("setup.rfd3.defaultFromTargetOverride")
        : t("setup.rfd3.defaultFromTarget");
      card.appendChild(notice);

      const noticeActions = document.createElement("div");
      noticeActions.className = "file-controls";
      const toggleBtn = document.createElement("button");
      toggleBtn.type = "button";
      toggleBtn.className = "ghost";
      toggleBtn.textContent = showSetupRfd3InputItem
        ? t("setup.rfd3.useTargetDefault")
        : t("setup.rfd3.useSeparateInput");
      toggleBtn.addEventListener("click", () => {
        state.answers.rfd3_input_pdb = "";
        state.answerMeta.rfd3_input_pdb = {};
        if (!showSetupRfd3InputItem) {
          state.answers.rfd3_use = true;
        }
        setSetupRfd3InputOverrideVisible(!showSetupRfd3InputItem);
        if (state.setupResiduePicker.sourceKey === "rfd3_input_pdb") {
          resetSetupResiduePicker();
        }
        refreshChainRangesFromAnswers();
        renderQuestions(state.plan?.questions || []);
      });
      noticeActions.appendChild(toggleBtn);
      card.appendChild(noticeActions);
    }

    visibleFileQuestions.forEach((q) => {
      const item = document.createElement("div");
      item.className = "attachment-item" + (q.required ? " required" : "");

      const itemTitle = document.createElement("div");
      itemTitle.className = "attachment-title";
      itemTitle.textContent = q.labelKey ? t(q.labelKey) : q.label || q.id || "file";

      const itemHelp = document.createElement("div");
      itemHelp.className = "attachment-help";
      itemHelp.textContent = q.questionKey ? t(q.questionKey) : q.question || "";

      const controls = document.createElement("div");
      controls.className = "file-controls";

      const fileInput = document.createElement("input");
      fileInput.type = "file";
      fileInput.className = "file-input-native";

      const selectBtn = document.createElement("button");
      selectBtn.type = "button";
      selectBtn.className = "ghost";
      selectBtn.textContent = t("attachment.select");
      selectBtn.addEventListener("click", () => fileInput.click());

      const fileName = document.createElement("div");
      fileName.className = "file-name";

      const meta = document.createElement("div");
      meta.className = "attachment-meta";
      const existingName = (state.answerMeta[q.id] || {}).fileName;
      if (state.answers[q.id] && existingName) {
        fileName.textContent = existingName;
        meta.textContent = t("attachment.attachedName", { name: existingName });
      } else {
        fileName.textContent = t("attachment.none");
        meta.textContent = t("attachment.none");
      }

      if (q.id === "diffdock_ligand" && state.runMode === "pipeline") {
        const toggleWrap = document.createElement("div");
        toggleWrap.className = "choice-group";

        const useBtn = document.createElement("button");
        useBtn.type = "button";
        useBtn.className = "choice-btn";
        useBtn.textContent = t("attachment.diffdock.use");

        const skipBtn = document.createElement("button");
        skipBtn.type = "button";
        skipBtn.className = "choice-btn selected";
        skipBtn.textContent = t("attachment.diffdock.skip");

        const setMode = (mode) => {
          state.answers.diffdock_use = mode;
          if (mode === "use") {
            useBtn.classList.add("selected");
            skipBtn.classList.remove("selected");
            fileInput.disabled = false;
            selectBtn.disabled = false;
          } else {
            useBtn.classList.remove("selected");
            skipBtn.classList.add("selected");
            fileInput.value = "";
            fileInput.disabled = true;
            selectBtn.disabled = true;
            state.answers.diffdock_ligand = "";
            fileName.textContent = t("attachment.none");
            meta.textContent = t("attachment.none");
          }
          updateRunEligibility(normalizedQuestions);
        };

        useBtn.addEventListener("click", () => setMode("use"));
        skipBtn.addEventListener("click", () => setMode("skip"));
        toggleWrap.appendChild(useBtn);
        toggleWrap.appendChild(skipBtn);
        item.appendChild(toggleWrap);
        setMode(state.answers.diffdock_use || "skip");
      } else if (q.id === "diffdock_ligand" && state.runMode === "diffdock") {
        state.answers.diffdock_use = "use";
      }

      const clearBtn = document.createElement("button");
      clearBtn.type = "button";
      clearBtn.className = "ghost";
      clearBtn.textContent = t("attachment.clear");

      fileInput.addEventListener("change", async (event) => {
        const file = event.target.files?.[0];
        if (!file) {
          state.answers[q.id] = "";
          state.answerMeta[q.id] = {};
          if (q.id === "rfd3_input_pdb") {
            setSetupRfd3InputOverrideVisible(false);
          }
          if (q.id === "target_input") {
            state.answers.target_fasta = "";
            state.answers.target_pdb = "";
            state.answerMeta.target_pdb = {};
          }
          fileName.textContent = t("attachment.none");
          meta.textContent = t("attachment.none");
          let rerender = false;
          if (q.id === "target_input") {
            if (!explicitRfd3InputPdbText(state.answers)) {
              clearStructureBoundRfd3Answers();
            }
            if (state.setupResiduePicker.sourceKey === "target_input") {
              resetSetupResiduePicker();
            }
            refreshChainRangesFromAnswers();
            rerender = true;
          }
          if (q.id === "rfd3_input_pdb") {
            clearStructureBoundRfd3Answers();
            if (state.setupResiduePicker.sourceKey === "rfd3_input_pdb") {
              resetSetupResiduePicker();
            }
            refreshChainRangesFromAnswers();
            rerender = true;
          }
          if (rerender) {
            renderQuestions(state.plan?.questions || []);
          }
          updateRunEligibility(normalizedQuestions);
          return;
        }
        try {
          const text = await file.text();
          state.answers[q.id] = text;
          state.answerMeta[q.id] = { fileName: file.name };
          if (q.id === "rfd3_input_pdb") {
            state.answers.rfd3_use = true;
            setSetupRfd3InputOverrideVisible(true);
          }
          const kb = Math.max(1, Math.round(file.size / 1024));
          fileName.textContent = file.name;
          meta.textContent = t("attachment.attached", { name: file.name, kb });
          let rerender = false;
          if (q.id === "target_input") {
            const key = detectTargetKey(text);
            state.answers.target_fasta = "";
            state.answers.target_pdb = "";
            state.answerMeta.target_pdb = {};
            if (!explicitRfd3InputPdbText(state.answers)) {
              clearStructureBoundRfd3Answers();
            }
            if (key === "target_pdb") {
              state.answers.target_pdb = text;
              state.answerMeta.target_pdb = { fileName: file.name };
              const loaded = setSetupResiduePickerStructure(text, {
                sourceLabel: t("setup.residuePicker.loadTargetInput"),
                sourceKey: "target_input",
              });
              if (!loaded && state.setupResiduePicker.sourceKey === "target_input") {
                resetSetupResiduePicker();
              }
            } else if (key === "target_fasta") {
              state.answers.target_fasta = text;
            } else if (state.setupResiduePicker.sourceKey === "target_input") {
              resetSetupResiduePicker();
            }
            refreshChainRangesFromAnswers();
            rerender = true;
          }
          if (q.id === "rfd3_input_pdb") {
            clearStructureBoundRfd3Answers();
            const loaded = setSetupResiduePickerStructure(text, {
              sourceLabel: t("setup.residuePicker.loadRfd3Input"),
              sourceKey: "rfd3_input_pdb",
            });
            if (!loaded && state.setupResiduePicker.sourceKey === "rfd3_input_pdb") {
              resetSetupResiduePicker();
            }
            refreshChainRangesFromAnswers();
            rerender = true;
          }
          if (rerender) {
            renderQuestions(state.plan?.questions || []);
          }
        } catch (err) {
          state.answers[q.id] = "";
          state.answerMeta[q.id] = {};
          if (q.id === "rfd3_input_pdb") {
            setSetupRfd3InputOverrideVisible(false);
          }
          if (q.id === "target_input") {
            state.answers.target_fasta = "";
            state.answers.target_pdb = "";
            state.answerMeta.target_pdb = {};
          }
          fileName.textContent = t("attachment.none");
          meta.textContent = t("attachment.failed", { error: err.message });
          let rerender = false;
          if (q.id === "target_input" && state.setupResiduePicker.sourceKey === "target_input") {
            resetSetupResiduePicker();
            rerender = true;
          }
          if (q.id === "rfd3_input_pdb" && state.setupResiduePicker.sourceKey === "rfd3_input_pdb") {
            resetSetupResiduePicker();
            rerender = true;
          }
          if (q.id === "target_input") {
            if (!explicitRfd3InputPdbText(state.answers)) {
              clearStructureBoundRfd3Answers();
            }
            refreshChainRangesFromAnswers();
            rerender = true;
          }
          if (q.id === "rfd3_input_pdb") {
            clearStructureBoundRfd3Answers();
            refreshChainRangesFromAnswers();
            rerender = true;
          }
          if (rerender) {
            renderQuestions(state.plan?.questions || []);
          }
        }
        updateRunEligibility(normalizedQuestions);
      });

      clearBtn.addEventListener("click", () => {
        fileInput.value = "";
        state.answers[q.id] = "";
        state.answerMeta[q.id] = {};
        if (q.id === "rfd3_input_pdb") {
          setSetupRfd3InputOverrideVisible(false);
        }
        if (q.id === "target_input") {
          state.answers.target_fasta = "";
          state.answers.target_pdb = "";
          state.answerMeta.target_pdb = {};
        }
        fileName.textContent = t("attachment.none");
        meta.textContent = t("attachment.none");
        let rerender = false;
        if (q.id === "target_input") {
          if (!explicitRfd3InputPdbText(state.answers)) {
            clearStructureBoundRfd3Answers();
          }
          if (state.setupResiduePicker.sourceKey === "target_input") {
            resetSetupResiduePicker();
          }
          refreshChainRangesFromAnswers();
          rerender = true;
        }
        if (q.id === "rfd3_input_pdb") {
          clearStructureBoundRfd3Answers();
          if (state.setupResiduePicker.sourceKey === "rfd3_input_pdb") {
            resetSetupResiduePicker();
          }
          refreshChainRangesFromAnswers();
          rerender = true;
        }
        if (rerender) {
          renderQuestions(state.plan?.questions || []);
        }
        updateRunEligibility(normalizedQuestions);
      });

      controls.appendChild(selectBtn);
      controls.appendChild(fileName);
      controls.appendChild(fileInput);
      controls.appendChild(clearBtn);

      item.appendChild(itemTitle);
      item.appendChild(itemHelp);
      item.appendChild(controls);
      item.appendChild(meta);
      list.appendChild(item);
    });

    card.appendChild(title);
    card.appendChild(help);
    card.appendChild(list);
    appendInputCard(card);
  }

  const showResiduePicker =
    (state.runMode === "pipeline" || state.runMode === "workflow") &&
    normalizedQuestions.some((q) => q.id === "fixed_positions_extra");
  if (showResiduePicker) {
    const selectedRunIdForPicker = String(el.setupRunSelector?.value || state.currentRunId || "").trim();
    const targetPdbText = getTargetInputPdbText();
    const targetFastaText = getTargetInputFastaText();
    const rfd3PdbText = getRfd3InputPdbText();
    const pickerProvider = state.answers.af2_provider || "colabfold";
    const card = buildResiduePickerLauncherCard({
      runId: selectedRunIdForPicker,
      onResetSelection: () => {
        clearSetupFixedPositionsExtraState();
        renderQuestions(state.plan?.questions || []);
      },
      onOpenDetached: () => {
        openDetachedResiduePicker({
          context: "setup",
          targetPdbText,
          targetFastaText,
          rfd3PdbText,
          selectedRunId: selectedRunIdForPicker,
          pickerProvider,
        });
      },
    });
    appendInputCard(card);
  }

  updateRunEligibility(normalizedQuestions);
}

function updateRunEligibility(questions) {
  if (state.runMode === "pipeline") {
    syncStartStopStages();
  }
  syncSetupRunReuseControls();

  const requiredIds = new Set(
    (questions || [])
      .map((q) => normalizeQuestion(q))
      .filter((q) => q && q.required && q.id !== "run_mode")
      .map((q) => q.id)
  );
  const setupNodes = setupWorkflowNodesForRfd3();
  const rfd3StageInScope = runUsesRfd3Stage({
    mode: state.runMode,
    answers: state.answers,
    nodes: setupNodes,
  });
  const rfd3StageActive = rfd3EnabledForContext({
    mode: state.runMode,
    answers: state.answers,
    nodes: setupNodes,
  });
  const effectiveRfd3Input = effectiveRfd3InputPdb({
    mode: state.runMode,
    answers: state.answers,
    nodes: setupNodes,
  });
  const hasEffectiveRfd3Input = Boolean(String(effectiveRfd3Input || "").trim());
  const currentRfd3Mode = effectiveSetupRfd3Mode(state.answers);

  if (state.runMode === "pipeline") {
    if (state.answers.stop_after === "rfd3") {
      requiredIds.add("rfd3_use");
    }
    if (rfd3StageActive && !hasEffectiveRfd3Input) {
      requiredIds.add("rfd3_input_pdb");
    }
    if (rfd3StageActive && hasEffectiveRfd3Input) {
      if (rfd3ModeUsesContig(currentRfd3Mode)) {
        requiredIds.add("rfd3_contig");
      }
      if (rfd3ModeUsesEnzymeFields(currentRfd3Mode)) {
        requiredIds.add("rfd3_unindex");
      }
      if (rfd3ModeUsesAdvancedInputs(currentRfd3Mode)) {
        requiredIds.add("rfd3_inputs_text");
      }
    }
    if (state.answers.diffdock_use === "use") {
      requiredIds.add("diffdock_ligand");
    } else {
      requiredIds.delete("diffdock_ligand");
    }
    if (state.answers.stop_after === "bioemu") {
      requiredIds.add("bioemu_use");
    }
  }

  if (state.runMode === "rfd3") {
    requiredIds.delete("target_input");
    requiredIds.add("rfd3_input_pdb");
    if (rfd3ModeUsesContig(currentRfd3Mode)) {
      requiredIds.add("rfd3_contig");
    }
    if (rfd3ModeUsesEnzymeFields(currentRfd3Mode)) {
      requiredIds.add("rfd3_unindex");
    }
    if (rfd3ModeUsesAdvancedInputs(currentRfd3Mode)) {
      requiredIds.add("rfd3_inputs_text");
    }
  }

  if (state.runMode === "msa") {
    requiredIds.add("target_input");
  }

  if (state.runMode === "design") {
    requiredIds.add("target_input");
  }

  if (state.runMode === "soluprot") {
    requiredIds.add("target_input");
  }

  if (state.runMode === "af2") {
    requiredIds.add("target_input");
  }

  if (state.runMode === "diffdock") {
    requiredIds.add("target_input");
    requiredIds.add("diffdock_ligand");
  }

  if (state.runMode === "bioemu") {
    requiredIds.add("target_input");
    requiredIds.add("bioemu_use");
  }

  if (state.runMode === "workflow") {
    requiredIds.add("target_input");
    requiredIds.add("__workflow_nodes__");
  }

  const missing = Array.from(requiredIds).filter((id) => {
    if (id === "__workflow_nodes__") {
      return normalizeWorkflowNodesForState(state.workflowDesigner?.nodes).length === 0;
    }
    if (id === "confirm_run") return state.answers.confirm_run !== true;
    if (id === "bioemu_use") return state.answers.bioemu_use !== true;
    if (id === "rfd3_use") return !(state.runMode === "rfd3" || rfd3StageActive || (rfd3StageInScope && state.answers.rfd3_use === true));
    return isAnswerMissing(state.answers[id]);
  });
  const partialRerunBlocked = isSetupPartialRerunRequested();
  const runBusy = state.runSubmitting;
  const wizardBlocked = setupWizardEnabled(questions) && !isSetupWizardFinalStep();
  if (missing.length === 0 && !runBusy && !wizardBlocked && !partialRerunBlocked) {
    el.runBtn.disabled = false;
    el.runHint.textContent = t("hint.ready");
  } else {
    el.runBtn.disabled = true;
    if (runBusy) {
      el.runHint.textContent = t("hint.running");
    } else if (partialRerunBlocked) {
      el.runHint.textContent = t("hint.partialRun");
    } else if (wizardBlocked) {
      el.runHint.textContent = t("hint.nextStep");
    } else {
      el.runHint.textContent = t("hint.missing");
    }
  }
}

function currentRunStateText() {
  const statusState = String(state.lastRunStatus?.state || "")
    .trim()
    .toLowerCase();
  if (statusState) return statusState;
  return String(state.currentRunState || "")
    .trim()
    .toLowerCase();
}

function updateMonitorActionButtons() {
  const hasRun = Boolean(String(state.currentRunId || "").trim());
  const running = currentRunStateText() === "running";
  if (el.cancelRunBtn) {
    el.cancelRunBtn.disabled = !hasRun || !running;
  }
  if (el.resumeRunBtn) {
    el.resumeRunBtn.disabled = !hasRun || running || Boolean(state.runSubmitting);
  }
}

function buildAnswerPayload(mode = state.runMode) {
  let answers = normalizeBioEmuCountFields({ ...state.answers }, { includeLegacyField: true });
  if (answers.target_input && !answers.target_pdb && !answers.target_fasta) {
    if (mode === "diffdock") {
      answers.target_pdb = answers.target_input;
    } else {
      const key = detectTargetKey(answers.target_input) || "target_pdb";
      answers[key] = answers.target_input;
    }
  }
  delete answers.target_input;
  if (answers.run_mode) {
    delete answers.run_mode;
  }
  if (answers.confirm_run !== undefined) {
    delete answers.confirm_run;
  }
  if (String(answers.rfd3_input_pdb || "").trim() === String(answers.target_pdb || "").trim()) {
    delete answers.rfd3_input_pdb;
  }
  const rfd3Nodes = mode === "workflow" ? setupWorkflowNodesForRfd3() : [];
  answers = sanitizeRfd3StructureBoundAnswers(answers, {
    mode,
    nodes: rfd3Nodes,
  });
  const {
    rfd3Enabled,
    effectiveRfd3Input,
    rfd3Mode: normalizedRfd3Mode,
    inferredContig,
    inferredUnindex,
    inferredSelectFixedAtoms,
  } = resolveRfd3Defaults({
    mode,
    answers,
    nodes: rfd3Nodes,
  });
  if (mode === "rfd3" || rfd3Enabled) {
    answers.rfd3_use = true;
  } else if (mode === "pipeline" || mode === "workflow") {
    answers.rfd3_use = false;
  } else {
    delete answers.rfd3_use;
  }
  if (mode === "rfd3") {
    answers.rfd3_use = true;
  }
  if (effectiveRfd3Input && (mode === "rfd3" || rfd3Enabled)) {
    answers.rfd3_input_pdb = effectiveRfd3Input;
    if (normalizedRfd3Mode) {
      answers.rfd3_mode = normalizedRfd3Mode;
    }
  } else {
    delete answers.rfd3_input_pdb;
    if (mode === "pipeline" || mode === "workflow") {
      delete answers.rfd3_mode;
      delete answers.rfd3_contig;
      delete answers.rfd3_hotspots;
      delete answers.rfd3_infer_ori_strategy;
      delete answers.rfd3_is_non_loopy;
      delete answers.rfd3_unindex;
      delete answers.rfd3_length;
      delete answers.rfd3_select_fixed_atoms;
      delete answers.rfd3_partial_t;
      delete answers.rfd3_inputs_text;
    }
  }
  if (inferredContig) {
    answers.rfd3_contig = inferredContig;
  }
  if (inferredUnindex) {
    answers.rfd3_unindex = inferredUnindex;
  }
  if (inferredSelectFixedAtoms) {
    answers.rfd3_select_fixed_atoms = inferredSelectFixedAtoms;
  }
  if (
    isAnswerMissing(answers.rfd3_partial_t) &&
    normalizedRfd3Mode === "local_diversify"
  ) {
    answers.rfd3_partial_t = QUESTION_PRESETS.rfd3_partial_t?.default ?? 5.0;
  }
  if (normalizedRfd3Mode && !rfd3ModeUsesContig(normalizedRfd3Mode)) {
    delete answers.rfd3_contig;
  }
  if (normalizedRfd3Mode && !rfd3ModeUsesBinderFields(normalizedRfd3Mode)) {
    delete answers.rfd3_hotspots;
    delete answers.rfd3_infer_ori_strategy;
    delete answers.rfd3_is_non_loopy;
  }
  if (normalizedRfd3Mode && !rfd3ModeUsesUnindexFields(normalizedRfd3Mode)) {
    delete answers.rfd3_unindex;
  }
  if (normalizedRfd3Mode && !rfd3ModeUsesEnzymeFields(normalizedRfd3Mode)) {
    delete answers.rfd3_length;
  }
  if (normalizedRfd3Mode && !rfd3ModeUsesFixedAtomFields(normalizedRfd3Mode)) {
    delete answers.rfd3_select_fixed_atoms;
  }
  if (normalizedRfd3Mode && !rfd3ModeUsesPartialT(normalizedRfd3Mode)) {
    delete answers.rfd3_partial_t;
  }
  if (normalizedRfd3Mode && !rfd3ModeUsesAdvancedInputs(normalizedRfd3Mode)) {
    delete answers.rfd3_inputs_text;
  }
  if (Array.isArray(answers.design_chains) && answers.design_chains.length === 0) {
    delete answers.design_chains;
  }
  if (answers.diffdock_use) {
    delete answers.diffdock_use;
  }
  if (answers.diffdock_ligand) {
    const name = (state.answerMeta.diffdock_ligand || {}).fileName || "";
    delete answers.diffdock_ligand_sdf;
    delete answers.diffdock_ligand_smiles;
    Object.assign(
      answers,
      diffdockLigandSubmissionFields({
        ligandText: answers.diffdock_ligand,
        fileName: name,
      })
    );
    delete answers.diffdock_ligand;
  }
  return answers;
}

function reconcileUserInputsIntoArgs(args) {
  if (!args || typeof args !== "object") return args;
  const src = state.answers || {};
  const rawTargetInput = String(src.target_input || "").trim();
  if (rawTargetInput && !args.target_pdb && !args.target_fasta) {
    const key = detectTargetKey(rawTargetInput) || "target_pdb";
    args[key] = rawTargetInput;
  }
  if (src.target_pdb && !args.target_pdb) args.target_pdb = src.target_pdb;
  if (src.target_fasta && !args.target_fasta) args.target_fasta = src.target_fasta;
  return args;
}

